        <!-- 批量处理视图 -->
        <div id="batchView" class="view">
          <div class="edit-header">
            <h2>批量处理世界书条目</h2>
            <div class="edit-actions">
              <button id="cancelBatchBtn" class="secondary">返回</button>
            </div>
          </div>

          <div class="batch-control">
            <div class="select-all-container">
              <input type="checkbox" id="selectAllCheckbox" />
              <label for="selectAllCheckbox">全选/取消全选</label>
              <span id="selectedCounter" class="batch-counter">已选择: 0 项</span>
            </div>

            <div class="search-bar" style="margin-top: 0; flex-grow: 1">
              <!-- Allow search bar to grow -->
              <input type="text" id="batchSearchInput" placeholder="搜索条目..." />
              <button id="batchSearchBtn">搜索</button>
              <button id="batchClearSearchBtn">清除</button>
              <button id="toggleBatchViewBtn" class="secondary" style="margin-left: 0.5rem">切换紧凑视图</button>
              <!-- Moved button here -->
            </div>
          </div>

          <div class="batch-actions">
            <div class="batch-section">
              <div class="batch-section-title">批量操作</div>
              <div style="display: flex; flex-wrap: wrap; gap: 0.5rem">
                <button id="batchDeleteBtn" class="danger">批量删除</button>
                <button id="batchEnableBtn" class="success">批量启用</button>
                <button id="batchDisableBtn" class="secondary">批量禁用</button>
