            <div class="batch-section">
              <div class="batch-section-title">批量修改属性</div>
              <div style="display: flex; flex-wrap: wrap; gap: 1rem; margin-bottom: 0.5rem">
                <div>
                  <label for="batchType">类型：</label>
                  <select id="batchType">
                    <option value="">不修改</option>
                    <option value="constant">常量（蓝灯）</option>
                    <option value="selective">选择性（绿灯）</option>
                    <option value="vectorized">向量化（紫灯）</option>
                  </select>
                </div>

                <div>
                  <label for="batchPosition">位置：</label>
                  <select id="batchPosition">
                    <option value="">不修改</option>
                    <option value="before_character_definition">角色定义之前</option>
                    <option value="after_character_definition">角色定义之后</option>
                    <option value="before_example_messages">示例消息之前</option>
                    <option value="after_example_messages">示例消息之后</option>
                    <option value="before_author_note">作者注释之前</option>
                    <option value="after_author_note">作者注释之后</option>
                    <option value="at_depth_as_system">@D⚙</option>
                    <option value="at_depth_as_assistant">@D👤</option>
                    <option value="at_depth_as_user">@D🤖</option>
                  </select>
