                <div>
                  <label for="batchDepth">深度：</label>
                  <input type="number" id="batchDepth" min="0" placeholder="不修改" />
                </div>

                <div>
                  <label for="batchOrder">顺序：</label>
                  <input type="number" id="batchOrder" min="0" placeholder="不修改" />
                </div>

                <div>
                  <label for="batchProbability">概率（%）：</label>
                  <input type="number" id="batchProbability" min="0" max="100" placeholder="不修改" />
                </div>
