          <div id="batchLoading" class="loading">加载中...</div>
          <div id="batchEntryList" class="entry-list batch-entry-list"></div>
          <div id="noBatchEntriesMessage" class="info-message" style="display: none">没有找到条目</div>
        </div>

        <!-- 导入预览视图 -->
        <div id="importPreviewView" class="view">
          <div class="edit-header">
            <h2>导入预览</h2>
            <div class="edit-actions">
              <button id="backToImportBtn" class="secondary">返回</button>
              <button id="confirmFinalImportBtnFromPreview" class="success">确认导入选中条目</button>
            </div>
          </div>

          <div class="import-preview-controls">
            <div class="select-all-container">
              <input type="checkbox" id="selectAllImportCheckboxFromPreview" checked />
              <label for="selectAllImportCheckboxFromPreview">全选/取消全选</label>
              <span id="selectedImportCounterFromPreview" class="batch-counter">已选择: 0 项</span>
            </div>
          </div>

          <div id="previewLoading" class="loading">加载中...</div>
          <div id="previewEntryList" class="entry-list import-preview-list"></div>
          <div id="noPreviewEntriesMessage" class="info-message" style="display: none">没有找到可预览的条目</div>

          <!-- 导入结果显示区 (预览界面也需要一个地方显示导入结果) -->
          <div id="importResultFromPreview" style="margin-top: 1rem; display: none">
            <h3>导入结果</h3>
            <div
              id="importResultContentFromPreview"
              style="margin-top: 0.5rem; padding: 1rem; background-color: #f5f5f5; border-radius: 4px"
            ></div>
          </div>
        </div>
      </main>
    </div>

    <script>
      document.addEventListener('DOMContentLoaded', async function () {
        // 初始化变量
        let currentWorldBook = '';
        let entries = [];
        let filteredEntries = [];
        let currentFilter = 'all';
        let currentSortMode = 'uid'; // 新增：当前排序模式，默认为 uid
        let currentView = 'list';
        let selectedEntries = new Set(); // 存储批量选择的条目UID
        let isBatchViewCompact = false; // 新增：批量视图是否为紧凑模式
        // 聊天变量键名
        const CHAT_VAR_KEY = 'selectedWorldBook';

        // 获取元素 - 视图
        const listView = document.getElementById('listView');
        const worldBookEditView = document.getElementById('worldBookEditView');
        const entryEditView = document.getElementById('entryEditView');
        const importView = document.getElementById('importView');
        const batchView = document.getElementById('batchView');
        const importPreviewView = document.getElementById('importPreviewView'); // 新增：获取预览视图
        const sortEntriesBtn = document.getElementById('sortEntriesBtn'); // 新增：获取排序按钮

        // 获取元素 - 列表视图
        const worldBookSelect = document.getElementById('worldBookSelect');
        const entryList = document.getElementById('entryList');
        const loading = document.getElementById('loading');
        const noEntriesMessage = document.getElementById('noEntriesMessage');
        const searchInput = document.getElementById('searchInput');
        const refreshBtn = document.getElementById('refreshBtn');
        const createWorldBookBtn = document.getElementById('createWorldBookBtn');
        const deleteWorldBookBtn = document.getElementById('deleteWorldBookBtn');
        const createEntryBtn = document.getElementById('createEntryBtn');
        const filterButtons = document.querySelectorAll('.filter-btn');
        const searchBtn = document.getElementById('searchBtn');
        const clearSearchBtn = document.getElementById('clearSearchBtn');
        const currentCharBookBtn = document.getElementById('currentCharBookBtn');
        const importEntriesBtn = document.getElementById('importEntriesBtn');
        const batchProcessBtn = document.getElementById('batchProcessBtn');
        const worldBookSearchInput = document.getElementById('worldBookSearchInput'); // 新增：获取世界书搜索框
        const clearWorldBookSearchBtn = document.getElementById('clearWorldBookSearchBtn'); // 新增：获取清除搜索按钮
        const enableWorldBookBtn = document.getElementById('enableWorldBookBtn'); // 新增：获取启用世界书按钮

        // 获取元素 - 世界书编辑视图
        const worldBookEditTitle = document.getElementById('worldBookEditTitle');
        const worldBookName = document.getElementById('worldBookName');
        const saveWorldBookBtn = document.getElementById('saveWorldBookBtn');
        const cancelWorldBookBtn = document.getElementById('cancelWorldBookBtn');

        // 获取元素 - 条目编辑视图
        const entryEditTitle = document.getElementById('entryEditTitle');
        const entryForm = document.getElementById('entryForm');
        const entryUid = document.getElementById('entryUid');
        const entryContentTextarea = document.getElementById('entryContent'); // 获取编辑界面的textarea
        const entryPosition = document.getElementById('entryPosition');
        const depthGroup = document.getElementById('depthGroup');
        const saveEntryBtn = document.getElementById('saveEntryBtn');
        const cancelEntryBtn = document.getElementById('cancelEntryBtn');

        // 获取元素 - 导入视图
        const importContentTextarea = document.getElementById('importContent'); // 获取导入界面的textarea
        const previewImportBtn = document.getElementById('previewImportBtn'); // 修改ID
        const cancelImportBtn = document.getElementById('cancelImportBtn');
        const formatImportBtn = document.getElementById('formatImportBtn'); // 新增：获取格式化按钮
        const importPreview = document.getElementById('importPreview');
        const previewList = document.getElementById('previewList');
        const selectAllImportCheckbox = document.getElementById('selectAllImportCheckbox');
        const selectedImportCounter = document.getElementById('selectedImportCounter');
        const confirmFinalImportBtn = document.getElementById('confirmFinalImportBtn');
        const importResult = document.getElementById('importResult');
        const importResultContent = document.getElementById('importResultContent');

        // 新增：获取导入预览视图中的元素
        const backToImportBtn = document.getElementById('backToImportBtn');
        const previewEntryList = document.getElementById('previewEntryList');
        const previewLoading = document.getElementById('previewLoading');
        const noPreviewEntriesMessage = document.getElementById('noPreviewEntriesMessage');
        const selectAllImportCheckboxFromPreview = document.getElementById('selectAllImportCheckboxFromPreview');
        const selectedImportCounterFromPreview = document.getElementById('selectedImportCounterFromPreview');
        const confirmFinalImportBtnFromPreview = document.getElementById('confirmFinalImportBtnFromPreview');
        const importResultFromPreview = document.getElementById('importResultFromPreview');
        const importResultContentFromPreview = document.getElementById('importResultContentFromPreview');

        // 获取元素 - 批量处理视图
        const selectAllCheckbox = document.getElementById('selectAllCheckbox');
        const selectedCounter = document.getElementById('selectedCounter');
        const batchSearchInput = document.getElementById('batchSearchInput');
        const batchSearchBtn = document.getElementById('batchSearchBtn');
        const batchClearSearchBtn = document.getElementById('batchClearSearchBtn');
        const batchEntryList = document.getElementById('batchEntryList');
        const batchLoading = document.getElementById('batchLoading');
        const noBatchEntriesMessage = document.getElementById('noBatchEntriesMessage');
        const batchDeleteBtn = document.getElementById('batchDeleteBtn');
        const batchEnableBtn = document.getElementById('batchEnableBtn');
        const batchDisableBtn = document.getElementById('batchDisableBtn');
        const batchType = document.getElementById('batchType');
        const batchPosition = document.getElementById('batchPosition');
        const batchDepth = document.getElementById('batchDepth');
        const batchOrder = document.getElementById('batchOrder');
        const batchProbability = document.getElementById('batchProbability');
        const applyBatchChangesBtn = document.getElementById('applyBatchChangesBtn');
        const cancelBatchBtn = document.getElementById('cancelBatchBtn');
        const depthFilterContainer = document.getElementById('depthFilterContainer'); // 新增：获取深度筛选容器
        const depthFilterInput = document.getElementById('depthFilterInput'); // 新增：获取深度筛选输入框

        // 存储待导入条目的临时变量
        let entriesToImport = [];
        let selectedImportIndices = new Set();
        let allWorldBooks = []; // 新增：存储所有世界书列表的变量

        // 初始化
        // await initializeApp(); // 改为延迟执行
        setupInitialization();

        // 自动调整Textarea高度的函数
        function autoGrowTextarea(element) {
          // 先重置高度，以便正确计算scrollHeight
          element.style.height = 'auto';
          // 设置高度为内容的实际高度
          element.style.height = element.scrollHeight + 'px';
        }

        // 为两个textarea添加输入事件监听器
        entryContentTextarea.addEventListener('input', function () {
          autoGrowTextarea(this);
        });
        importContentTextarea.addEventListener('input', function () {
          autoGrowTextarea(this);
        });

        // 初始化应用程序
        async function initializeApp() {
          // 这个函数现在只包含需要等待API注入后才能执行的逻辑
          console.log('Running delayed initialization...');

          // 先尝试从聊天变量加载之前选择的世界书
          try {
            // 获取聊天变量 - 使用正确的函数
            const chatVars = await getVariables({ type: 'chat' });

            // 检查是否存在保存的世界书选择
            if (chatVars && chatVars[CHAT_VAR_KEY]) {
              // 暂存选择的世界书名称
              currentWorldBook = chatVars[CHAT_VAR_KEY];
              console.log('Loaded initial world book from chat vars:', currentWorldBook);
            }
          } catch (error) {
            console.error('加载聊天变量失败:', error);
            // 如果出错，默认不选择任何世界书
            currentWorldBook = '';
          }

          // 无论是否有聊天变量，都需要加载世界书列表
          await loadWorldBooks(); // 现在调用 loadWorldBooks

          // 检查导入文本框是否有内容（由外部正则填充）
          const initialImportContent = importContentTextarea.value.trim();
          const placeholderComment = ''; // 原本的注释已经不在，直接判断是否为空
          if (initialImportContent && initialImportContent !== placeholderComment && currentView !== 'importPreview') {
            // 避免在预览返回时覆盖视图
            // 如果有内容，并且当前不在预览视图，默认显示导入视图
            console.log('Initial import content found, showing import view.');
            showView('import');
            // 并调整导入文本框的初始高度
            // 延迟一点执行，确保视图切换完成
            setTimeout(() => autoGrowTextarea(importContentTextarea), 0);
          } else if (currentView === 'list') {
            // 确保只在初始状态下显示列表视图
            console.log('No initial import content or returning from preview, showing list view.');
            // 否则显示列表视图
            showView('list');
          }
        }

        // 设置初始化，处理 DOMContentLoaded 和 API 注入延迟
        function setupInitialization() {
          // 获取元素等不依赖外部API的操作可以立即执行
          console.log('DOM content loaded, setting up initialization delay.');

          // 延迟执行需要外部API的初始化逻辑
          setTimeout(() => {
            // 在尝试初始化前检查关键函数是否存在
            if (typeof getLorebooks === 'function' && typeof getVariables === 'function') {
              initializeApp();
            } else {
              console.error(
                'World Book API functions (getLorebooks, getVariables) not defined after delay. Initialization aborted.',
              );
              alert(
                '无法加载世界书助手所需的功能。请确保前端助手扩展已启用并正常工作。您可以尝试刷新页面。如果问题持续存在，请检查浏览器控制台获取更多信息。',
              );
              // 可以在这里显示一个错误消息给用户
              loading.textContent = '加载失败，请检查扩展或刷新页面。';
              loading.style.color = 'var(--danger-color)';
              loading.style.display = 'block';
              noEntriesMessage.style.display = 'none';
            }
          }, 200); // 延迟200毫秒，可以根据需要调整
        }

        // 保存当前选择的世界书到聊天变量
        async function saveSelectedWorldBookToChatVars() {
          try {
            // 获取现有的聊天变量 - 使用正确的函数
            const chatVars = (await getVariables({ type: 'chat' })) || {};

            // 更新世界书选择
            chatVars[CHAT_VAR_KEY] = currentWorldBook;

            // 保存回聊天变量 - 使用正确的函数
            await replaceVariables(chatVars, { type: 'chat' });

            console.log('世界书选择已保存到聊天变量:', currentWorldBook);
          } catch (error) {
            console.error('保存聊天变量失败:', error);
          }
        }

        // 视图切换函数
        function showView(viewName) {
          currentView = viewName;

          // 隐藏所有视图
          listView.classList.remove('active');
          worldBookEditView.classList.remove('active');
          entryEditView.classList.remove('active');
          importView.classList.remove('active');
          batchView.classList.remove('active');
          importPreviewView.classList.remove('active'); // 新增：隐藏预览视图

          // 显示指定视图
          if (viewName === 'list') {
            listView.classList.add('active');
          } else if (viewName === 'worldBookEdit') {
            worldBookEditView.classList.add('active');
          } else if (viewName === 'entryEdit') {
            entryEditView.classList.add('active');
          } else if (viewName === 'import') {
            importView.classList.add('active');
            // 更新导入视图中的世界书信息
            updateImportViewWorldBookInfo();
          } else if (viewName === 'batch') {
            batchView.classList.add('active');
            loadBatchView(); // 加载批量处理视图
          } else if (viewName === 'importPreview') {
            // 新增：显示预览视图
            importPreviewView.classList.add('active');
          }
        }

        // 事件监听器 - 列表视图
        refreshBtn.addEventListener('click', async function () {
          await loadWorldBooks();
          if (currentWorldBook) {
            await loadEntries(currentWorldBook);
          }
        });

        worldBookSelect.addEventListener('change', async function () {
          currentWorldBook = worldBookSelect.value;
          if (currentWorldBook) {
            await loadEntries(currentWorldBook);
            // 保存选择到聊天变量
            await saveSelectedWorldBookToChatVars();
          } else {
            entryList.innerHTML = '';
            noEntriesMessage.style.display = 'block';
            // 清除聊天变量中的选择
            await saveSelectedWorldBookToChatVars();
          }
        });

        createWorldBookBtn.addEventListener('click', function () {
          worldBookEditTitle.textContent = '新建世界书';
          worldBookName.value = '';
          showView('worldBookEdit');
        });

        deleteWorldBookBtn.addEventListener('click', async function () {
          if (!currentWorldBook) {
            alert('请先选择一个世界书');
            return;
          }

          if (confirm(`确定要删除世界书 "${currentWorldBook}" 吗？此操作不可恢复！`)) {
            await deleteLorebook(currentWorldBook);
            await loadWorldBooks();
            entryList.innerHTML = '';
            noEntriesMessage.style.display = 'block';
          }
        });

        createEntryBtn.addEventListener('click', function () {
          if (!currentWorldBook) {
            alert('请先选择一个世界书');
            return;
          }
          entryEditTitle.textContent = '新建条目';
          entryForm.reset();
          entryUid.value = '';
          showView('entryEdit');
          checkPositionForDepth();
        });

        filterButtons.forEach(btn => {
          btn.addEventListener('click', function () {
            filterButtons.forEach(b => b.classList.remove('active'));
            this.classList.add('active');
            currentFilter = this.dataset.filter;
            // 控制深度筛选框的显示
            if (currentFilter.startsWith('pos_depth_')) {
              depthFilterContainer.style.display = 'flex';
            } else {
              depthFilterContainer.style.display = 'none';
              depthFilterInput.value = ''; // 清空深度值
            }
            filterAndDisplayEntries();
          });
        });

        searchBtn.addEventListener('click', function () {
          filterAndDisplayEntries();
        });

        clearSearchBtn.addEventListener('click', function () {
          searchInput.value = '';
          filterAndDisplayEntries();
        });

        // 事件监听器 - 世界书编辑视图
        cancelWorldBookBtn.addEventListener('click', function () {
          showView('list');
        });

        saveWorldBookBtn.addEventListener('click', async function () {
          const name = worldBookName.value.trim();
          if (!name) {
            alert('世界书名称不能为空');
            return;
          }

          const success = await createLorebook(name);
          if (success) {
            showView('list');
            await loadWorldBooks();
            worldBookSelect.value = name;
            currentWorldBook = name;
            await loadEntries(name);
          } else {
            alert('创建世界书失败，可能已存在同名世界书');
          }
        });

        // 事件监听器 - 条目编辑视图
        cancelEntryBtn.addEventListener('click', function () {
          showView('list');
        });

        entryPosition.addEventListener('change', checkPositionForDepth);

        saveEntryBtn.addEventListener('click', async function () {
          // 收集表单数据
          const formData = {
            comment: document.getElementById('entryComment').value,
            enabled: document.getElementById('entryEnabled').checked,
            type: document.getElementById('entryType').value,
            position: document.getElementById('entryPosition').value,
            order: parseInt(document.getElementById('entryOrder').value),
            probability: parseInt(document.getElementById('entryProbability').value),
            key: document
              .getElementById('entryKeys')
              .value.split(',')
              .map(k => k.trim())
              .filter(k => k),
            logic: document.getElementById('entryLogic').value,
            content: document.getElementById('entryContent').value,
          };

          if (formData.position.startsWith('at_depth_as_')) {
            formData.depth = parseInt(document.getElementById('entryDepth').value);
          }

          const uid = entryUid.value;
          if (uid) {
            // 编辑现有条目
            formData.uid = parseInt(uid);
            await setLorebookEntries(currentWorldBook, [formData]);
          } else {
            // 创建新条目
            await createLorebookEntry(currentWorldBook, formData);
          }

          showView('list');
          await loadEntries(currentWorldBook);
        });

        // 事件监听器 - 选择当前角色卡世界书
        currentCharBookBtn.addEventListener('click', async function () {
          try {
            // 显示加载状态
            loading.style.display = 'block';

            // 获取当前角色卡绑定的主要世界书
            const primaryLorebook = await getCurrentCharPrimaryLorebook();

            // 检查是否成功获取世界书
            if (primaryLorebook) {
              // 更新选择框并加载条目
              worldBookSelect.value = primaryLorebook;
              currentWorldBook = primaryLorebook;
              await loadEntries(primaryLorebook);
              // 保存选择到聊天变量
              await saveSelectedWorldBookToChatVars();
            } else {
              alert('当前角色卡没有绑定主要世界书');
            }
          } catch (error) {
            console.error('获取当前角色卡世界书失败', error);
            alert('获取当前角色卡世界书失败: ' + error.message);
