        // 事件监听器 - 从预览返回导入按钮
        backToImportBtn.addEventListener('click', function () {
          showView('import');
        });

        // 函数 - 显示预览条目 (类似displayEntries，但添加复选框)
        function displayPreviewEntries(entriesToDisplay) {
          previewEntryList.innerHTML = '';
          selectedImportIndices.clear(); // 清空之前的选择
          selectAllImportCheckboxFromPreview.checked = true; // 重置全选状态

          if (entriesToDisplay.length === 0) {
            noPreviewEntriesMessage.style.display = 'block';
            updateImportSelectionCounter(); // 更新计数器为0
            return;
          }

          noPreviewEntriesMessage.style.display = 'none';

          entriesToDisplay.forEach((entry, index) => {
            selectedImportIndices.add(index); // 默认全选
            const entryItem = createEntryElement(entry, true, index); // 使用公共函数创建元素
            previewEntryList.appendChild(entryItem);
          });

          updateImportSelectionCounter(); // 更新初始计数器
        }

        // 事件监听器 - 导入预览全选框
        selectAllImportCheckboxFromPreview.addEventListener('change', function () {
          const checkboxes = previewEntryList.querySelectorAll('.import-entry-checkbox'); // 修改目标列表
          checkboxes.forEach(checkbox => {
            checkbox.checked = selectAllImportCheckboxFromPreview.checked;
            const entryIndex = parseInt(checkbox.dataset.index);
            if (selectAllImportCheckboxFromPreview.checked) {
              selectedImportIndices.add(entryIndex);
            } else {
              selectedImportIndices.delete(entryIndex);
            }
          });
          updateImportSelectionCounter(); // 使用统一的更新函数
        });

        // 事件监听器 - 确认导入选中条目按钮
        confirmFinalImportBtnFromPreview.addEventListener('click', async function () {
          // 修改监听的按钮
          if (selectedImportIndices.size === 0) {
            alert('请至少选择一个要导入的条目');
            return;
          }

          // 隐藏预览区，显示导入结果加载状态
          previewEntryList.innerHTML = ''; // 清空预览列表
          previewLoading.style.display = 'block'; // 显示加载状态
          importResultFromPreview.style.display = 'block'; // 显示预览界面的结果区域
          importResultContentFromPreview.innerHTML =
            '<div style="text-align: center; padding: 1rem;">导入中，请稍候...</div>';

          // 获取实际要导入的条目
          const entriesToActuallyImport = [];
          selectedImportIndices.forEach(index => {
            if (index >= 0 && index < entriesToImport.length) {
              entriesToActuallyImport.push(entriesToImport[index]);
            }
          });

          if (entriesToActuallyImport.length === 0) {
            importResultContentFromPreview.innerHTML =
              '<div style="color: var(--danger-color);">没有有效的条目被选中进行导入。</div>';
            return;
          }

          // 执行导入
          const results = [];
          for (const entry of entriesToActuallyImport) {
            try {
              // 创建新条目
              const newUid = await createLorebookEntry(currentWorldBook, entry);
              results.push({
                success: true,
                title: entry.comment,
                uid: newUid,
              });
            } catch (error) {
              results.push({
                success: false,
                title: entry.comment,
                error: error.message,
              });
            }
          }

          // 显示导入结果
          let resultHtml = '';
          const successCount = results.filter(r => r.success).length;

          resultHtml += `<div style="margin-bottom: 1rem;">
                    成功导入 <strong>${successCount}</strong> 个条目，失败 <strong>${
            results.length - successCount
          }</strong> 个条目
                </div>`;

          if (successCount > 0) {
            resultHtml +=
              '<div style="margin-bottom: 0.5rem; font-weight: bold; color: var(--success-color);">成功导入的条目：</div>';
            resultHtml += '<ul style="margin-bottom: 1rem;">';
            results
              .filter(r => r.success)
              .forEach(result => {
                resultHtml += `<li>${result.title || '无标题'} (UID: ${result.uid})</li>`;
              });
            resultHtml += '</ul>';
          }

          if (results.length - successCount > 0) {
            resultHtml +=
              '<div style="margin-bottom: 0.5rem; font-weight: bold; color: var(--danger-color);">导入失败的条目：</div>';
            resultHtml += '<ul>';
            results
              .filter(r => !r.success)
              .forEach(result => {
                resultHtml += `<li>${result.title || '无标题'} - 错误：${result.error}</li>`;
              });
            resultHtml += '</ul>';
          }

          importResultContentFromPreview.innerHTML = resultHtml; // 在预览界面的结果区显示

          // 清空临时数据
          entriesToImport = [];
          selectedImportIndices.clear();

          // 重新加载主列表的条目
          await loadEntries(currentWorldBook);

          // 导入完成后，可以选择停留在预览界面显示结果，或者跳转回列表
          // 这里选择停留在预览界面显示结果，用户可以点击返回按钮回到导入界面
          previewLoading.style.display = 'none'; // 隐藏加载状态
        });

        // 函数 - 更新导入选择计数器
        function updateImportSelectionCounter() {
          const text = `已选择: ${selectedImportIndices.size} / ${entriesToImport.length} 项`;
          // 更新两个计数器（如果存在）
          if (selectedImportCounter) selectedImportCounter.textContent = text;
          if (selectedImportCounterFromPreview) selectedImportCounterFromPreview.textContent = text;
        }

        // 函数 - 加载世界书
        async function loadWorldBooks() {
          loading.style.display = 'block';
          worldBookSelect.innerHTML = '<option value="">-- 加载中 --</option>'; // 显示加载状态
          try {
            // 在调用前再次检查函数是否存在，增加健壮性
            if (typeof getLorebooks !== 'function') {
              console.error('getLorebooks function is not defined when trying to load world books.');
              alert('加载世界书失败：所需函数丢失。');
              loading.textContent = '加载世界书失败，函数丢失。';
              loading.style.color = 'var(--danger-color)';
              return; // 提前退出
            }

            allWorldBooks = await getLorebooks(); // 存储所有世界书到变量
            displayWorldBooks(); // 调用新的显示函数

            // 注意：选中逻辑移到 displayWorldBooks 函数中处理
            if (currentWorldBook && !allWorldBooks.includes(currentWorldBook)) {
              // 如果之前选中的书已不存在 (可能被删除了)
              currentWorldBook = '';
              saveSelectedWorldBookToChatVars(); // 更新聊天变量
              entryList.innerHTML = '';
              noEntriesMessage.style.display = 'block';
            } else if (currentWorldBook) {
              worldBookSelect.value = currentWorldBook;
              // 并加载其条目
              await loadEntries(currentWorldBook);
            } else {
              // 如果没有选中过，确保条目列表是空的
              currentWorldBook = '';
              entryList.innerHTML = '';
              noEntriesMessage.style.display = 'block';
            }
          } catch (error) {
            console.error('加载世界书失败', error);
            alert('加载世界书失败: ' + error.message);
          } finally {
            loading.style.display = 'none';
          }
        }

        // 新增：函数 - 根据搜索词显示世界书列表
        function displayWorldBooks(searchTerm = '') {
          const lowerSearchTerm = searchTerm.toLowerCase();

          // 过滤世界书
          const filteredBooks = allWorldBooks.filter(book => book.toLowerCase().includes(lowerSearchTerm));

          // 清空现有选项
          worldBookSelect.innerHTML = '';

          // 添加默认选项
          const emptyOption = document.createElement('option');
          emptyOption.value = '';
          emptyOption.textContent =
            filteredBooks.length === 0 && searchTerm ? '-- 无匹配世界书 --' : '-- 请选择世界书 --';
          worldBookSelect.appendChild(emptyOption);

          // 添加过滤后的选项
          filteredBooks.forEach(book => {
            const option = document.createElement('option');
            option.value = book;
            option.textContent = book;
            worldBookSelect.appendChild(option);
          });

          // 检查当前选中的世界书是否仍在过滤结果中
          if (currentWorldBook && filteredBooks.includes(currentWorldBook)) {
            worldBookSelect.value = currentWorldBook; // 保持选中
          } else if (currentWorldBook && !filteredBooks.includes(currentWorldBook)) {
            // 如果当前选中的不在过滤结果中，取消选中状态，但不清除条目列表
            // 用户需要手动选择一个新的或清除搜索
            worldBookSelect.value = '';
          } else {
            // 如果本来就没选中，保持空值
            worldBookSelect.value = '';
          }
        }

        // 函数 - 加载条目
        async function loadEntries(worldBook) {
          loading.style.display = 'block';
          entryList.innerHTML = '';

          try {
            entries = await getLorebookEntries(worldBook);
            if (entries.length === 0) {
              noEntriesMessage.style.display = 'block';
            } else {
              noEntriesMessage.style.display = 'none';
              filterAndDisplayEntries();
            }
          } catch (error) {
            console.error('加载条目失败', error);
            alert('加载条目失败: ' + error.message);
            noEntriesMessage.style.display = 'block';
          } finally {
            loading.style.display = 'none';
          }
        }

        // 函数 - 筛选和显示条目
        function filterAndDisplayEntries() {
          const searchTerm = searchInput.value.toLowerCase();

          filteredEntries = entries.filter(entry => {
            // 应用过滤器
            if (currentFilter === 'enabled' && !entry.enabled) return false;
            if (currentFilter === 'disabled' && entry.enabled) return false;
            if (currentFilter === 'constant' && entry.type !== 'constant') return false;
            if (currentFilter === 'selective' && entry.type !== 'selective') return false;
            if (currentFilter === 'vectorized' && entry.type !== 'vectorized') return false;

            // 新增：应用位置过滤器
            if (currentFilter === 'pos_before_char' && entry.position !== 'before_character_definition') return false;
            if (currentFilter === 'pos_after_char' && entry.position !== 'after_character_definition') return false;
            if (currentFilter === 'pos_before_ex' && entry.position !== 'before_example_messages') return false;
            if (currentFilter === 'pos_after_ex' && entry.position !== 'after_example_messages') return false;
            if (currentFilter === 'pos_before_an' && entry.position !== 'before_author_note') return false;
            if (currentFilter === 'pos_after_an' && entry.position !== 'after_author_note') return false;
            if (currentFilter === 'pos_depth_sys' && entry.position !== 'at_depth_as_system') return false;
            if (currentFilter === 'pos_depth_asst' && entry.position !== 'at_depth_as_assistant') return false;
            if (currentFilter === 'pos_depth_user' && entry.position !== 'at_depth_as_user') return false;

            // 新增：应用深度筛选 (仅当@D过滤器激活时)
            if (currentFilter.startsWith('pos_depth_') && depthFilterInput.value !== '') {
              const filterDepth = parseInt(depthFilterInput.value);
              if (isNaN(filterDepth) || entry.depth !== filterDepth) {
                return false;
              }
            }

            // 应用搜索
            if (searchTerm) {
              return (
                entry.comment.toLowerCase().includes(searchTerm) ||
                entry.content.toLowerCase().includes(searchTerm) ||
                entry.key.some(k => k.toLowerCase().includes(searchTerm))
              );
            }

            return true;
          });

          // 在显示前进行排序
          const sortedEntries = sortEntries(filteredEntries, currentSortMode);

          displayEntries(sortedEntries); // 使用排序后的条目进行显示
        }

        /**
         * 创建单个条目元素的公共函数
         * @param {Object} entry 条目数据
         * @param {boolean} isPreview 是否为预览模式 (添加复选框)
         * @param {number} [index] 条目在数组中的索引 (预览模式下需要)
         * @returns {HTMLElement} 创建的条目DOM元素
         */
        function createEntryElement(entry, isPreview = false, index = -1) {
          const entryItem = document.createElement('div');
          entryItem.className = 'entry-item';

          // 如果是预览模式，添加复选框
          if (isPreview && index !== -1) {
            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.className = 'import-entry-checkbox';
            checkbox.dataset.index = index;
            checkbox.checked = selectedImportIndices.has(index); // 根据集合设置初始状态
            checkbox.addEventListener('change', function () {
              const entryIndex = parseInt(checkbox.dataset.index);
              if (checkbox.checked) {
                selectedImportIndices.add(entryIndex);
              } else {
                selectedImportIndices.delete(entryIndex);
              }
              updateImportSelectionCounter();
              // 更新全选框状态
              selectAllImportCheckboxFromPreview.checked = selectedImportIndices.size === entriesToImport.length;
            });
            entryItem.appendChild(checkbox);
          }

          // 根据条目类型设置不同的边框颜色
          if (entry.type === 'constant') {
            entryItem.style.borderLeftColor = '#3a7bd5'; // 使用主色调变量
          } else if (entry.type === 'selective') {
            entryItem.style.borderLeftColor = '#4caf50'; // 使用成功色变量
          } else if (entry.type === 'vectorized') {
            entryItem.style.borderLeftColor = '#9c27b0'; // 使用一个更明显的紫色
          }

          // 如果条目被禁用，显示灰色
          if (!entry.enabled) {
            entryItem.style.opacity = '0.7';
          }

          const header = document.createElement('div');
          header.className = 'entry-header';

          const title = document.createElement('div');
          title.className = 'entry-title';
          title.textContent = entry.comment || '无标题';

          const statusBadge = document.createElement('span');
          statusBadge.textContent = entry.enabled ? '已启用' : '已禁用';
          statusBadge.style.backgroundColor = entry.enabled ? 'var(--success-color)' : 'var(--danger-color)';
          statusBadge.style.color = 'white';
          statusBadge.style.padding = '0.2rem 0.5rem';
          statusBadge.style.borderRadius = '4px';
          statusBadge.style.fontSize = '0.75rem';

          header.appendChild(title);
          header.appendChild(statusBadge);
          entryItem.appendChild(header);

          const meta = document.createElement('div');
          meta.className = 'entry-meta';

          // 显示UID
          const uidSpan = document.createElement('span');
          uidSpan.textContent = 'UID: ' + entry.uid;
          meta.appendChild(uidSpan);

          // 显示类型
          const typeSpan = document.createElement('span');
          const typeNames = {
            constant: '常量（蓝灯）',
            selective: '选择性（绿灯）',
            vectorized: '向量化（紫灯）',
          };
          typeSpan.textContent = '类型: ' + (typeNames[entry.type] || entry.type);
          meta.appendChild(typeSpan);

          // 显示位置
          const positionSpan = document.createElement('span');
          const positionNames = {
            before_character_definition: '角色定义之前',
            after_character_definition: '角色定义之后',
            before_example_messages: '示例消息之前',
            after_example_messages: '示例消息之后',
            before_author_note: '作者注释之前',
            after_author_note: '作者注释之后',
            at_depth_as_system: '@D⚙',
            at_depth_as_assistant: '@D👤',
            at_depth_as_user: '@D🤖',
          };
          positionSpan.textContent = '位置: ' + (positionNames[entry.position] || entry.position);
          if (entry.position.startsWith('at_depth_as_') && entry.depth !== null) {
            positionSpan.textContent += ` (深度: ${entry.depth})`;
          }
          meta.appendChild(positionSpan);

          // 显示顺序
          const orderSpan = document.createElement('span');
          orderSpan.textContent = '顺序: ' + entry.order;
          meta.appendChild(orderSpan);

          // 显示概率
          const probabilitySpan = document.createElement('span');
          probabilitySpan.textContent = '概率: ' + entry.probability + '%';
          meta.appendChild(probabilitySpan);

          entryItem.appendChild(meta);

          // 显示关键词标签
          if (entry.key && entry.key.length > 0) {
            const tagList = document.createElement('div');
            tagList.className = 'tag-list';

            const logicNames = {
              and_any: '任意一个关键词（OR）',
              and_all: '所有关键词（AND）',
              not_all: '排除所有关键词',
              not_any: '排除任意关键词',
            };

            const logicTag = document.createElement('div');
            logicTag.className = 'tag';
            logicTag.style.backgroundColor = '#e1d5e7'; // 浅紫色背景
            logicTag.style.color = '#000';
            logicTag.textContent = logicNames[entry.logic] || entry.logic;
            tagList.appendChild(logicTag);

            entry.key.forEach(keyword => {
              if (keyword) {
                const tag = document.createElement('div');
                tag.className = 'tag';
                tag.textContent = keyword;
                tagList.appendChild(tag);
              }
            });

            entryItem.appendChild(tagList);
          }

          // 显示内容
          const content = document.createElement('div');
          content.className = 'entry-content';
          content.textContent = entry.content;
          entryItem.appendChild(content);

          // 操作按钮 (主列表模式下添加)
          if (!isPreview) {
            const actions = document.createElement('div');
            actions.className = 'entry-actions';

            const editBtn = document.createElement('button');
            editBtn.textContent = '编辑';
            editBtn.addEventListener('click', () => editEntry(entry));

            const toggleBtn = document.createElement('button');
            toggleBtn.textContent = entry.enabled ? '禁用' : '启用';
            toggleBtn.className = entry.enabled ? 'danger' : 'success';
            toggleBtn.addEventListener('click', () => toggleEntry(entry));

            const deleteBtn = document.createElement('button');
            deleteBtn.textContent = '删除';
            deleteBtn.className = 'danger';
            deleteBtn.addEventListener('click', () => deleteEntry(entry));

            actions.appendChild(editBtn);
            actions.appendChild(toggleBtn);
            actions.appendChild(deleteBtn);
            entryItem.appendChild(actions);
          }

          return entryItem;
        }

        // 函数 - 显示主列表条目
        function displayEntries(entriesToDisplay) {
          entryList.innerHTML = '';

          if (entriesToDisplay.length === 0) {
            noEntriesMessage.style.display = 'block';
            return;
          }

          noEntriesMessage.style.display = 'none';

          entriesToDisplay.forEach(entry => {
            const entryItem = createEntryElement(entry, false); // 使用公共函数创建元素

            entryList.appendChild(entryItem);
          });
        }

        // 函数 - 编辑条目
        function editEntry(entry) {
          entryEditTitle.textContent = '编辑条目';
          entryUid.value = entry.uid;
          document.getElementById('entryComment').value = entry.comment || '';
          document.getElementById('entryEnabled').checked = entry.enabled;
          document.getElementById('entryType').value = entry.type;
          document.getElementById('entryPosition').value = entry.position;
          document.getElementById('entryOrder').value = entry.order;
          document.getElementById('entryProbability').value = entry.probability;
          document.getElementById('entryKeys').value = entry.key.join(',');
          document.getElementById('entryLogic').value = entry.logic;
          document.getElementById('entryContent').value = entry.content;

          if (entry.position.startsWith('at_depth_as_') && entry.depth !== null) {
            document.getElementById('entryDepth').value = entry.depth;
            depthGroup.style.display = 'block';
          } else {
            depthGroup.style.display = 'none';
          }

          showView('entryEdit');
          // 调整编辑文本框的初始高度
          // 延迟一点执行，确保视图切换完成
          setTimeout(() => autoGrowTextarea(entryContentTextarea), 0);
        }

        // 函数 - 切换条目启用状态
        async function toggleEntry(entry) {
          const updatedEntry = {
            uid: entry.uid,
            enabled: !entry.enabled,
          };

          await setLorebookEntries(currentWorldBook, [updatedEntry]);
          await loadEntries(currentWorldBook);
        }

        // 函数 - 删除条目
        async function deleteEntry(entry) {
          if (confirm(`确定要删除条目 "${entry.comment}" 吗？此操作不可恢复！`)) {
            await deleteLorebookEntry(currentWorldBook, entry.uid);
            await loadEntries(currentWorldBook);
          }
        }

        // 函数 - 检查位置是否需要显示深度选项
        function checkPositionForDepth() {
          const position = entryPosition.value;
          if (position.startsWith('at_depth_as_')) {
            depthGroup.style.display = 'block';
          } else {
            depthGroup.style.display = 'none';
          }
        }

        /**
         * 解析世界书内容文本为条目对象数组
         * @param {string} content 世界书条目文本内容
         * @returns {Array} 解析后的条目对象数组
         */
        function parseWorldBookContent(content) {
          const entries = [];
          const uidRegex = /(?:^|\n)uid:\s*(\d+)/g; // 匹配行首或换行后的uid，并捕获数字
          let match;
          const splitIndices = [];

          try {
            // 查找所有uid块的起始位置
            while ((match = uidRegex.exec(content)) !== null) {
              // match.index 是匹配项（可能包含\n）的起始位置
              splitIndices.push(match.index);
            }

            if (splitIndices.length > 0) {
              // 添加内容的结束位置，以便提取最后一个块
              splitIndices.push(content.length);

              // 根据索引提取块
              for (let i = 0; i < splitIndices.length - 1; i++) {
                // 确定块的实际起始索引（跳过可能的引导换行符）
                let startIndex = splitIndices[i];
                if (content[startIndex] === '\n') {
                  startIndex += 1; // 从换行符后开始
                }
                const block = content.substring(startIndex, splitIndices[i + 1]);

                if (block.trim()) {
                  try {
                    const entry = parseEntryBlock(block);
                    if (entry) {
                      entries.push(entry);
                    }
                  } catch (error) {
                    console.error('解析条目失败', block, error);
                    // 继续解析其他条目
                  }
                }
              }
            } else {
              // 如果没有找到UID，可能整个内容是一个单独的条目？
              // 尝试将整个内容作为单个块解析
              if (content.trim()) {
                try {
                  const entry = parseEntryBlock(content);
                  if (entry) {
                    entries.push(entry);
                    console.warn("未找到多个'uid:'标记，尝试将整个内容作为单个条目解析。");
                  } else {
                    console.warn("未在内容中找到'uid:'标记，也无法将整个内容解析为单个条目。");
                  }
                } catch (error) {
                  console.error('将整个内容解析为单个条目失败', content, error);
                }
              } else {
                console.warn("未在内容中找到 'uid:' 标记，且内容为空，无法解析条目。");
              }
            }
          } catch (error) {
            console.error('解析世界书内容时发生错误', error);
          }

          return entries;
        }

        /**
         * 解析单个条目块
         * @param {string} block 条目文本块
         * @returns {Object|null} 解析后的条目对象，如果解析失败则返回null
         */
        function parseEntryBlock(block) {
          try {
            // 提取UID - 使用更灵活的正则表达式，可以匹配行首或行中的UID
            const uidMatch = block.match(/uid:\s*(\d+)/);
            if (!uidMatch) return null;
            const uid = parseInt(uidMatch[1]);

            // 提取trigger部分 - 使用更宽松的匹配方式
            let triggerMatch = block.match(/trigger:\s*\n([\s\S]*?)(?=\ncontent:|$)/);

            // 如果没有找到标准格式的trigger，尝试查找其他可能的格式
            if (!triggerMatch) {
              // 尝试查找不带换行的trigger格式
              triggerMatch = block.match(/trigger:\s*([\s\S]*?)(?=\ncontent:|$)/);

              // 如果仍然找不到，尝试直接解析block中的type和position
              if (!triggerMatch) {
                // 创建默认值的条目
                const typeMatch = block.match(/type:\s*([^\n]+)/);
                const positionMatch = block.match(/position:\s*([^\n]+)/);
                const titleMatch = block.match(/Title:\s*([^\n]+)/);
                const keyListMatch = block.match(/Comma_separated_list:\s*([^\n]+)/);

                // 提取content部分
                const contentMatch = block.match(/content:\s*\|([\s\S]*?)(?=\nuid:|$)/);
                let content = '';
                if (contentMatch) {
                  content = contentMatch[1].trim();
                } else {
                  // 如果找不到标准格式的content，尝试找不带竖线的格式
                  const altContentMatch = block.match(/content:\s*([\s\S]*?)(?=\nuid:|$)/);
                  if (altContentMatch) {
                    content = altContentMatch[1].trim();
                  }
                }

                // 如果提取不到内容，则返回null
                if (!content && !typeMatch && !positionMatch) return null;

                // 映射类型
                let type = typeMatch ? typeMatch[1].trim() : 'Constant';
                let entryType = 'constant';
                if (type === 'Normal') {
                  entryType = 'selective';
                } else if (type === 'Vectorized') {
                  entryType = 'vectorized';
                }

                // 映射位置
                let position = positionMatch ? positionMatch[1].trim() : 'Before Character Definition';
                let entryPosition = 'before_character_definition';
                if (position === 'After Character Definition') {
                  entryPosition = 'after_character_definition';
                } else if (position === 'Before Example Messages') {
                  entryPosition = 'before_example_messages';
                } else if (position === 'After Example Messages') {
                  entryPosition = 'after_example_messages';
                } else if (position === 'Before Author Note') {
                  entryPosition = 'before_author_note';
                } else if (position === 'After Author Note') {
                  entryPosition = 'after_author_note';
                }

                // 提取标题和关键词
                const comment = titleMatch ? titleMatch[1].trim() : '';
                const keys = keyListMatch
                  ? keyListMatch[1]
                      .split(',')
                      .map(k => k.trim())
                      .filter(k => k)
                  : [];

                // 创建条目对象
                return {
                  uid: uid, // 使用找到的UID
                  comment: comment,
                  enabled: true,
                  type: entryType,
                  position: entryPosition,
                  order: 100,
                  probability: 100,
                  key: keys,
                  logic: 'and_any',
                  content: content,
                };
              }
            }

            const triggerContent = triggerMatch[1].trim();
            const triggerLines = triggerContent.split('\n');
            let type = '',
              position = '',
              comment = '',
              keyString = '';

            triggerLines.forEach(line => {
              const trimmedLine = line.trim();
              if (trimmedLine.startsWith('type:')) {
                type = trimmedLine.substring(5).trim();
              } else if (trimmedLine.startsWith('position:')) {
                position = trimmedLine.substring(9).trim();
              } else if (trimmedLine.startsWith('Title:')) {
                comment = trimmedLine.substring(6).trim();
              } else if (trimmedLine.startsWith('Comma_separated_list:')) {
                // 修正：确保从冒号后面开始提取，并且去除可能的前后空格
                keyString = trimmedLine.substring(trimmedLine.indexOf(':') + 1).trim();
              }
            });

            // 提取content部分
            const contentMatch = block.match(/content:\s*\|([\s\S]*?)(?=\nuid:|$)/);
            let content = '';

            if (contentMatch) {
              content = contentMatch[1].trim();
            } else {
              // 如果找不到标准格式的content，尝试找不带竖线的格式
              const altContentMatch = block.match(/content:\s*([\s\S]*?)(?=\nuid:|$)/);
              if (altContentMatch) {
                content = altContentMatch[1].trim();
              }
            }

            // 映射类型
            let entryType = 'constant';
            if (type === 'Normal') {
              entryType = 'selective';
            } else if (type === 'Vectorized') {
              entryType = 'vectorized';
            }

            // 映射位置
            let entryPosition = 'before_character_definition';
            if (position === 'After Character Definition') {
              entryPosition = 'after_character_definition';
            } else if (position === 'Before Example Messages') {
              entryPosition = 'before_example_messages';
            } else if (position === 'After Example Messages') {
              entryPosition = 'after_example_messages';
            } else if (position === 'Before Author Note') {
              entryPosition = 'before_author_note';
            } else if (position === 'After Author Note') {
              entryPosition = 'after_author_note';
            }

            // 解析关键词
            const keys = keyString
              .split(',')
              .map(k => k.trim())
              .filter(k => k);

            // 创建条目对象
            return {
              uid: uid, // 使用找到的UID
              comment: comment,
              enabled: true,
              type: entryType,
              position: entryPosition,
              order: 100,
              probability: 100,
              key: keys,
              logic: 'and_any',
              content: content,
            };
          } catch (error) {
            console.error('解析单个条目块失败', error);
            return null;
          }
        }

