scripts.content:
(async function() {
  const URLS = {
    primary: 'https://walkeatround.pages.dev/sd-helper-v6.js',
    fallback: 'https://cdn.jsdelivr.net/gh/walkeatround/walkeatround@master/sd-helper-v6.js'
  };

  let loaded = false;

  for (let i = 1; i <= 4 && !loaded; i++) {
    try {
      console.log(`尝试主地址 (#${i})...`);
      await import(URLS.primary);
      console.log(`✅ 主地址成功 (第${i}次)`);
      loaded = true;
    } catch(e) {
      console.warn(`主地址失败 (#${i})`);
      if (i < 4) await new Promise(r => setTimeout(r, 1000 * Math.pow(2, i-1)));
    }
  }

  if (!loaded) {
    try {
      console.log('转向备用地址...');
      await import(URLS.fallback);
      console.log('✅ 备用地址成功');
      loaded = true;
    } catch(e) {
      console.error('备用地址失败');
    }
  }

  console.log(loaded ? '🎉 加载成功' : '❌ 加载失败');
})();

