    lastRetryAt: 0,
    generation: {
      active: false,
      type: '',
      serial: 0,
      lastStoppedSerial: 0,
      startLastMessageId: -1,
      sawAssistantMessage: false,
      stoppedByUser: false,
      manualStopRequested: false,
    },
    wakeLock: {
      sentinel: null,
      retryTimer: null,
      requesting: false,
      unsupportedNotified: false,
      disposed: false,
      lastErrorName: '',
      lastErrorMessage: '',
    },
    lastAssistantRender: {
      messageId: -1,
      at: 0,
      countsForErrorRetry: false,
    },
    lastVibrationKey: '',
    uiExpandModeRetryTimer: null,
  };

  const eventStops = [];
  const domCleanup = [];

  let settings = sanitizeSettings(loadSettings());
  if (settings.panelOpen && settings.uiPage !== 'settings') {
    settings.uiPage = 'settings';
    saveSettings();
  }

  const ui = {
    widget: null,
    fab: null,
    panel: null,
    headerDrag: null,
    pageSettings: null,
    pageHelp: null,
    pageAbout: null,
    tabSettings: null,
    tabHelp: null,
    tabAbout: null,
    logInterceptPanelToggle: null,
    logInterceptPanelBody: null,
    logInterceptSourceList: null,
    logInterceptSourceEmpty: null,
    logInterceptSeenCount: null,
    logInterceptBlockedCount: null,
    iframeLoadRatio: null,
    changelogPanelToggle: null,
    changelogPanelBody: null,
    inputs: {},
  };

  const logInterception = {
    contexts: new Map(),
    windowToContextId: new WeakMap(),
    hookedIframes: new WeakSet(),
    sourceStats: new Map(),
    nextContextId: 1,
    scanTimer: null,
    observer: null,
    renderTimer: null,
    scanPending: false,
    scanPendingTimer: null,
    iframeHookAbortController: null,
    fallbackIframeListeners: [],
  };

  const iframeOptimization = {
    io: null,
    observer: null,
    scanTimer: null,
    currentRootMarginPx: null,
    managed: new Set(),
    pendingCullTimers: new Map(),
    pendingUnlockListeners: new Map(),
    pendingParkListeners: new Map(),
    parkedMeta: new WeakMap(),
    bottomWhitelistCacheAt: 0,
    bottomWhitelistCacheCount: 0,
    bottomWhitelistCacheSet: new Set(),
    pendingFullRecheck: false,
    statusRenderTimer: null,
    disposed: false,
  };

  function log(...args) {
    if (settings.debug) {
      consoleRef.log(LOG_PREFIX, ...args);
    }
  }

  function logWarn(...args) {
    consoleRef.warn(LOG_PREFIX, ...args);
  }

  function logError(...args) {
    consoleRef.error(LOG_PREFIX, ...args);
  }

  function registerEventStop(stopObj) {
    if (stopObj && typeof stopObj.stop === 'function') {
      eventStops.push(() => stopObj.stop());
    }
  }

  function onDOM(target, eventName, handler, options) {
    if (
      !target
      || typeof target.addEventListener !== 'function'
      || typeof target.removeEventListener !== 'function'
    ) {
      return;
    }
    target.addEventListener(eventName, handler, options);
    domCleanup.push(() => target.removeEventListener(eventName, handler, options));
  }

  function sanitizeLogInterceptRules(raw) {
    const sanitized = {};
    if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
      return sanitized;
    }

    let kept = 0;
    for (const [key, value] of Object.entries(raw)) {
      if (kept >= LOG_INTERCEPT_MAX_RULES) {
        break;
      }
      const sourceId = String(key ?? '').trim();
      if (!sourceId || sourceId.length > 240) {
        continue;
      }
      sanitized[sourceId] = !!value;
      kept += 1;
    }
    return sanitized;
  }

  function normalizeLogSourceMeta(sourceId, sourceLabel, fallbackToken = '') {
    const safeFallback = String(fallbackToken || 'unknown').trim();
    const safeId = String(sourceId || '').trim() || `iframe:${safeFallback}`;
    const safeLabel = String(sourceLabel || '').trim() || safeId;
    return { sourceId: safeId, sourceLabel: safeLabel };
  }

  function getLogSourceMetaForWindow(win, fallbackToken = '') {
    if (win === root) {
      return {
        sourceId: ROOT_LOG_SOURCE_ID,
        sourceLabel: '主页面（SillyTavern）',
      };
    }

    let rawId = '';
    try {
      const frameEl = win?.frameElement;
      if (frameEl) {
        rawId = String(frameEl.id || frameEl.getAttribute?.('name') || '').trim();
      }
    } catch (_error) {
      // Cross-origin frame access can fail; fallback to window name.
    }

    if (!rawId) {
      try {
        rawId = String(win?.name || '').trim();
      } catch (_error) {
        // Some frames can throw while reading name; keep fallback.
      }
    }

    if (rawId) {
      const scriptMatch = rawId.match(/^TH-script--(.+)--(.+)$/);
      if (scriptMatch) {
        const scriptName = String(scriptMatch[1] || '').trim() || '未命名脚本';
        const scriptId = String(scriptMatch[2] || '').trim() || scriptName;
        return normalizeLogSourceMeta(`script:${scriptId}`, `脚本：${scriptName}`);
      }

      const messageMatch = rawId.match(/^TH-message--(\d+)--(.+)$/);
      if (messageMatch) {
        const slot = String(messageMatch[2] || '').trim() || '0';
        return normalizeLogSourceMeta(`message-slot:${slot}`, `消息楼层界面：#${slot}`);
      }

      return normalizeLogSourceMeta(`iframe:${rawId}`, `iframe：${rawId}`);
    }

    return normalizeLogSourceMeta('', '', fallbackToken);
  }

  function shouldCollectLogSources() {
    return !!(settings.featureLogInterception || settings.logInterceptPanelOpen);
  }

  function isLogSourceBlocked(sourceId) {
    if (!settings.featureLogInterception) {
      return false;
    }
    if (settings.logInterceptSelectAll) {
      return true;
    }
    return !!settings.logInterceptRules?.[sourceId];
  }

  function ensureLogSourceStat(sourceId, sourceLabel) {
    const safeMeta = normalizeLogSourceMeta(sourceId, sourceLabel, 'unknown');
    let stat = logInterception.sourceStats.get(safeMeta.sourceId);
    if (!stat) {
      stat = {
        sourceId: safeMeta.sourceId,
        sourceLabel: safeMeta.sourceLabel,
        total: 0,
        blocked: 0,
        updatedAt: 0,
      };
      logInterception.sourceStats.set(safeMeta.sourceId, stat);
      trimLogSourceStatsIfNeeded();
    } else if (safeMeta.sourceLabel && stat.sourceLabel !== safeMeta.sourceLabel) {
      stat.sourceLabel = safeMeta.sourceLabel;
    }
    return stat;
  }

  function trimLogSourceStatsIfNeeded() {
    if (logInterception.sourceStats.size <= LOG_INTERCEPT_MAX_SOURCES) {
      return;
    }

    const stats = Array.from(logInterception.sourceStats.values())
      .sort((a, b) => (
        (a.updatedAt - b.updatedAt)
        || (a.total - b.total)
        || String(a.sourceId).localeCompare(String(b.sourceId))
      ));

    const removeCount = Math.max(0, stats.length - LOG_INTERCEPT_MAX_SOURCES);
    if (removeCount <= 0) {
      return;
    }

    for (let i = 0; i < removeCount; i += 1) {
      const stat = stats[i];
      if (!stat) {
        continue;
      }
      logInterception.sourceStats.delete(stat.sourceId);
    }
  }

  function getSortedLogSourceStats() {
    return Array.from(logInterception.sourceStats.values())
      .sort((a, b) => (
        (b.updatedAt - a.updatedAt)
        || (b.total - a.total)
        || String(a.sourceLabel).localeCompare(String(b.sourceLabel), 'zh-Hans-CN')
      ));
  }

  function syncLogSourcePanelUI() {
    const panelOpen = !!settings.logInterceptPanelOpen;

    if (ui.logInterceptPanelToggle) {
      ui.logInterceptPanelToggle.dataset.open = panelOpen ? '1' : '0';
      ui.logInterceptPanelToggle.textContent = panelOpen
        ? '收起日志来源列表'
        : '展开日志来源列表';
    }

    if (ui.logInterceptPanelBody) {
      ui.logInterceptPanelBody.hidden = !panelOpen;
    }
  }

  function syncChangelogPanelUI(panelOpen) {
    const nextOpen = !!panelOpen;
    if (ui.changelogPanelToggle) {
      ui.changelogPanelToggle.dataset.open = nextOpen ? '1' : '0';
      ui.changelogPanelToggle.textContent = nextOpen
        ? '收起更新日志'
        : '展开更新日志';
    }
    if (ui.changelogPanelBody) {
      ui.changelogPanelBody.hidden = !nextOpen;
    }
  }

  function renderLogSourcePanel() {
    const stats = getSortedLogSourceStats();
    const visibleStats = stats.filter(stat => !(Number(stat.total || 0) === 0 && Number(stat.blocked || 0) === 0));

    let totalLogs = 0;
    let blockedLogs = 0;
    for (const stat of stats) {
      totalLogs += Number(stat.total || 0);
      blockedLogs += Number(stat.blocked || 0);
    }

    if (ui.logInterceptSeenCount) {
      ui.logInterceptSeenCount.textContent = String(totalLogs);
    }
    if (ui.logInterceptBlockedCount) {
      ui.logInterceptBlockedCount.textContent = String(blockedLogs);
    }

    if (!settings.logInterceptPanelOpen) {
      return;
    }
    if (!ui.logInterceptSourceList || !ui.logInterceptSourceEmpty) {
      return;
    }

    ui.logInterceptSourceList.textContent = '';
    if (!visibleStats.length) {
      ui.logInterceptSourceEmpty.hidden = false;
      return;
    }
    ui.logInterceptSourceEmpty.hidden = true;

    const fragment = hostDocument.createDocumentFragment();
    for (const stat of visibleStats) {
      const row = hostDocument.createElement('label');
      row.className = 'th-asr-log-source-row';

      const left = hostDocument.createElement('span');
      left.className = 'th-asr-log-source-toggle';

      const checkbox = hostDocument.createElement('input');
      checkbox.type = 'checkbox';
      checkbox.dataset.logSource = stat.sourceId;
      checkbox.checked = !!settings.logInterceptSelectAll || !!settings.logInterceptRules?.[stat.sourceId];
      checkbox.disabled = !!settings.logInterceptSelectAll;

      const name = hostDocument.createElement('span');
      name.className = 'th-asr-log-source-name';
      name.textContent = stat.sourceLabel;

      left.appendChild(checkbox);
      left.appendChild(name);

      const right = hostDocument.createElement('span');
      right.className = 'th-asr-log-source-count';
      right.textContent = `拦截 ${stat.blocked} / ${stat.total}`;

      row.appendChild(left);
      row.appendChild(right);
      fragment.appendChild(row);
    }

    ui.logInterceptSourceList.appendChild(fragment);
  }

  function scheduleLogSourcePanelRender() {
    if (logInterception.renderTimer !== null) {
      return;
    }
    logInterception.renderTimer = setTimeout(() => {
      logInterception.renderTimer = null;
      renderLogSourcePanel();
    }, 120);
  }

  function recordLogSourceActivity(sourceId, sourceLabel, blocked) {
    const stat = ensureLogSourceStat(sourceId, sourceLabel);
    stat.total += 1;
    if (blocked) {
      stat.blocked += 1;
    }
    stat.updatedAt = Date.now();
    scheduleLogSourcePanelRender();
  }

  function createLogInterceptWrapper(context, level) {
    return function interceptedConsoleMethod(...args) {
      const blocked = isLogSourceBlocked(context.sourceId);
      recordLogSourceActivity(context.sourceId, context.sourceLabel, blocked);
      if (blocked) {
        return undefined;
      }

      const original = context.originals[level];
      if (typeof original === 'function' && original !== context.wrappers[level]) {
        return original.apply(context.consoleObj, args);
      }
      return undefined;
    };
  }

  function wrapContextConsole(context) {
    if (!context?.consoleObj) {
      return;
    }

    for (const level of LOG_INTERCEPT_LEVELS) {
      const current = context.consoleObj[level];
      if (typeof current !== 'function') {
        continue;
      }

      if (context.wrappers[level]) {
        continue;
      }

      context.originals[level] = current;
      const wrapper = createLogInterceptWrapper(context, level);
      context.wrappers[level] = wrapper;

      try {
        context.consoleObj[level] = wrapper;
      } catch (error) {
        delete context.originals[level];
        delete context.wrappers[level];
        logWarn(`日志拦截装配失败（${context.sourceLabel} ${level}）`, error);
      }
    }
  }

  function unwrapContextConsole(context) {
    if (!context?.consoleObj) {
      return;
    }

    for (const level of LOG_INTERCEPT_LEVELS) {
      const wrapper = context.wrappers[level];
      const original = context.originals[level];
      if (!wrapper || typeof original !== 'function') {
        delete context.wrappers[level];
        delete context.originals[level];
        continue;
      }

      try {
        if (context.consoleObj[level] === wrapper) {
          context.consoleObj[level] = original;
        }
      } catch (_error) {
        // Ignore restoration failure caused by sealed consoles.
      }
      delete context.wrappers[level];
      delete context.originals[level];
    }
  }

  function unwrapAllLogContexts({ keepStats = true } = {}) {
    for (const context of logInterception.contexts.values()) {
      unwrapContextConsole(context);
    }
    logInterception.contexts.clear();
    logInterception.windowToContextId = new WeakMap();
    if (!keepStats) {
      logInterception.sourceStats.clear();
    }
  }

  function ensureLogContext(win, fallbackToken = '') {
    if (!win) {
      return null;
    }

    const consoleObj = win?.console;
    if (!consoleObj || typeof consoleObj !== 'object') {
      return null;
    }

    let contextId = logInterception.windowToContextId.get(win);
    if (!contextId) {
      contextId = `ctx-${logInterception.nextContextId++}`;
      logInterception.windowToContextId.set(win, contextId);
    }

    let context = logInterception.contexts.get(contextId);
    if (!context) {
      context = {
        id: contextId,
        win,
        consoleObj,
        sourceId: '',
        sourceLabel: '',
        originals: Object.create(null),
        wrappers: Object.create(null),
      };
      logInterception.contexts.set(contextId, context);
    } else {
      context.consoleObj = consoleObj;
    }

    const meta = getLogSourceMetaForWindow(win, fallbackToken || contextId);
    context.sourceId = meta.sourceId;
    context.sourceLabel = meta.sourceLabel;
    ensureLogSourceStat(context.sourceId, context.sourceLabel);

    wrapContextConsole(context);
    return contextId;
  }

  function forEachIframeInNode(node, callback) {
    if (!node || typeof callback !== 'function') {
      return;
    }
    if (node.nodeType !== 1) {
      return;
    }

    const element = node;
    if (String(element.tagName || '').toUpperCase() === 'IFRAME') {
      callback(element);
    }

    if (typeof element.querySelectorAll === 'function') {
      for (const frame of element.querySelectorAll('iframe')) {
        callback(frame);
      }
    }
  }

  function ensureIframeHook(iframe) {
    if (!iframe || logInterception.hookedIframes.has(iframe)) {
      return;
    }

    logInterception.hookedIframes.add(iframe);
    const handler = () => {
      scheduleLogContextScan(20);
    };

    const controller = logInterception.iframeHookAbortController;
    if (controller && !controller.signal.aborted) {
      try {
        iframe.addEventListener('load', handler, { signal: controller.signal });
        return;
      } catch (_error) {
        // Some environments do not support addEventListener signal option.
      }
    }

    iframe.addEventListener('load', handler);
    logInterception.fallbackIframeListeners.push({ iframe, handler });
  }

  function clearIframeHooks() {
    const controller = logInterception.iframeHookAbortController;
    if (controller && !controller.signal.aborted) {
      controller.abort();
    }
    logInterception.iframeHookAbortController = null;

    if (logInterception.fallbackIframeListeners.length) {
      for (const entry of logInterception.fallbackIframeListeners.splice(0)) {
        try {
          entry.iframe?.removeEventListener?.('load', entry.handler);
        } catch (_error) {
          // Ignore detached frames.
        }
      }
    }

    logInterception.hookedIframes = new WeakSet();
  }

  function scheduleLogContextScan(delayMs = 0) {
    if (logInterception.scanPending) {
      return;
    }

    logInterception.scanPending = true;
    const safeDelay = clampInt(delayMs, 0, 10000, 0);
    logInterception.scanPendingTimer = setTimeout(() => {
      logInterception.scanPending = false;
      logInterception.scanPendingTimer = null;
      scanAndWrapLogContexts();
    }, safeDelay);
  }

  function scanAndWrapLogContexts() {
    if (!shouldCollectLogSources()) {
      return;
    }

    const aliveContextIds = new Set();
    const rootContextId = ensureLogContext(root, 'main');
    if (rootContextId) {
      aliveContextIds.add(rootContextId);
    }

    let fallbackIndex = 0;
    for (const iframe of hostDocument.querySelectorAll('iframe')) {
      ensureIframeHook(iframe);

      let frameWindow = null;
      try {
        frameWindow = iframe.contentWindow;
        if (!frameWindow) {
          continue;
        }
        // Cross-origin iframes can throw here; skip them.
        void frameWindow.document;
      } catch (_error) {
        continue;
      }

      fallbackIndex += 1;
      const fallbackToken = iframe.id || iframe.getAttribute?.('name') || `f${fallbackIndex}`;
      const contextId = ensureLogContext(frameWindow, fallbackToken);
      if (contextId) {
        aliveContextIds.add(contextId);
      }
    }

    for (const [contextId, context] of logInterception.contexts.entries()) {
      if (aliveContextIds.has(contextId)) {
        continue;
      }
      unwrapContextConsole(context);
      logInterception.contexts.delete(contextId);
    }

    scheduleLogSourcePanelRender();
  }

  function startLogInterceptionMonitor() {
    if (
      typeof AbortController === 'function'
      && (!logInterception.iframeHookAbortController || logInterception.iframeHookAbortController.signal.aborted)
    ) {
      logInterception.iframeHookAbortController = new AbortController();
    }

    if (logInterception.scanTimer === null) {
      logInterception.scanTimer = setInterval(
        () => scanAndWrapLogContexts(),
        LOG_INTERCEPT_SCAN_INTERVAL_MS
      );
    }

    for (const iframe of hostDocument.querySelectorAll('iframe')) {
      ensureIframeHook(iframe);
    }

    if (!logInterception.observer && typeof MutationObserver === 'function' && hostDocument.body) {
      logInterception.observer = new MutationObserver(mutations => {
        for (const mutation of mutations) {
          for (const node of mutation.addedNodes) {
            forEachIframeInNode(node, frame => ensureIframeHook(frame));
          }
        }
        scheduleLogContextScan(20);
      });
      logInterception.observer.observe(hostDocument.body, {
        childList: true,
        subtree: true,
      });
    }
  }

  function stopLogInterceptionMonitor() {
    if (logInterception.scanTimer !== null) {
      clearInterval(logInterception.scanTimer);
      logInterception.scanTimer = null;
    }

    if (logInterception.observer) {
      logInterception.observer.disconnect();
      logInterception.observer = null;
    }

    if (logInterception.scanPendingTimer !== null) {
      clearTimeout(logInterception.scanPendingTimer);
      logInterception.scanPendingTimer = null;
    }
    logInterception.scanPending = false;
    clearIframeHooks();
  }

  function refreshLogInterceptionState(reason = '') {
    if (shouldCollectLogSources()) {
      startLogInterceptionMonitor();
      scheduleLogContextScan(0);
    } else {
      stopLogInterceptionMonitor();
      unwrapAllLogContexts({ keepStats: true });
    }

    syncLogSourcePanelUI();
    scheduleLogSourcePanelRender();

    if (reason && settings.debug) {
      log(
        `日志拦截状态已刷新：${reason}（拦截=${settings.featureLogInterception ? '开' : '关'}，来源面板=${settings.logInterceptPanelOpen ? '开' : '关'}）`
      );
    }
  }

  function teardownLogInterception() {
    stopLogInterceptionMonitor();
    if (logInterception.renderTimer !== null) {
      clearTimeout(logInterception.renderTimer);
      logInterception.renderTimer = null;
    }
    unwrapAllLogContexts({ keepStats: false });
  }

  function parseMessageIdFromIframeId(rawId) {
    const match = String(rawId || '').match(/^TH-message--(\d+)--/);
    if (!match) {
      return null;
    }
    const id = Number(match[1]);
    return Number.isFinite(id) ? id : null;
  }

  function computeIframeLoadStatus() {
    const frames = hostDocument.querySelectorAll('iframe[id^="TH-message--"]');
    const total = frames.length;
    let loaded = 0;
    for (const iframe of frames) {
      if (iframe?.dataset?.thAsrIframeParked !== '1') {
        loaded += 1;
      }
    }
    return { loaded, total };
  }

  function isMessageFloorNode(node) {
    if (!node || node.nodeType !== 1) {
      return false;
    }
    const element = node;
    if (typeof element.matches === 'function' && element.matches('.mes[mesid]')) {
      return true;
    }
    if (element.childElementCount <= 0 || typeof element.querySelector !== 'function') {
      return false;
    }
    return !!element.querySelector('.mes[mesid]');
  }

  function isIframeOptimizationMutationRelevantNode(node) {
    if (!node || node.nodeType !== 1) {
      return false;
    }
    const element = node;
    if (isMessageIframe(element) || isMessageFloorNode(element)) {
      return true;
    }
    if (element.childElementCount <= 0 || typeof element.querySelector !== 'function') {
      return false;
    }
    return !!element.querySelector('iframe[id^="TH-message--"]');
  }

  function markIframeFullRecheckPending() {
    iframeOptimization.pendingFullRecheck = true;
  }

  function shouldRenderIframeLoadStatus() {
    return !!(
      ui.iframeLoadRatio
      && settings.panelOpen
      && settings.uiPage === 'settings'
    );
  }

  function renderIframeLoadStatus() {
    if (!shouldRenderIframeLoadStatus()) {
      return;
    }
    const { loaded, total } = computeIframeLoadStatus();
    ui.iframeLoadRatio.textContent = `${loaded}/${total}`;
  }

  function scheduleIframeLoadStatusRender(delayMs = 0) {
    if (!shouldRenderIframeLoadStatus()) {
      return;
    }
    const safeDelay = Math.max(0, Math.min(1000, Number(delayMs) || 0));
    if (iframeOptimization.statusRenderTimer !== null) {
      return;
    }
    iframeOptimization.statusRenderTimer = setTimeout(() => {
      iframeOptimization.statusRenderTimer = null;
      renderIframeLoadStatus();
    }, safeDelay);
  }

  function isMessageIframe(iframe) {
    if (!iframe || String(iframe.tagName || '').toUpperCase() !== 'IFRAME') {
      return false;
    }
    const id = String(iframe.id || '').trim();
    return /^TH-message--\d+--/.test(id);
  }

  function getIframeOptimizeRootMarginPx() {
    return normalizeSettingInt(
      settings.iframeCullRootMarginPx,
      0,
      6000,
      DEFAULT_SETTINGS.iframeCullRootMarginPx,
      settings.featureProfessionalUser
    );
  }

  function getIframeOptimizeDelayMs() {
    return normalizeSettingInt(
      settings.iframeCullDelayMs,
      0,
      10000,
      DEFAULT_SETTINGS.iframeCullDelayMs,
      settings.featureProfessionalUser
    );
  }

  function getIframeBottomWhitelistCount() {
    return normalizeSettingInt(
      settings.iframeBottomWhitelistCount,
      0,
      120,
      DEFAULT_SETTINGS.iframeBottomWhitelistCount,
      settings.featureProfessionalUser
    );
  }

  function getBottomWhitelistedMessageIdSet() {
    const safeCount = getIframeBottomWhitelistCount();
    if (safeCount <= 0) {
      iframeOptimization.bottomWhitelistCacheAt = Date.now();
      iframeOptimization.bottomWhitelistCacheCount = 0;
      iframeOptimization.bottomWhitelistCacheSet = new Set();
      return iframeOptimization.bottomWhitelistCacheSet;
    }

    const now = Date.now();
    if (
      iframeOptimization.bottomWhitelistCacheCount === safeCount
      && now - iframeOptimization.bottomWhitelistCacheAt <= 200
    ) {
      return iframeOptimization.bottomWhitelistCacheSet;
    }

    // 只以主聊天列表中的楼层顺序作为“底部白名单”依据，避免页面其他 .mes 干扰。
    const nodes = hostDocument.querySelectorAll('#chat > .mes[mesid]');
    const result = new Set();
    for (let i = nodes.length - 1; i >= 0 && result.size < safeCount; i -= 1) {
      const id = Number(nodes[i].getAttribute('mesid'));
      if (Number.isFinite(id)) {
        result.add(id);
      }
    }

    iframeOptimization.bottomWhitelistCacheAt = now;
    iframeOptimization.bottomWhitelistCacheCount = safeCount;
    iframeOptimization.bottomWhitelistCacheSet = result;
    return result;
  }

  function isMessageIdWhitelistedFromBottom(messageId) {
    if (!Number.isFinite(messageId)) {
      return false;
    }
    const set = getBottomWhitelistedMessageIdSet();
    return set.has(messageId);
  }

  function isIframeWhitelistedFromBottom(iframe) {
    const messageId = parseMessageIdFromIframeId(iframe?.id);
    if (!Number.isFinite(messageId)) {
      return false;
    }
    return isMessageIdWhitelistedFromBottom(messageId);
  }

  function clearIframeCullTimer(iframe) {
    const timer = iframeOptimization.pendingCullTimers.get(iframe);
    if (timer !== undefined) {
      clearTimeout(timer);
      iframeOptimization.pendingCullTimers.delete(iframe);
    }
  }

  function clearIframeUnlockListener(iframe) {
    const handler = iframeOptimization.pendingUnlockListeners.get(iframe);
    if (handler) {
      try {
        iframe.removeEventListener('load', handler);
      } catch (_error) {
        // Ignore detached frames.
      }
      iframeOptimization.pendingUnlockListeners.delete(iframe);
    }
  }

  function clearIframeParkListener(iframe) {
    const handler = iframeOptimization.pendingParkListeners.get(iframe);
    if (handler) {
      try {
        iframe.removeEventListener('load', handler);
      } catch (_error) {
        // Ignore detached frames.
      }
      iframeOptimization.pendingParkListeners.delete(iframe);
    }
  }

  function releaseIframeHeightLock(iframe) {
    const meta = iframeOptimization.parkedMeta.get(iframe);
    if (meta && Object.prototype.hasOwnProperty.call(meta, 'prevMinHeight')) {
      iframe.style.minHeight = meta.prevMinHeight || '';
    } else {
      iframe.style.minHeight = '';
    }
    iframeOptimization.parkedMeta.delete(iframe);
  }

  function markIframeParked(iframe) {
    iframe.dataset.thAsrIframeParked = '1';
    scheduleIframeLoadStatusRender(0);
  }

  function clearIframeParkedState(iframe) {
    delete iframe.dataset.thAsrIframeParked;
    releaseIframeHeightLock(iframe);
    scheduleIframeLoadStatusRender(0);
  }

  function restoreParkedIframe(iframe) {
    if (!iframe) {
      return;
    }

    clearIframeCullTimer(iframe);
    // 可视区触发恢复时，先取消可能正在进行的“回收到 about:blank”流程。
    clearIframeParkListener(iframe);
    if (iframe.dataset.thAsrIframeParked !== '1') {
      return;
    }
    if (!iframe.isConnected) {
      clearIframeParkedState(iframe);
      return;
    }
    // 已在恢复流程中时不重复触发，避免反复重载 srcdoc 导致闪烁。
    if (iframeOptimization.pendingUnlockListeners.has(iframe)) {
      return;
    }

    const srcdoc = iframe.getAttribute('srcdoc');
    if (!srcdoc || !String(srcdoc).trim()) {
      clearIframeParkedState(iframe);
      return;
    }

    const handleLoad = () => {
      iframeOptimization.pendingUnlockListeners.delete(iframe);
      clearIframeParkedState(iframe);
    };
    iframeOptimization.pendingUnlockListeners.set(iframe, handleLoad);
    iframe.addEventListener('load', handleLoad, { once: true });

    try {
      iframe.srcdoc = srcdoc;
    } catch (_error) {
      clearIframeUnlockListener(iframe);
      clearIframeParkedState(iframe);
    }
  }

  function parkIframe(iframe) {
    if (
      !iframe
      || iframe.dataset.thAsrIframeParked === '1'
      || iframeOptimization.pendingParkListeners.has(iframe)
    ) {
      return;
    }
    if (!isMessageIframe(iframe) || isIframeWhitelistedFromBottom(iframe)) {
      return;
    }
    if (!iframe.isConnected) {
      return;
    }

    // 暂不处理 blob 渲染模式（通常表现为仅有 src/blob:，没有 srcdoc）。
    // TODO: 如后续需要支持 blob 渲染，再补充 URL 管理与恢复策略。
    const srcdoc = iframe.getAttribute('srcdoc');
    if (!srcdoc || !String(srcdoc).trim()) {
      return;
    }

    clearIframeUnlockListener(iframe);
    clearIframeParkListener(iframe);
    const rect = iframe.getBoundingClientRect();
    iframeOptimization.parkedMeta.set(iframe, { prevMinHeight: iframe.style.minHeight || '' });
    if (rect.height > 0) {
      iframe.style.minHeight = `${Math.ceil(rect.height)}px`;
    }

    const handleLoad = () => {
      iframeOptimization.pendingParkListeners.delete(iframe);
      if (!iframe.isConnected) {
        clearIframeParkedState(iframe);
        return;
      }
      let isAboutBlank = false;
      try {
        isAboutBlank = iframe.contentWindow?.location?.href === 'about:blank';
      } catch (_error) {
        // 保守处理：若无法读取地址，按已回收处理，避免重复回收触发。
        isAboutBlank = true;
      }
      if (isAboutBlank) {
        markIframeParked(iframe);
      } else {
        clearIframeParkedState(iframe);
      }
    };
    iframeOptimization.pendingParkListeners.set(iframe, handleLoad);
    iframe.addEventListener('load', handleLoad, { once: true });

    let parkRequested = false;
    try {
      const frameWindow = iframe.contentWindow;
      if (frameWindow && frameWindow.location && typeof frameWindow.location.replace === 'function') {
        frameWindow.location.replace('about:blank');
        parkRequested = true;
      }
    } catch (_error) {
      parkRequested = false;
    }

    if (!parkRequested) {
      clearIframeParkListener(iframe);
      clearIframeParkedState(iframe);
      return;
    }

    // 某些环境会同步切换到 about:blank，这里做一次快速确认。
    try {
      if (iframe.contentWindow?.location?.href === 'about:blank') {
        clearIframeParkListener(iframe);
        markIframeParked(iframe);
      }
    } catch (_error) {
      // Keep waiting for load event confirmation.
    }
  }

  function queueIframeCull(iframe) {
    if (
      !iframe
      || iframe.dataset.thAsrIframeParked === '1'
      || iframeOptimization.pendingParkListeners.has(iframe)
      || isIframeWhitelistedFromBottom(iframe)
    ) {
      return;
    }
    // 已排队的离屏回收不要重复重置，否则在高频扫描下可能永远触发不到回收。
    if (iframeOptimization.pendingCullTimers.has(iframe)) {
      return;
    }
    const delay = getIframeOptimizeDelayMs();
    if (delay <= 0) {
      parkIframe(iframe);
      return;
    }
    const timer = setTimeout(() => {
      iframeOptimization.pendingCullTimers.delete(iframe);
      parkIframe(iframe);
    }, delay);
    iframeOptimization.pendingCullTimers.set(iframe, timer);
  }

  function isIframeNearViewport(iframe) {
    if (!iframe || !iframe.isConnected) {
      return false;
    }
    const margin = getIframeOptimizeRootMarginPx();
    const rect = iframe.getBoundingClientRect();
    return rect.bottom >= -margin && rect.top <= (root.innerHeight + margin);
  }

  function evaluateIframeOptimizationState(iframe) {
    if (!iframe || !iframe.isConnected) {
      return;
    }
    if (!isMessageIframe(iframe)) {
      return;
    }
    if (isIframeWhitelistedFromBottom(iframe) || isIframeNearViewport(iframe)) {
      restoreParkedIframe(iframe);
      return;
    }
    queueIframeCull(iframe);
  }

  function unmanageIframe(iframe, { restoreIfParked = false } = {}) {
    if (!iframe) {
      return;
    }
    clearIframeCullTimer(iframe);
    clearIframeUnlockListener(iframe);
    clearIframeParkListener(iframe);
    if (restoreIfParked) {
      restoreParkedIframe(iframe);
    } else if (iframe.dataset.thAsrIframeParked === '1') {
      clearIframeParkedState(iframe);
    }
    if (iframeOptimization.io) {
      try {
        iframeOptimization.io.unobserve(iframe);
      } catch (_error) {
        // Ignore detached frames.
      }
    }
    iframeOptimization.managed.delete(iframe);
    scheduleIframeLoadStatusRender(0);
  }

  function manageIframe(iframe) {
    if (!isMessageIframe(iframe)) {
      return;
    }
    if (iframeOptimization.managed.has(iframe)) {
      return;
    }
    if (iframeOptimization.managed.size >= IFRAME_OPTIMIZE_MAX_MANAGED) {
      return;
    }
    iframeOptimization.managed.add(iframe);
    if (iframeOptimization.io) {
      iframeOptimization.io.observe(iframe);
    }
    evaluateIframeOptimizationState(iframe);
    scheduleIframeLoadStatusRender(0);
  }

  function scanAndManageMessageIframes() {
    if (!hostDocument.body) {
      return;
    }

    for (const iframe of Array.from(iframeOptimization.managed)) {
      if (!iframe || !iframe.isConnected || !isMessageIframe(iframe)) {
        unmanageIframe(iframe);
      }
    }

    const frames = hostDocument.querySelectorAll('iframe[id^="TH-message--"]');
    for (const iframe of frames) {
      manageIframe(iframe);
    }
  }

  function scheduleIframeOptimizationScan(delayMs = 0, { recheckAll = false } = {}) {
    const safeDelay = clampInt(delayMs, 0, 10000, 0);
    if (recheckAll) {
      markIframeFullRecheckPending();
    }
    if (iframeOptimization.scanTimer !== null) {
      return;
    }
    iframeOptimization.scanTimer = setTimeout(() => {
      iframeOptimization.scanTimer = null;
      const shouldRecheckAll = iframeOptimization.pendingFullRecheck;
      iframeOptimization.pendingFullRecheck = false;
      iframeOptimization.bottomWhitelistCacheAt = 0;
      scanAndManageMessageIframes();
      if (shouldRecheckAll) {
        for (const iframe of iframeOptimization.managed) {
          evaluateIframeOptimizationState(iframe);
        }
      }
      scheduleIframeLoadStatusRender(0);
    }, safeDelay);
  }

  function recreateIframeIntersectionObserver() {
    if (typeof IntersectionObserver !== 'function') {
      return false;
    }

    const margin = getIframeOptimizeRootMarginPx();
    if (iframeOptimization.io && iframeOptimization.currentRootMarginPx === margin) {
      return true;
    }

    if (iframeOptimization.io) {
      iframeOptimization.io.disconnect();
      iframeOptimization.io = null;
    }

    iframeOptimization.io = new IntersectionObserver(entries => {
      for (const entry of entries) {
        const iframe = entry.target;
        if (!iframe || !isMessageIframe(iframe)) {
          continue;
        }
        if (entry.isIntersecting || isIframeWhitelistedFromBottom(iframe)) {
          restoreParkedIframe(iframe);
        } else {
          queueIframeCull(iframe);
        }
      }
    }, {
      rootMargin: `${margin}px 0px`,
    });
    iframeOptimization.currentRootMarginPx = margin;

    for (const iframe of iframeOptimization.managed) {
      iframeOptimization.io.observe(iframe);
    }

    return true;
  }

  function startIframeMemoryOptimizationMonitor() {
    if (!hostDocument.body) {
      return;
    }
    if (!recreateIframeIntersectionObserver()) {
      return;
    }

    if (!iframeOptimization.observer && typeof MutationObserver === 'function') {
      iframeOptimization.observer = new MutationObserver(mutations => {
        let shouldRescan = false;
        let needsFullRecheck = false;
        for (const mutation of mutations) {
          for (const node of mutation.addedNodes) {
            if (!isIframeOptimizationMutationRelevantNode(node)) {
              continue;
            }
            shouldRescan = true;
            if (isMessageFloorNode(node)) {
              needsFullRecheck = true;
            }
            forEachIframeInNode(node, frame => manageIframe(frame));
          }
          for (const node of mutation.removedNodes) {
            if (!isIframeOptimizationMutationRelevantNode(node)) {
              continue;
            }
            shouldRescan = true;
            if (isMessageFloorNode(node)) {
              needsFullRecheck = true;
            }
            forEachIframeInNode(node, frame => unmanageIframe(frame));
          }
        }
        if (shouldRescan) {
          scheduleIframeOptimizationScan(120, { recheckAll: needsFullRecheck });
        }
      });
      const observeTarget = hostDocument.querySelector('#chat') || hostDocument.body;
      iframeOptimization.observer.observe(observeTarget, {
        childList: true,
        subtree: true,
      });
    }

    scanAndManageMessageIframes();
    scheduleIframeOptimizationScan(0, { recheckAll: true });
    scheduleIframeLoadStatusRender(0);
  }

  function stopIframeMemoryOptimizationMonitor() {
    if (iframeOptimization.scanTimer !== null) {
      clearTimeout(iframeOptimization.scanTimer);
      iframeOptimization.scanTimer = null;
    }

    if (iframeOptimization.observer) {
      iframeOptimization.observer.disconnect();
      iframeOptimization.observer = null;
    }

    if (iframeOptimization.io) {
      iframeOptimization.io.disconnect();
      iframeOptimization.io = null;
    }
    if (iframeOptimization.statusRenderTimer !== null) {
      clearTimeout(iframeOptimization.statusRenderTimer);
      iframeOptimization.statusRenderTimer = null;
    }
    iframeOptimization.currentRootMarginPx = null;
    iframeOptimization.bottomWhitelistCacheAt = 0;
    iframeOptimization.bottomWhitelistCacheCount = 0;
    iframeOptimization.bottomWhitelistCacheSet = new Set();
    iframeOptimization.pendingFullRecheck = false;

    for (const iframe of Array.from(iframeOptimization.managed)) {
      unmanageIframe(iframe, { restoreIfParked: true });
    }
    iframeOptimization.managed.clear();

    const parkedFrames = hostDocument.querySelectorAll('iframe[data-th-asr-iframe-parked="1"]');
    parkedFrames.forEach(iframe => {
      restoreParkedIframe(iframe);
    });
    scheduleIframeLoadStatusRender(0);
  }

  function refreshIframeMemoryOptimizationState(reason = '') {
    if (settings.featureIframeMemoryOptimize) {
      startIframeMemoryOptimizationMonitor();
      scheduleIframeOptimizationScan(0, { recheckAll: true });
    } else {
      stopIframeMemoryOptimizationMonitor();
    }

    if (reason && settings.debug) {
      log(
        `Iframe 内存优化状态已刷新：${reason}（优化=${settings.featureIframeMemoryOptimize ? '开' : '关'}）`
      );
    }
    scheduleIframeLoadStatusRender(0);
  }

  function teardownIframeMemoryOptimization() {
    stopIframeMemoryOptimizationMonitor();
    iframeOptimization.disposed = true;
  }

  function clampInt(value, min, max, fallback) {
    const n = Number(value);
    if (!Number.isFinite(n)) {
      return fallback;
    }
    const rounded = Math.round(n);
    return Math.min(max, Math.max(min, rounded));
  }

  function parseRoundedInt(value, fallback) {
    const n = Number(value);
    if (!Number.isFinite(n)) {
      return fallback;
    }
    return Math.round(n);
  }

  function normalizeSettingInt(value, min, max, fallback, unlockRanges = false) {
    if (unlockRanges) {
      return parseRoundedInt(value, fallback);
    }
    return clampInt(value, min, max, fallback);
  }

  function clampFloat(value, min, max, fallback) {
    const n = Number(value);
    if (!Number.isFinite(n)) {
      return fallback;
    }
    return Math.min(max, Math.max(min, n));
  }

  function normalizeHexColor(value, fallback) {
    const raw = String(value ?? '').trim();
    if (/^#[0-9a-fA-F]{6}$/.test(raw)) return raw.toLowerCase();
    if (/^#[0-9a-fA-F]{3}$/.test(raw)) {
      return `#${raw[1]}${raw[1]}${raw[2]}${raw[2]}${raw[3]}${raw[3]}`.toLowerCase();
    }
    return fallback;
  }

  function hexToRgb(hex) {
    const safe = normalizeHexColor(hex, '#000000');
    return {
      r: Number.parseInt(safe.slice(1, 3), 16),
      g: Number.parseInt(safe.slice(3, 5), 16),
      b: Number.parseInt(safe.slice(5, 7), 16),
    };
  }

  function toHexByte(value) {
    return Math.min(255, Math.max(0, Math.round(value))).toString(16).padStart(2, '0');
  }

  function rgbToHex(rgb) {
    return `#${toHexByte(rgb.r)}${toHexByte(rgb.g)}${toHexByte(rgb.b)}`;
  }

  function mixHex(colorA, colorB, ratio) {
    const t = clampFloat(ratio, 0, 1, 0.5);
    const a = hexToRgb(colorA);
    const b = hexToRgb(colorB);
    return rgbToHex({
      r: a.r + (b.r - a.r) * t,
      g: a.g + (b.g - a.g) * t,
      b: a.b + (b.b - a.b) * t,
    });
  }

  function srgbToLinear(v) {
    const x = v / 255;
    return x <= 0.04045 ? x / 12.92 : ((x + 0.055) / 1.055) ** 2.4;
  }

  function relativeLuminance(hex) {
    const rgb = hexToRgb(hex);
    const r = srgbToLinear(rgb.r);
    const g = srgbToLinear(rgb.g);
    const b = srgbToLinear(rgb.b);
    return 0.2126 * r + 0.7152 * g + 0.0722 * b;
  }

  function contrastRatio(colorA, colorB) {
    const l1 = relativeLuminance(colorA);
    const l2 = relativeLuminance(colorB);
    const bright = Math.max(l1, l2);
    const dark = Math.min(l1, l2);
    return (bright + 0.05) / (dark + 0.05);
  }

  function pickReadableText(backgroundColor) {
    const dark = '#0f172a';
    const light = '#f8fafc';
    return contrastRatio(backgroundColor, dark) >= contrastRatio(backgroundColor, light) ? dark : light;
  }

  function getThemePresetPatch(name) {
    const preset = THEME_PRESETS[String(name)];
    if (!preset) return null;
    return {
      uiThemePreset: String(name),
      fabColorA: preset.fabColorA,
      fabColorB: preset.fabColorB,
      panelColor: preset.panelColor,
    };
  }

  function normalizeUiExpandMode(value, fallback = DEFAULT_SETTINGS.uiExpandMode) {
    const raw = String(value || '');
    if (Object.values(UI_EXPAND_MODES).includes(raw)) {
      return raw;
    }
    return String(fallback || DEFAULT_SETTINGS.uiExpandMode);
  }

  function sanitizeSettings(raw) {
    const rawObj = (raw && typeof raw === 'object') ? raw : {};
    const s = Object.assign({}, DEFAULT_SETTINGS, rawObj);
    s.featureAutoScroll = !!s.featureAutoScroll;
    s.featureAutoRetry = !!s.featureAutoRetry;
    s.featureErrorRetry = !!s.featureErrorRetry;
    s.featureJumpBottomOnChatOpen = !!s.featureJumpBottomOnChatOpen;
    s.featureKeepScreenAwake = !!s.featureKeepScreenAwake;
    s.featureMobileVibration = !!s.featureMobileVibration;
    s.featureLogInterception = !!s.featureLogInterception;
    s.featureIframeMemoryOptimize = !!s.featureIframeMemoryOptimize;
    s.featureProfessionalUser = !!s.featureProfessionalUser;
    const hasLegacyPopup = Object.prototype.hasOwnProperty.call(rawObj, 'showRetryPopup');
    const hasShortPopup = Object.prototype.hasOwnProperty.call(rawObj, 'showShortRetryPopup');
    const hasErrorPopup = Object.prototype.hasOwnProperty.call(rawObj, 'showErrorRetryPopup');
    const hasLegacyIdleTimeout = Object.prototype.hasOwnProperty.call(rawObj, 'waitIdleTimeoutMs');
    const hasLegacyIdlePoll = Object.prototype.hasOwnProperty.call(rawObj, 'waitIdlePollMs');
    const hasShortIdleTimeout = Object.prototype.hasOwnProperty.call(rawObj, 'shortWaitIdleTimeoutMs');
    const hasShortIdlePoll = Object.prototype.hasOwnProperty.call(rawObj, 'shortWaitIdlePollMs');
    const hasErrorIdleTimeout = Object.prototype.hasOwnProperty.call(rawObj, 'errorWaitIdleTimeoutMs');
    const hasErrorIdlePoll = Object.prototype.hasOwnProperty.call(rawObj, 'errorWaitIdlePollMs');
    s.showShortRetryPopup = !hasShortPopup && hasLegacyPopup ? !!rawObj.showRetryPopup : !!s.showShortRetryPopup;
    s.showErrorRetryPopup = !hasErrorPopup && hasLegacyPopup ? !!rawObj.showRetryPopup : !!s.showErrorRetryPopup;
    s.shortWaitIdleTimeoutMs = !hasShortIdleTimeout && hasLegacyIdleTimeout ? rawObj.waitIdleTimeoutMs : s.shortWaitIdleTimeoutMs;
    s.shortWaitIdlePollMs = !hasShortIdlePoll && hasLegacyIdlePoll ? rawObj.waitIdlePollMs : s.shortWaitIdlePollMs;
    s.errorWaitIdleTimeoutMs = !hasErrorIdleTimeout && hasLegacyIdleTimeout ? rawObj.waitIdleTimeoutMs : s.errorWaitIdleTimeoutMs;
    s.errorWaitIdlePollMs = !hasErrorIdlePoll && hasLegacyIdlePoll ? rawObj.waitIdlePollMs : s.errorWaitIdlePollMs;
    s.debug = !!s.debug;
    s.logInterceptPanelOpen = !!s.logInterceptPanelOpen;
    s.logInterceptSelectAll = !!s.logInterceptSelectAll;
    s.logInterceptRules = sanitizeLogInterceptRules(s.logInterceptRules);
    s.panelOpen = !!s.panelOpen;
    const unlockRanges = s.featureProfessionalUser;

    s.minChars = normalizeSettingInt(s.minChars, 0, 5000, DEFAULT_SETTINGS.minChars, unlockRanges);
    s.maxRetriesPerMessage = normalizeSettingInt(
      s.maxRetriesPerMessage,
      0,
      20,
      DEFAULT_SETTINGS.maxRetriesPerMessage,
      unlockRanges
    );
    s.maxErrorRetriesPerCycle = normalizeSettingInt(
      s.maxErrorRetriesPerCycle,
      0,
      20,
      DEFAULT_SETTINGS.maxErrorRetriesPerCycle,
      unlockRanges
    );
    s.renderSettleDelayMs = normalizeSettingInt(s.renderSettleDelayMs, 0, 5000, DEFAULT_SETTINGS.renderSettleDelayMs, unlockRanges);
    s.scrollBehavior = ['auto', 'smooth'].includes(String(s.scrollBehavior))
      ? String(s.scrollBehavior)
      : DEFAULT_SETTINGS.scrollBehavior;
    s.scrollRetryTimes = normalizeSettingInt(s.scrollRetryTimes, 0, 80, DEFAULT_SETTINGS.scrollRetryTimes, unlockRanges);
    s.scrollRetryIntervalMs = normalizeSettingInt(
      s.scrollRetryIntervalMs,
      20,
      3000,
      DEFAULT_SETTINGS.scrollRetryIntervalMs,
      unlockRanges
    );
    s.retryDelayMs = normalizeSettingInt(s.retryDelayMs, 0, 10000, DEFAULT_SETTINGS.retryDelayMs, unlockRanges);
    s.errorRetryDelayMs = normalizeSettingInt(s.errorRetryDelayMs, 0, 10000, DEFAULT_SETTINGS.errorRetryDelayMs, unlockRanges);
    s.shortWaitIdleTimeoutMs = normalizeSettingInt(
      s.shortWaitIdleTimeoutMs,
      1000,
      120000,
      DEFAULT_SETTINGS.shortWaitIdleTimeoutMs,
      unlockRanges
    );
    s.shortWaitIdlePollMs = normalizeSettingInt(
      s.shortWaitIdlePollMs,
      50,
      5000,
      DEFAULT_SETTINGS.shortWaitIdlePollMs,
      unlockRanges
    );
    s.errorWaitIdleTimeoutMs = normalizeSettingInt(
      s.errorWaitIdleTimeoutMs,
      1000,
      120000,
      DEFAULT_SETTINGS.errorWaitIdleTimeoutMs,
      unlockRanges
    );
    s.errorWaitIdlePollMs = normalizeSettingInt(
      s.errorWaitIdlePollMs,
      50,
      5000,
      DEFAULT_SETTINGS.errorWaitIdlePollMs,
      unlockRanges
    );
    s.chatOpenJumpDelayMs = normalizeSettingInt(s.chatOpenJumpDelayMs, 0, 10000, DEFAULT_SETTINGS.chatOpenJumpDelayMs, unlockRanges);
    s.chatOpenJumpRetryTimes = normalizeSettingInt(s.chatOpenJumpRetryTimes, 0, 80, DEFAULT_SETTINGS.chatOpenJumpRetryTimes, unlockRanges);
    s.chatOpenJumpRetryIntervalMs = normalizeSettingInt(
      s.chatOpenJumpRetryIntervalMs,
      20,
      3000,
      DEFAULT_SETTINGS.chatOpenJumpRetryIntervalMs,
      unlockRanges
    );
    s.vibrationDurationMs = normalizeSettingInt(
      s.vibrationDurationMs,
      20,
      1000,
      DEFAULT_SETTINGS.vibrationDurationMs,
      unlockRanges
    );
    s.iframeCullRootMarginPx = normalizeSettingInt(
      s.iframeCullRootMarginPx,
      0,
      6000,
      DEFAULT_SETTINGS.iframeCullRootMarginPx,
      unlockRanges
    );
    s.iframeCullDelayMs = normalizeSettingInt(
      s.iframeCullDelayMs,
      0,
      10000,
      DEFAULT_SETTINGS.iframeCullDelayMs,
      unlockRanges
    );
    s.iframeBottomWhitelistCount = normalizeSettingInt(
      s.iframeBottomWhitelistCount,
      0,
      120,
      DEFAULT_SETTINGS.iframeBottomWhitelistCount,
      unlockRanges
    );

    s.uiThemePreset = ['custom', ...Object.keys(THEME_PRESETS)].includes(String(s.uiThemePreset))
      ? String(s.uiThemePreset)
      : DEFAULT_SETTINGS.uiThemePreset;
    s.fabSizePx = normalizeSettingInt(s.fabSizePx, 32, 96, DEFAULT_SETTINGS.fabSizePx, unlockRanges);
    s.fabOpacityPercent = normalizeSettingInt(
      s.fabOpacityPercent,
      0,
      100,
      DEFAULT_SETTINGS.fabOpacityPercent,
      unlockRanges
    );
    s.fabColorA = normalizeHexColor(s.fabColorA, DEFAULT_SETTINGS.fabColorA);
    s.fabColorB = normalizeHexColor(s.fabColorB, DEFAULT_SETTINGS.fabColorB);
    s.panelColor = normalizeHexColor(s.panelColor, DEFAULT_SETTINGS.panelColor);
    s.uiExpandMode = normalizeUiExpandMode(s.uiExpandMode, DEFAULT_SETTINGS.uiExpandMode);

    s.uiPage = ['settings', 'help', 'about'].includes(String(s.uiPage)) ? String(s.uiPage) : 'settings';
    s.uiLeft = Number.isFinite(Number(s.uiLeft)) ? Number(s.uiLeft) : null;
    s.uiTop = Number.isFinite(Number(s.uiTop)) ? Number(s.uiTop) : null;
    return s;
  }

  // Local persistence keeps user preferences across refreshes.
  function loadSettings() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) {
        return {};
      }
      return JSON.parse(raw);
    } catch (error) {
      logWarn('加载设置失败', error);
      return {};
    }
  }

  function saveSettings() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
    } catch (error) {
      logWarn('保存设置失败', error);
    }
  }

  function updateSettings(patch) {
    settings = sanitizeSettings(Object.assign({}, settings, patch || {}));
    saveSettings();
    syncUIFromSettings();
  }

  // Compute CSS variables so custom colors remain readable in light/dark backgrounds.
  function applyThemeVariables() {
    if (!ui.widget) return;

    const fabColorA = normalizeHexColor(settings.fabColorA, DEFAULT_SETTINGS.fabColorA);
    const fabColorB = normalizeHexColor(settings.fabColorB, DEFAULT_SETTINGS.fabColorB);
    const panelColor = normalizeHexColor(settings.panelColor, DEFAULT_SETTINGS.panelColor);
    const fabOpacityPercent = normalizeSettingInt(
      settings.fabOpacityPercent,
      0,
      100,
      DEFAULT_SETTINGS.fabOpacityPercent
    );
    const fabOpacity = clampFloat(fabOpacityPercent / 100, 0, 1, 1);

    const panelText = pickReadableText(panelColor);
    const isDarkPanel = panelText === '#f8fafc';

    const fabMix = mixHex(fabColorA, fabColorB, 0.5);
    const fabText = pickReadableText(fabMix);
    const headerText = pickReadableText(mixHex(fabColorA, fabColorB, 0.42));

    const panelBorder = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.24) : mixHex(panelColor, '#0f172a', 0.14);
    const panelBodyTop = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.04) : mixHex(panelColor, '#3b82f6', 0.06);
    const sectionBg = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.08) : mixHex(panelColor, '#0f172a', 0.02);
    const sectionBorder = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.16) : mixHex(panelColor, '#0f172a', 0.09);
    const inputBg = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.06) : '#ffffff';
    const inputBorder = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.22) : mixHex(panelColor, '#0f172a', 0.18);
    const accent = isDarkPanel ? mixHex(fabColorA, '#ffffff', 0.35) : mixHex(fabColorB, '#1d4ed8', 0.2);

    const miniBtnBg = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.18) : '#ffffff';
    const miniBtnText = pickReadableText(miniBtnBg);
    const miniBtnActiveBg = isDarkPanel ? mixHex(panelColor, '#60a5fa', 0.24) : '#dbeafe';
    const miniBtnActiveText = pickReadableText(miniBtnActiveBg);

    const codeBg = isDarkPanel ? mixHex(panelColor, '#000000', 0.16) : mixHex(panelColor, '#3b82f6', 0.08);
    const codeBorder = isDarkPanel ? mixHex(panelColor, '#ffffff', 0.22) : mixHex(panelColor, '#1d4ed8', 0.2);
    const focusRing = isDarkPanel ? mixHex(accent, '#ffffff', 0.42) : mixHex(accent, '#93c5fd', 0.5);
    const fabShadow = isDarkPanel ? '0 10px 26px rgba(2, 6, 23, 0.58)' : '0 10px 24px rgba(15, 23, 42, 0.32)';
    const fabShadowHover = isDarkPanel ? '0 14px 34px rgba(2, 6, 23, 0.66)' : '0 14px 30px rgba(15, 23, 42, 0.38)';
    const panelShadow = isDarkPanel ? '0 20px 44px rgba(2, 6, 23, 0.52)' : '0 18px 40px rgba(15, 23, 42, 0.24)';

    const vars = {
      '--fab-size': `${settings.fabSizePx}px`,
      '--fab-opacity': String(fabOpacity),
      '--fab-grad-a': fabColorA,
      '--fab-grad-b': fabColorB,
      '--fab-text': fabText,
      '--fab-off-a': '#6b7280',
      '--fab-off-b': '#4b5563',
      '--fab-shadow': fabShadow,
      '--fab-shadow-hover': fabShadowHover,
      '--panel-bg': panelColor,
      '--panel-text': panelText,
      '--panel-border': panelBorder,
      '--panel-shadow': panelShadow,
      '--panel-body-top': panelBodyTop,
      '--panel-body-bottom': panelColor,
      '--header-grad-a': fabColorA,
      '--header-grad-b': fabColorB,
      '--header-text': headerText,
      '--mini-btn-bg': miniBtnBg,
      '--mini-btn-text': miniBtnText,
      '--mini-btn-active-bg': miniBtnActiveBg,
      '--mini-btn-active-text': miniBtnActiveText,
      '--section-bg': sectionBg,
      '--section-border': sectionBorder,
      '--accent': accent,
      '--row-text': panelText,
      '--input-bg': inputBg,
      '--input-border': inputBorder,
      '--input-text': panelText,
      '--help-text': panelText,
      '--code-bg': codeBg,
      '--code-border': codeBorder,
      '--focus-ring': focusRing,
    };

    for (const [key, value] of Object.entries(vars)) {
      ui.widget.style.setProperty(key, value);
    }
  }

  function clearUiExpandModeRetryTimer() {
    if (state.uiExpandModeRetryTimer !== null) {
      clearTimeout(state.uiExpandModeRetryTimer);
      state.uiExpandModeRetryTimer = null;
    }
  }

  function scheduleUiExpandModeRetry() {
    if (state.uiExpandModeRetryTimer !== null) {
      return;
    }
    state.uiExpandModeRetryTimer = setTimeout(() => {
      state.uiExpandModeRetryTimer = null;
      syncExpandModeTriggerUI();
    }, 1000);
  }

  function refreshExtensionsMenuButtonVisibility() {
    const menu = hostDocument.getElementById('extensionsMenu');
    const menuButton = hostDocument.getElementById('extensionsMenuButton');
    if (!menu || !menuButton) {
      return;
    }
    const hasVisibleItems = Array.from(menu.children).some(child => {
      if (!child || child.nodeType !== 1) {
        return false;
      }
      try {
        return root.getComputedStyle(child).display !== 'none';
      } catch (_error) {
        return child.style.display !== 'none';
      }
    });
    menuButton.style.display = hasVisibleItems ? 'flex' : 'none';
  }

  function ensureExtensionsMenuEntry() {
    const menu = hostDocument.getElementById('extensionsMenu');
    if (!menu) {
      return null;
    }

    let container = hostDocument.getElementById(EXT_MENU_CONTAINER_ID);
    if (!container) {
      container = hostDocument.createElement('div');
      container.id = EXT_MENU_CONTAINER_ID;
      container.className = 'extension_container';
      menu.appendChild(container);
    } else if (!menu.contains(container)) {
      menu.appendChild(container);
    }

    let trigger = container.querySelector(`[data-action="${EXT_MENU_OPEN_ACTION}"]`);
    if (!trigger) {
      trigger = hostDocument.createElement('div');
      trigger.className = 'list-group-item flex-container flexGap5 interactable';
      trigger.setAttribute('tabindex', '0');
      trigger.setAttribute('role', 'listitem');
      trigger.setAttribute('data-action', EXT_MENU_OPEN_ACTION);
      trigger.setAttribute('title', `打开${PLUGIN_NAME}`);
      trigger.innerHTML = `
        <div class="fa-fw fa-solid fa-wine-glass extensionsMenuExtensionButton" aria-hidden="true"></div>
        <span>${PLUGIN_NAME}</span>
      `;
      container.appendChild(trigger);
    }

    if (trigger.dataset.bound !== '1') {
      trigger.dataset.bound = '1';
      trigger.onclick = () => {
        updateSettings({ panelOpen: true, uiPage: 'settings' });
      };
      trigger.onkeydown = event => {
        if (event.key !== 'Enter' && event.key !== ' ' && event.key !== 'Spacebar') {
          return;
        }
        event.preventDefault();
        updateSettings({ panelOpen: true, uiPage: 'settings' });
      };
    }

    return container;
  }

  function setExtensionsMenuEntryVisible(visible) {
    if (!visible) {
      removeExtensionsMenuEntry();
      return true;
    }

    const container = ensureExtensionsMenuEntry();
    if (!container) {
      refreshExtensionsMenuButtonVisibility();
      return false;
    }
    container.style.display = '';
    refreshExtensionsMenuButtonVisibility();
    return true;
  }

  function removeExtensionsMenuEntry() {
    const container = hostDocument.getElementById(EXT_MENU_CONTAINER_ID);
    if (container) {
      container.remove();
    }
    refreshExtensionsMenuButtonVisibility();
  }

  function syncExpandModeTriggerUI() {
    if (!ui.widget || !ui.fab) {
      return;
    }

    const mode = normalizeUiExpandMode(settings.uiExpandMode, DEFAULT_SETTINGS.uiExpandMode);
    const useExtensionsMenu = mode === UI_EXPAND_MODES.EXTENSIONS_MENU;
    const setFabVisible = visible => {
      ui.fab.hidden = !visible;
      ui.fab.disabled = !visible;
      ui.fab.tabIndex = visible ? 0 : -1;
      ui.fab.style.display = visible ? '' : 'none';
    };

    ui.widget.dataset.expandMode = mode;
    if (!useExtensionsMenu) {
      clearUiExpandModeRetryTimer();
      setExtensionsMenuEntryVisible(false);
      setFabVisible(true);
      return;
    }

    const menuReady = setExtensionsMenuEntryVisible(true);
    setFabVisible(false);
    if (menuReady) {
      clearUiExpandModeRetryTimer();
      return;
    }

    // SillyTavern 的拓展菜单可能稍后才挂载，持续重试以便注入按钮。
    scheduleUiExpandModeRetry();
  }

  // Runtime helpers around SillyTavern chat/message access.
  function getRuntimeFunction(name) {
    if (!name) {
      return null;
    }

    const fromRoot = root?.[name];
    if (typeof fromRoot === 'function') {
      return fromRoot.bind(root);
    }

    const fromGlobal = globalThis?.[name];
    if (typeof fromGlobal === 'function') {
      return fromGlobal.bind(globalThis);
    }
    return null;
  }

  function getRuntimeObject(name) {
    if (!name) {
      return null;
    }

    const fromRoot = root?.[name];
    if (fromRoot && typeof fromRoot === 'object') {
      return fromRoot;
    }

    const fromGlobal = globalThis?.[name];
    if (fromGlobal && typeof fromGlobal === 'object') {
      return fromGlobal;
    }
    return null;
  }

  function getAssistantMessage(messageId) {
    const getChatMessagesFn = getRuntimeFunction('getChatMessages');
    if (!getChatMessagesFn) {
      return null;
    }

    const message = getChatMessagesFn(messageId, { include_swipes: false })?.[0];
    if (!message || message.role !== 'assistant') {
      return null;
    }
    return message;
  }

  function effectiveLength(text) {
    return String(text ?? '').replace(/\s+/g, '').length;
  }

  function isAssistantPlaceholderText(text) {
    const normalized = String(text ?? '').replace(/\s+/g, '').trim();
    return normalized === '' || normalized === '...' || normalized === '…';
  }

  function canShortRetryLength(length) {
    const safeLength = Number.isFinite(Number(length)) ? Number(length) : 0;
    return settings.featureAutoRetry
      && settings.maxRetriesPerMessage > 0
      && safeLength < settings.minChars;
  }

  function shouldCountAssistantForErrorRetry(message, precomputedLength = null) {
    if (!message || message.role !== 'assistant') {
      return false;
    }

    const text = String(message.message ?? '');
    const length = Number.isFinite(Number(precomputedLength))
      ? Number(precomputedLength)
      : effectiveLength(text);

    if (!isAssistantPlaceholderText(text)) {
      return true;
    }

    // Placeholder output should only suppress error-retry when short-retry can take over.
    return canShortRetryLength(length);
  }

  function shouldHandleType(type) {
    const allowedTypes = new Set([
      'normal',
      'regenerate',
      'swipe',
      'continue',
      'append',
      'appendFinal',
      'first_message',
    ]);
    return allowedTypes.has(String(type ?? ''));
  }

  function shouldTrackGenerationType(type) {
    return shouldHandleType(type);
  }

  function getLastMessageIdSafe() {
    const getLastMessageIdFn = getRuntimeFunction('getLastMessageId');
    if (getLastMessageIdFn) {
      const id = Number(getLastMessageIdFn());
      if (Number.isFinite(id)) {
        return id;
      }
    }

    const doc = hostDocument;
    const nodes = doc.querySelectorAll('.mes[mesid]');
    let maxId = -1;
    nodes.forEach(node => {
      const id = Number(node.getAttribute('mesid'));
      if (Number.isFinite(id) && id > maxId) {
        maxId = id;
      }
    });
    return maxId;
  }

  function hasAssistantMessageInRange(startExclusiveId, endInclusiveId) {
    if (!Number.isFinite(endInclusiveId) || endInclusiveId < 0) {
      return false;
    }
    const from = Math.max(0, Number(startExclusiveId) + 1);
    for (let id = from; id <= endInclusiveId; id += 1) {
      const message = getAssistantMessage(id);
      if (shouldCountAssistantForErrorRetry(message)) {
        return true;
      }
    }
    return false;
  }

  function getGenerationEndSettleDelayMs() {
    const baseDelay = normalizeSettingInt(
      settings.renderSettleDelayMs,
      0,
      5000,
      DEFAULT_SETTINGS.renderSettleDelayMs,
      settings.featureProfessionalUser
    );
    return Math.max(80, Math.min(6000, baseDelay + 40));
  }

  function hasAssistantEvidenceAfterGeneration(snapshot, endLastMessageId) {
    if (snapshot.sawAssistantMessage) {
      return true;
    }
    if (hasAssistantMessageInRange(snapshot.startLastMessageId, endLastMessageId)) {
      return true;
    }

    const marker = state.lastAssistantRender;
    if (!marker.countsForErrorRetry) {
      return false;
    }
    if (!Number.isFinite(marker.at) || marker.at < snapshot.endedAt) {
      return false;
    }

    const startId = Number(snapshot.startLastMessageId);
    const minId = Number.isFinite(startId) ? Math.max(0, startId) : 0;
    const renderedId = Number(marker.messageId);
    return Number.isFinite(renderedId) && renderedId >= minId;
  }

  function resolveErrorRetryMessageId(startLastMessageId, endLastMessageId) {
    const startId = Number(startLastMessageId);
    const endId = Number(endLastMessageId);
    const safeStart = Number.isFinite(startId) ? startId : -1;
    const safeEnd = Number.isFinite(endId) ? endId : -1;
    const nextId = Math.max(safeStart, safeEnd) + 1;
    return Number.isFinite(nextId) && nextId >= 0 ? nextId : null;
  }

  function getMessageElement(messageId) {
    return hostDocument.querySelector(`.mes[mesid="${messageId}"]`);
  }

  function findScrollContainer() {
    const selectors = ['.simplebar-content-wrapper', '#chat', '#chat_messages', '.chat'];
    for (const selector of selectors) {
      const el = hostDocument.querySelector(selector);
      if (el) return el;
    }
    return null;
  }

  function scrollMessageToTop(messageId, triesLeft = settings.scrollRetryTimes) {
    const element = getMessageElement(messageId);
    if (element) {
      element.scrollIntoView({ behavior: settings.scrollBehavior, block: 'start' });
      return;
    }

    if (triesLeft > 0) {
      setTimeout(() => scrollMessageToTop(messageId, triesLeft - 1), settings.scrollRetryIntervalMs);
    }
  }

  function jumpToBottomOnce() {
    const container = findScrollContainer();
    let jumped = false;

    const lastId = getLastMessageIdSafe();

    if (Number.isFinite(lastId) && lastId >= 0) {
      const message = getMessageElement(lastId);
      if (message) {
        message.scrollIntoView({ behavior: settings.scrollBehavior, block: 'end' });
        jumped = true;
      }
    }

    if (container) {
      container.scrollTop = container.scrollHeight;
      jumped = true;
    }

    return jumped;
  }

  function jumpToBottomWithRetry(triesLeft = settings.chatOpenJumpRetryTimes) {
    const ok = jumpToBottomOnce();
    if (ok) return;
    if (triesLeft > 0) {
      setTimeout(
        () => jumpToBottomWithRetry(triesLeft - 1),
        settings.chatOpenJumpRetryIntervalMs
      );
    }
  }

  function scheduleChatBottomJump() {
    if (!settings.featureJumpBottomOnChatOpen) return;
    clearJumpTimer();
    state.chatJumpTimer = setTimeout(() => {
      log('对话打开后自动跳到底部');
      jumpToBottomWithRetry(settings.chatOpenJumpRetryTimes);
    }, settings.chatOpenJumpDelayMs);
  }

  // Timer helpers ensure we do not keep stale scheduled tasks.
  function clearRetryTimer() {
    if (state.retryTimer !== null) {
      clearTimeout(state.retryTimer);
      state.retryTimer = null;
    }
  }

  function clearErrorRetryTimer() {
    if (state.errorRetryTimer !== null) {
      clearTimeout(state.errorRetryTimer);
      state.errorRetryTimer = null;
    }
  }

  function clearJumpTimer() {
    if (state.chatJumpTimer !== null) {
      clearTimeout(state.chatJumpTimer);
      state.chatJumpTimer = null;
    }
  }

  function clearWakeLockRetryTimer() {
    if (state.wakeLock.retryTimer !== null) {
      clearTimeout(state.wakeLock.retryTimer);
      state.wakeLock.retryTimer = null;
    }
  }

  function scheduleWakeLockRetry(delayMs = 15000) {
    if (!settings.featureKeepScreenAwake || state.wakeLock.disposed) {
      return;
    }
    clearWakeLockRetryTimer();
    const safeDelay = clampInt(delayMs, 1000, 600000, 15000);
    state.wakeLock.retryTimer = setTimeout(() => {
      void requestScreenWakeLock('重试申请');
    }, safeDelay);
  }

  async function releaseScreenWakeLock(reason = '') {
    clearWakeLockRetryTimer();
    const sentinel = state.wakeLock.sentinel;
    state.wakeLock.sentinel = null;

    if (!sentinel || typeof sentinel.release !== 'function') {
      return;
    }

    try {
      if (!sentinel.released) {
        await sentinel.release();
        log(`防熄屏已释放${reason ? `：${reason}` : ''}`);
      }
    } catch (error) {
      logWarn('释放防熄屏锁失败', error);
    }
  }

  function handleWakeLockReleased() {
    state.wakeLock.sentinel = null;
    if (state.wakeLock.disposed) {
      return;
    }
    if (settings.featureKeepScreenAwake && hostDocument.visibilityState === 'visible') {
      scheduleWakeLockRetry(1200);
    }
  }

  async function requestScreenWakeLock(reason = '') {
    if (state.wakeLock.disposed) {
      state.wakeLock.lastErrorName = 'Disposed';
      state.wakeLock.lastErrorMessage = '脚本已停止';
      return false;
    }
    if (!settings.featureKeepScreenAwake) {
      state.wakeLock.lastErrorName = 'Disabled';
      state.wakeLock.lastErrorMessage = '功能未开启';
      return false;
    }
    if (hostDocument.visibilityState !== 'visible') {
      state.wakeLock.lastErrorName = 'NotVisible';
      state.wakeLock.lastErrorMessage = '页面不可见';
      return false;
    }
    if (state.wakeLock.sentinel && !state.wakeLock.sentinel.released) {
      state.wakeLock.lastErrorName = '';
      state.wakeLock.lastErrorMessage = '';
      return true;
    }
    if (state.wakeLock.requesting) {
      state.wakeLock.lastErrorName = 'Pending';
      state.wakeLock.lastErrorMessage = '请求进行中';
      return false;
    }

    const wakeLockApi = root?.navigator?.wakeLock;
    if (!wakeLockApi || typeof wakeLockApi.request !== 'function') {
      state.wakeLock.lastErrorName = 'Unsupported';
      state.wakeLock.lastErrorMessage = '浏览器不支持 Wake Lock API';
      if (!state.wakeLock.unsupportedNotified) {
        logWarn('当前环境不支持防熄屏（Wake Lock API），该功能不可用');
        state.wakeLock.unsupportedNotified = true;
      }
      return false;
    }

    state.wakeLock.requesting = true;
    clearWakeLockRetryTimer();

    try {
      const sentinel = await wakeLockApi.request('screen');
      state.wakeLock.sentinel = sentinel;
      state.wakeLock.lastErrorName = '';
      state.wakeLock.lastErrorMessage = '';

      if (typeof sentinel.addEventListener === 'function') {
        sentinel.addEventListener('release', handleWakeLockReleased);
      } else {
        sentinel.onrelease = handleWakeLockReleased;
      }

      log(`防熄屏已启用${reason ? `：${reason}` : ''}`);
      return true;
    } catch (error) {
      state.wakeLock.lastErrorName = String(error?.name || 'UnknownError');
      state.wakeLock.lastErrorMessage = String(error?.message || '').trim();
      if (error?.name === 'NotAllowedError' || error?.name === 'AbortError') {
        log(`防熄屏暂不可用，等待重试（${error?.name || '未知错误'}）`);
      } else {
        logWarn('启用防熄屏失败，稍后重试', error);
      }
      scheduleWakeLockRetry(15000);
      return false;
    } finally {
      state.wakeLock.requesting = false;
    }
  }

  function refreshScreenWakeLock(reason = '') {
    if (settings.featureKeepScreenAwake) {
      void requestScreenWakeLock(reason);
    } else {
      void releaseScreenWakeLock(reason);
    }
  }

  function isLikelyMobileDevice() {
    const nav = root?.navigator;
    if (!nav) {
      return false;
    }

    if (typeof nav.userAgentData?.mobile === 'boolean') {
      return nav.userAgentData.mobile;
    }

    const ua = String(nav.userAgent || '');
    if (/Android|webOS|iPhone|iPad|iPod|IEMobile|Opera Mini/i.test(ua)) {
      return true;
    }

    const maxTouchPoints = Number(nav.maxTouchPoints || 0);
    const coarsePointer = typeof root.matchMedia === 'function'
      && root.matchMedia('(pointer: coarse)').matches;
    return maxTouchPoints > 1 && coarsePointer;
  }

  function requestVibration(duration, contextLabel) {
    const nav = root?.navigator;
    const vibrate = nav?.vibrate;
    if (typeof vibrate !== 'function') {
      log(`当前环境不支持震动 API，已跳过${contextLabel}`);
      return false;
    }

    const safeDuration = normalizeSettingInt(
      duration,
      20,
      1000,
      DEFAULT_SETTINGS.vibrationDurationMs,
      settings.featureProfessionalUser
    );
    try {
      const accepted = !!vibrate.call(nav, safeDuration);
      if (accepted) {
        return true;
      }

      // Some mobile kernels reject a single duration but accept a vibration pattern.
      const fallbackAccepted = !!vibrate.call(nav, [safeDuration, 40, safeDuration]);
      if (!fallbackAccepted) {
        log(`${contextLabel}请求未被接受`);
      }
      return fallbackAccepted;
    } catch (error) {
      logWarn(`触发${contextLabel}失败`, error);
      return false;
    }
  }

  function triggerMobileVibration(messageId, reason = 'message_ready') {
    if (!settings.featureMobileVibration) {
      return;
    }
    if (!isLikelyMobileDevice()) {
      return;
    }

    const numericMessageId = Number(messageId);
    if (Number.isFinite(numericMessageId) && numericMessageId === 0) {
      return;
    }

    const safeMessageId = Number.isFinite(Number(messageId)) ? Number(messageId) : String(messageId);
    const safeReason = String(reason || 'message_ready');
    const generationSerial = Number.isFinite(Number(state.generation.serial))
      ? Number(state.generation.serial)
      : 0;
    const vibrationKey = `${generationSerial}|${safeMessageId}|${safeReason}`;
    if (state.lastVibrationKey === vibrationKey) {
      return;
    }
    state.lastVibrationKey = vibrationKey;

    requestVibration(settings.vibrationDurationMs, '手机震动提醒');
  }

  function resetState() {
    clearRetryTimer();
    clearErrorRetryTimer();
    clearJumpTimer();
    state.currentMessageId = -1;
    state.retriesForCurrentMessage = 0;
    state.errorRetriesInRow = 0;
    state.retrying = false;
    state.generation.active = false;
    state.generation.type = '';
    state.generation.serial = 0;
    state.generation.lastStoppedSerial = 0;
    state.generation.startLastMessageId = -1;
    state.generation.sawAssistantMessage = false;
    state.generation.stoppedByUser = false;
    state.generation.manualStopRequested = false;
    state.lastAssistantRender.messageId = -1;
    state.lastAssistantRender.at = 0;
    state.lastAssistantRender.countsForErrorRetry = false;
    state.lastVibrationKey = '';
  }

  function markManualStopRequested(reason = '') {
    const serialAtStop = Number.isFinite(Number(state.generation.serial))
      ? Number(state.generation.serial)
      : 0;
    state.generation.manualStopRequested = true;
    state.generation.stoppedByUser = true;
    state.generation.lastStoppedSerial = serialAtStop;

    if (state.retryTimer !== null) {
      clearRetryTimer();
      log('手动停止优先生效，已取消待执行的过短重试');
    }
    if (state.errorRetryTimer !== null) {
      clearErrorRetryTimer();
      log('手动停止优先生效，已取消待执行的请求出错重试');
    }

    if (reason && settings.debug) {
      log(`已记录手动停止信号：${reason}`);
    }
  }

  function isGeneratingNow() {
    const builtinApi = getRuntimeObject('builtin');
    if (builtinApi && typeof builtinApi.duringGenerating === 'function') {
      try {
        return !!builtinApi.duringGenerating();
      } catch (error) {
        logWarn('读取生成状态失败，将尝试后备判断', error);
      }
    }

    const bodyGenerating = String(hostDocument?.body?.dataset?.generating || '') === 'true';
    return bodyGenerating || !!state.generation.active;
  }

  async function waitUntilNotGenerating(timeoutMs, pollMs) {
    const safeTimeout = normalizeSettingInt(
      timeoutMs,
      1000,
      120000,
      DEFAULT_SETTINGS.shortWaitIdleTimeoutMs,
      settings.featureProfessionalUser
    );
    const safePoll = normalizeSettingInt(
      pollMs,
      50,
      5000,
      DEFAULT_SETTINGS.shortWaitIdlePollMs,
      settings.featureProfessionalUser
    );
    const startedAt = Date.now();
    while (isGeneratingNow() && Date.now() - startedAt < safeTimeout) {
      await new Promise(resolve => setTimeout(resolve, safePoll));
    }
    return !isGeneratingNow();
  }

  async function triggerRegenerate() {
    const sillyTavernApi = getRuntimeObject('SillyTavern');
    if (typeof sillyTavernApi?.generate === 'function') {
      await sillyTavernApi.generate('regenerate');
      return true;
    }

    const regenButton = hostDocument.getElementById('option_regenerate');
    if (regenButton) {
      regenButton.click();
      return true;
    }

    const triggerSlashFn = getRuntimeFunction('triggerSlash');
    if (triggerSlashFn) {
      await triggerSlashFn('/trigger await=true');
      return true;
    }

    return false;
  }

  function ensureToastRoot() {
    if (!hostDocument.body) {
      logWarn('提示弹窗容器创建失败：文档 body 未就绪');
      return null;
    }

    let rootEl = hostDocument.getElementById(TOAST_ID);
    if (!rootEl) {
      rootEl = hostDocument.createElement('div');
      rootEl.id = TOAST_ID;
      hostDocument.body.appendChild(rootEl);
    }
    return rootEl;
  }

  function showToast({
    icon = 'ℹ',
    title = `${PLUGIN_NAME}：提示`,
    subtitle = '',
    tone = 'blue',
    durationMs = 3600,
  }) {
    const safeTitle = String(title || `${PLUGIN_NAME}：提示`);
    const safeSubtitle = String(subtitle || '');
    const safeTone = tone === 'red' ? 'red' : 'blue';
    const safeDuration = clampInt(durationMs, 1200, 10000, 3600);

    const rootEl = ensureToastRoot();
    if (!rootEl) {
      return;
    }
    const toast = hostDocument.createElement('div');
    toast.className = `th-asr-toast th-asr-toast--${safeTone}`;

    const iconEl = hostDocument.createElement('div');
    iconEl.className = 'th-asr-toast-icon';
    iconEl.textContent = String(icon || 'ℹ');

    const mainEl = hostDocument.createElement('div');
    mainEl.className = 'th-asr-toast-main';

    const titleEl = hostDocument.createElement('div');
    titleEl.className = 'th-asr-toast-title';
    titleEl.textContent = safeTitle;

    const subEl = hostDocument.createElement('div');
    subEl.className = 'th-asr-toast-sub';
    subEl.textContent = safeSubtitle;

    mainEl.appendChild(titleEl);
    mainEl.appendChild(subEl);
    toast.appendChild(iconEl);
    toast.appendChild(mainEl);

    rootEl.appendChild(toast);
    requestAnimationFrame(() => toast.classList.add('show'));

    setTimeout(() => {
      toast.classList.remove('show');
      setTimeout(() => {
        if (toast.parentNode) {
          toast.parentNode.removeChild(toast);
        }
      }, 220);
    }, safeDuration);
  }

  function showRetryPopup({ title, messageId, length, attempt, maxAttempts, enabled = true }) {
    if (!enabled) {
      return;
    }

    const messageLabel = messageId === null || messageId === undefined ? '-' : String(messageId);
    const lengthLabel = Number.isFinite(Number(length)) ? String(length) : '-';
    showToast({
      icon: '↻',
      title: String(title || `${PLUGIN_NAME}：已触发自动重试`),
      subtitle: `楼层 #${messageLabel}，长度 ${lengthLabel}，第 ${attempt}/${maxAttempts} 次`,
      tone: 'blue',
      durationMs: 3600,
    });
  }

  function showWakeLockEnablePopup(success, reason = '') {
    const detail = String(reason || '').trim();
    const subtitle = success
      ? '防熄屏已开启，等待回复时会尽量保持屏幕常亮'
      : `防熄屏开启失败${detail ? `：${detail}` : '（请检查浏览器权限或系统策略）'}`;
    showToast({
      icon: success ? '✓' : '!',
      title: `${PLUGIN_NAME}：手机防熄屏${success ? '开启成功' : '开启失败'}`,
      subtitle,
      tone: success ? 'blue' : 'red',
      durationMs: 4200,
    });
  }

  function pulseFab() {
    if (!ui.fab) {
      return;
    }
    ui.fab.classList.remove('pulse');
    void ui.fab.offsetWidth;
    ui.fab.classList.add('pulse');
  }

  function scheduleShortRetryCheck(messageId, delayMs, reason) {
    if (!settings.featureAutoRetry) {
      return;
    }
    if (isCurrentGenerationStoppedByUser()) {
      log('检测到手动停止生成，跳过过短重试计划');
      return;
    }

    const safeDelay = normalizeSettingInt(
      delayMs,
      0,
      60000,
      settings.retryDelayMs,
      settings.featureProfessionalUser
    );
    clearRetryTimer();
    if (reason) {
      log(`消息过短重试等待：消息ID=${messageId}，${reason}，${safeDelay}ms 后再次检查`);
    }
    state.retryTimer = setTimeout(() => {
      retryIfNeeded(messageId).catch(error => {
        logError('过短重试任务执行失败', error);
      });
    }, safeDelay);
  }

  function getShortRetryBusyDelay() {
    return settings.featureProfessionalUser
      ? settings.shortWaitIdlePollMs
      : Math.max(settings.shortWaitIdlePollMs, 120);
  }

  async function retryIfNeeded(messageId) {
    if (!settings.featureAutoRetry) {
      return;
    }
    if (isCurrentGenerationStoppedByUser()) {
      log('检测到手动停止生成，本轮忽略过短重试');
      return;
    }

    if (state.currentMessageId !== messageId) {
      return;
    }

    if (state.retrying) {
      scheduleShortRetryCheck(messageId, getShortRetryBusyDelay(), '上一轮重试尚未结束');
      return;
    }

    const message = getAssistantMessage(messageId);
    if (!message) {
      return;
    }

    const length = effectiveLength(message.message);
    if (length >= settings.minChars) {
      state.retriesForCurrentMessage = 0;
      triggerMobileVibration(messageId, 'message_ready');
      return;
    }

    if (isGeneratingNow()) {
      scheduleShortRetryCheck(messageId, getShortRetryBusyDelay(), '检测到仍在生成，延后复检');
      return;
    }

    const idle = await waitUntilNotGenerating(settings.shortWaitIdleTimeoutMs, settings.shortWaitIdlePollMs);
    if (!idle) {
      scheduleShortRetryCheck(messageId, getShortRetryBusyDelay(), '等待空闲超时，延后复检');
      return;
    }
    if (isCurrentGenerationStoppedByUser()) {
      log('检测到手动停止生成，取消本次过短重试触发');
      return;
    }
    if (state.currentMessageId !== messageId) {
      return;
    }

    const refreshedMessage = getAssistantMessage(messageId);
    if (!refreshedMessage) {
      return;
    }

    const refreshedLength = effectiveLength(refreshedMessage.message);
    if (refreshedLength >= settings.minChars) {
      state.retriesForCurrentMessage = 0;
      triggerMobileVibration(messageId, 'message_ready');
      return;
    }

    if (state.retriesForCurrentMessage >= settings.maxRetriesPerMessage) {
      log(`消息 ${messageId} 已达到过短重试上限`);
      triggerMobileVibration(messageId, 'short_retry_exhausted');
      return;
    }

    const now = Date.now();
    state.retrying = true;
    state.retriesForCurrentMessage += 1;
    state.lastRetryAt = now;

    const attempt = state.retriesForCurrentMessage;
    const maxAttempts = settings.maxRetriesPerMessage;

    log(`消息过短重试 ${attempt}/${maxAttempts}：消息ID=${messageId}，长度=${refreshedLength}`);
    showRetryPopup({
      title: `${PLUGIN_NAME}：消息过短，自动重试`,
      messageId,
      length: refreshedLength,
      attempt,
      maxAttempts,
      enabled: settings.showShortRetryPopup,
    });
    pulseFab();

    try {
      if (isGeneratingNow()) {
        scheduleShortRetryCheck(messageId, getShortRetryBusyDelay(), '触发前检测到仍在生成，延后复检');
        return;
      }

      const ok = await triggerRegenerate();
      if (!ok) {
        logWarn('未找到可用的重新生成方式');
      }
    } catch (error) {
      logError('过短自动重试失败', error);
    } finally {
      state.retrying = false;
    }
  }

  async function retryByErrorIfNeeded(messageIdHint = null, errorContext = null) {
    if (!settings.featureErrorRetry) {
      return;
    }
    if (isCurrentGenerationStoppedByUser()) {
      log('检测到手动停止生成，本轮忽略请求出错重试');
      return;
    }

    if (errorContext && hasAssistantEvidenceAfterGeneration(errorContext, getLastMessageIdSafe())) {
      if (state.errorRetriesInRow > 0) {
        log(`请求出错重试已取消：检测到助手消息，清空连续计数（${state.errorRetriesInRow} -> 0）`);
      } else {
        log('请求出错重试已取消：检测到助手消息');
      }
      state.errorRetriesInRow = 0;
      return;
    }

    if (state.retrying) {
      log('请求出错重试已跳过：已有其他重试正在执行');
      return;
    }

    if (state.errorRetriesInRow >= settings.maxErrorRetriesPerCycle) {
      logWarn(`请求出错重试已达到上限（${state.errorRetriesInRow}/${settings.maxErrorRetriesPerCycle}）`);
      return;
    }

    const now = Date.now();
    state.retrying = true;
    state.errorRetriesInRow += 1;
    state.lastRetryAt = now;

    const attempt = state.errorRetriesInRow;
    const maxAttempts = settings.maxErrorRetriesPerCycle;
    logWarn(`请求出错重试 ${attempt}/${maxAttempts}：生成结束但未收到助手消息`);
    showRetryPopup({
      title: `${PLUGIN_NAME}：请求出错，自动重试`,
      messageId: messageIdHint,
      length: '-',
      attempt,
      maxAttempts,
      enabled: settings.showErrorRetryPopup,
    });
    pulseFab();

    try {
      const idle = await waitUntilNotGenerating(settings.errorWaitIdleTimeoutMs, settings.errorWaitIdlePollMs);
      if (!idle) {
        logWarn('当前仍在生成，跳过本次请求出错重试');
        return;
      }
      if (isCurrentGenerationStoppedByUser()) {
        log('检测到手动停止生成，取消本次请求出错重试触发');
        return;
      }
      if (errorContext && hasAssistantEvidenceAfterGeneration(errorContext, getLastMessageIdSafe())) {
        if (state.errorRetriesInRow > 0) {
          log(`请求出错重试在触发前取消：检测到助手消息，清空连续计数（${state.errorRetriesInRow} -> 0）`);
        } else {
          log('请求出错重试在触发前取消：检测到助手消息');
        }
        state.errorRetriesInRow = 0;
        return;
      }

      const ok = await triggerRegenerate();
      if (!ok) {
        logWarn('请求出错重试未找到可用的重新生成方式');
      }
    } catch (error) {
      logError('请求出错重试失败', error);
    } finally {
      state.retrying = false;
    }
  }

  function scheduleErrorRetry(messageIdHint = null, errorContext = null) {
    const safeMessageIdHint = Number.isFinite(Number(messageIdHint)) ? Number(messageIdHint) : null;
    const safeErrorContext = errorContext && typeof errorContext === 'object'
      ? {
        serial: Number.isFinite(Number(errorContext.serial)) ? Number(errorContext.serial) : 0,
        type: String(errorContext.type ?? ''),
        startLastMessageId: Number.isFinite(Number(errorContext.startLastMessageId))
          ? Number(errorContext.startLastMessageId)
          : -1,
        endLastMessageId: Number.isFinite(Number(errorContext.endLastMessageId))
          ? Number(errorContext.endLastMessageId)
          : -1,
        sawAssistantMessage: !!errorContext.sawAssistantMessage,
        endedAt: Number.isFinite(Number(errorContext.endedAt))
          ? Number(errorContext.endedAt)
          : Date.now(),
      }
      : null;
    clearErrorRetryTimer();
    state.errorRetryTimer = setTimeout(() => {
      retryByErrorIfNeeded(safeMessageIdHint, safeErrorContext).catch(error => {
        logError('请求出错重试任务执行失败', error);
      });
    }, settings.errorRetryDelayMs);
  }

  function handleGenerationStarted(type, _params, dryRun) {
    if (dryRun) {
      return;
    }

    if (!shouldTrackGenerationType(type)) {
      log(`生成开始事件类型已忽略：${String(type)}`);
      state.generation.active = false;
      return;
    }

    if (state.retryTimer !== null) {
      clearRetryTimer();
      log('检测到生成开始，已清理遗留的过短重试任务');
    }
    if (state.errorRetryTimer !== null) {
      clearErrorRetryTimer();
      log('检测到生成开始，已清理遗留的请求出错重试任务');
    }
    state.retrying = false;
    state.generation.manualStopRequested = false;

    state.generation.serial += 1;
    if (!Number.isFinite(state.generation.serial) || state.generation.serial > 1000000000) {
      state.generation.serial = 1;
    }
    state.generation.active = true;
    state.generation.type = String(type ?? '');
    state.generation.startLastMessageId = getLastMessageIdSafe();
    state.generation.sawAssistantMessage = false;
    state.generation.stoppedByUser = false;
    log(`生成开始：类型=${state.generation.type}，起始末条消息ID=${state.generation.startLastMessageId}`);
  }

  function handleGenerationStopped() {
    markManualStopRequested('generation_stopped 事件');

    if (state.generation.active) {
      logWarn('收到生成停止事件（generation_stopped），当前轮次跳过请求出错重试');
      return;
    }

    log('收到生成停止事件（generation_stopped），无活动生成，已记为手动停止');
  }

  function handleGenerationEnded() {
    if (!state.generation.active) {
      return;
    }

    const snapshot = {
      serial: Number.isFinite(Number(state.generation.serial)) ? Number(state.generation.serial) : 0,
      type: state.generation.type,
      startLastMessageId: state.generation.startLastMessageId,
      sawAssistantMessage: state.generation.sawAssistantMessage,
      stoppedByUser: state.generation.stoppedByUser,
      endedAt: Date.now(),
    };

    state.generation.active = false;
    state.generation.type = '';

    if (snapshot.stoppedByUser) {
      log('检测到手动停止生成，本轮忽略请求出错重试');
      return;
    }
    if (snapshot.serial > 0 && snapshot.serial === state.generation.lastStoppedSerial) {
      log('检测到手动停止生成（轮次匹配），本轮忽略请求出错重试');
      return;
    }

    const settleDelayMs = getGenerationEndSettleDelayMs();
    setTimeout(() => {
      if (snapshot.serial <= 0 || snapshot.serial !== state.generation.serial) {
        return;
      }
      if (snapshot.serial === state.generation.lastStoppedSerial || isCurrentGenerationStoppedByUser()) {
        log('检测到手动停止生成（结算阶段），本轮忽略请求出错重试');
        return;
      }

      const endLastMessageId = getLastMessageIdSafe();
      const gotAssistant = hasAssistantEvidenceAfterGeneration(snapshot, endLastMessageId);

      if (gotAssistant) {
        if (state.errorRetriesInRow > 0) {
          log(`已收到助手消息，清空请求出错连续重试计数（${state.errorRetriesInRow} -> 0）`);
        }
        state.errorRetriesInRow = 0;
        return;
      }

      logWarn(
        `生成结束但未收到助手消息：类型=${snapshot.type}，起始末条消息ID=${snapshot.startLastMessageId}，结束末条消息ID=${endLastMessageId}`
      );
      if (!settings.featureErrorRetry) {
        return;
      }
      scheduleErrorRetry(
        resolveErrorRetryMessageId(snapshot.startLastMessageId, endLastMessageId),
        {
          serial: snapshot.serial,
          type: snapshot.type,
          startLastMessageId: snapshot.startLastMessageId,
          endLastMessageId,
          sawAssistantMessage: false,
          endedAt: snapshot.endedAt,
        }
      );
    }, settleDelayMs);
  }

  function isCurrentGenerationStoppedByUser() {
    if (state.generation.manualStopRequested) {
      return true;
    }
    const serial = Number(state.generation.serial);
    if (!Number.isFinite(serial) || serial <= 0) {
      return false;
    }
    if (state.generation.stoppedByUser) {
      return true;
    }
    return state.generation.lastStoppedSerial === serial;
  }

  function handleCharacterMessageRendered(messageId, type) {
    if (!shouldHandleType(type)) {
      return;
    }

    setTimeout(() => {
      const message = getAssistantMessage(messageId);
      if (!message) {
        return;
      }

      const length = effectiveLength(message.message);
      const countsAsAssistantMessage = shouldCountAssistantForErrorRetry(message, length);

      state.lastAssistantRender.messageId = Number.isFinite(Number(messageId)) ? Number(messageId) : -1;
      state.lastAssistantRender.at = Date.now();
      state.lastAssistantRender.countsForErrorRetry = countsAsAssistantMessage;

      state.generation.sawAssistantMessage = state.generation.sawAssistantMessage || countsAsAssistantMessage;
      if (countsAsAssistantMessage) {
        if (state.errorRetryTimer !== null) {
          clearErrorRetryTimer();
          log('检测到助手消息已渲染，已取消待执行的请求出错重试');
        }
        state.errorRetriesInRow = 0;
      } else {
        logWarn(`助手消息为占位文本，保留请求出错重试资格：消息ID=${messageId}，类型=${String(type)}`);
      }
      log(`助手消息已渲染：消息ID=${messageId}，类型=${String(type)}`);

      if (settings.featureAutoScroll) {
        scrollMessageToTop(messageId);
      }

      if (!settings.featureAutoRetry) {
        if (countsAsAssistantMessage) {
          triggerMobileVibration(messageId, 'message_ready');
        }
        return;
      }

      if (state.currentMessageId !== messageId) {
        state.currentMessageId = messageId;
        state.retriesForCurrentMessage = 0;
      }

      log(`助手消息有效长度：消息ID=${messageId}，长度=${length}，阈值=${settings.minChars}`);
      if (canShortRetryLength(length)) {
        scheduleShortRetryCheck(messageId, settings.retryDelayMs, '收到过短消息');
      } else {
        state.retriesForCurrentMessage = 0;
        if (countsAsAssistantMessage) {
          triggerMobileVibration(messageId, 'message_ready');
        }
      }
    }, settings.renderSettleDelayMs);
  }

  function handleChatChanged() {
    log('对话已切换，重置运行状态');
    resetState();
    scheduleChatBottomJump();
  }

