  // Build draggable floating widget with settings/help pages.
  function buildWidget() {
    if (!hostDocument.body) {
      logError('悬浮窗构建失败：文档 body 未就绪');
      return false;
    }

    const oldWidget = hostDocument.getElementById(WIDGET_ID);
    if (oldWidget) {
      oldWidget.remove();
    }

    const widget = hostDocument.createElement('div');
    widget.id = WIDGET_ID;
    widget.innerHTML = `
      <button class="th-asr-fab" title="${PLUGIN_NAME}">🍷</button>
      <div class="th-asr-panel" hidden>
        <div class="th-asr-header">
          <div class="th-asr-title-wrap">
            <div class="th-asr-title">${PLUGIN_NAME}</div>
            <div class="th-asr-subtitle">滚动、重试、防熄屏与外观设置</div>
          </div>
          <div class="th-asr-actions">
            <button class="th-asr-mini-btn" data-action="tab-settings">设置</button>
            <button class="th-asr-mini-btn" data-action="tab-help">帮助</button>
            <button class="th-asr-mini-btn" data-action="tab-about">关于</button>
            <button class="th-asr-mini-btn" data-action="reset">重置</button>
            <button class="th-asr-mini-btn" data-action="collapse">收起</button>
          </div>
        </div>
        <div class="th-asr-body">
          <div class="th-asr-page" data-page="settings">
            <div class="th-asr-section">
              <div class="th-asr-section-title">自动滚动到新消息开头</div>
              <div class="th-asr-section-desc">收到新的助手消息后，把该消息滚动到视口顶部，便于直接查看。</div>
              <label class="th-asr-row"><span>启用此功能</span><input type="checkbox" data-key="featureAutoScroll"></label>
              <label class="th-asr-row"><span>滚动动画</span>
                <select data-key="scrollBehavior">
                  <option value="smooth">smooth</option>
                  <option value="auto">auto</option>
                </select>
              </label>
              <label class="th-asr-row"><span>渲染后等待 (ms)</span><input type="number" data-key="renderSettleDelayMs" min="0" max="5000" step="10"></label>
              <label class="th-asr-row"><span>滚动重试次数</span><input type="number" data-key="scrollRetryTimes" min="0" max="80" step="1"></label>
              <label class="th-asr-row"><span>滚动重试间隔 (ms)</span><input type="number" data-key="scrollRetryIntervalMs" min="20" max="3000" step="10"></label>
            </div>

            <div class="th-asr-section">
              <div class="th-asr-section-title">打开对话自动跳到底部</div>
