    `;

    hostDocument.body.appendChild(widget);

    ui.widget = widget;
    ui.fab = widget.querySelector('.th-asr-fab');
    ui.panel = widget.querySelector('.th-asr-panel');
    ui.headerDrag = widget.querySelector('.th-asr-header');
    ui.pageSettings = widget.querySelector('[data-page="settings"]');
    ui.pageHelp = widget.querySelector('[data-page="help"]');
    ui.pageAbout = widget.querySelector('[data-page="about"]');
    ui.tabSettings = widget.querySelector('[data-action="tab-settings"]');
    ui.tabHelp = widget.querySelector('[data-action="tab-help"]');
    ui.tabAbout = widget.querySelector('[data-action="tab-about"]');
    ui.logInterceptPanelToggle = widget.querySelector('[data-action="toggle-log-sources"]');
    ui.logInterceptPanelBody = widget.querySelector('[data-role="log-source-panel"]');
    ui.logInterceptSourceList = widget.querySelector('[data-role="log-source-list"]');
    ui.logInterceptSourceEmpty = widget.querySelector('[data-role="log-source-empty"]');
    ui.logInterceptSeenCount = widget.querySelector('[data-role="log-seen-count"]');
    ui.logInterceptBlockedCount = widget.querySelector('[data-role="log-blocked-count"]');
    ui.iframeLoadRatio = widget.querySelector('[data-role="iframe-load-ratio"]');
    ui.changelogPanelToggle = widget.querySelector('[data-action="toggle-changelog"]');
    ui.changelogPanelBody = widget.querySelector('[data-role="changelog-panel"]');

    for (const key of Object.keys(DEFAULT_SETTINGS)) {
      const input = widget.querySelector(`[data-key="${key}"]`);
      if (input) {
        ui.inputs[key] = input;
      }
    }

    const resetBtn = widget.querySelector('[data-action="reset"]');
    const collapseBtn = widget.querySelector('[data-action="collapse"]');
    let suppressOutsideCloseUntil = 0;

    onDOM(ui.fab, 'click', () => {
      if (ui.widget?.dataset?.dragging === '1') {
        return;
      }
      if (settings.panelOpen) {
        updateSettings({ panelOpen: false });
      } else {
        updateSettings({ panelOpen: true, uiPage: 'settings' });
      }
    });

    onDOM(ui.tabSettings, 'click', () => {
      updateSettings({ uiPage: 'settings' });
    });

    onDOM(ui.tabHelp, 'click', () => {
      updateSettings({ uiPage: 'help' });
    });

    onDOM(ui.tabAbout, 'click', () => {
      updateSettings({ uiPage: 'about' });
    });

    onDOM(ui.logInterceptPanelToggle, 'click', () => {
      updateSettings({ logInterceptPanelOpen: !settings.logInterceptPanelOpen });
      setTimeout(() => {
        refreshLogInterceptionState('来源列表折叠切换');
      }, 0);
    });

    syncChangelogPanelUI(false);
    onDOM(ui.changelogPanelToggle, 'click', () => {
      const nextOpen = !(ui.changelogPanelToggle && ui.changelogPanelToggle.dataset.open === '1');
      syncChangelogPanelUI(nextOpen);
    });

    onDOM(widget, 'change', event => {
      const target = event.target;
      if (
        !target
        || String(target.tagName || '').toUpperCase() !== 'INPUT'
        || String(target.type || '').toLowerCase() !== 'checkbox'
      ) {
        return;
      }

      const sourceId = String(target.dataset?.logSource || '').trim();
      if (!sourceId) {
        return;
      }

      if (settings.logInterceptSelectAll) {
        return;
      }

      const nextRules = Object.assign({}, settings.logInterceptRules || {});
      if (target.checked) {
        nextRules[sourceId] = true;
      } else {
        delete nextRules[sourceId];
      }
      updateSettings({ logInterceptRules: nextRules });
      setTimeout(() => scheduleLogSourcePanelRender(), 0);
    });

    onDOM(resetBtn, 'click', () => {
      const ok = root.confirm(`${PLUGIN_NAME}：确定要重置所有设置吗？`);
      if (!ok) {
        return;
      }

      const keepPos = {
        uiLeft: settings.uiLeft,
        uiTop: settings.uiTop,
        panelOpen: settings.panelOpen,
        uiPage: 'settings',
      };
      settings = sanitizeSettings(Object.assign({}, DEFAULT_SETTINGS, keepPos));
      saveSettings();
      syncUIFromSettings();
      resetState();
      if (settings.featureJumpBottomOnChatOpen) {
        scheduleChatBottomJump();
      }
      refreshScreenWakeLock('重置设置');
      refreshLogInterceptionState('重置设置');
      refreshIframeMemoryOptimizationState('重置设置');
      logWarn('设置已重置为默认值');
    });

    onDOM(collapseBtn, 'click', () => updateSettings({ panelOpen: false }));
    onDOM(widget, 'pointerdown', event => {
      const target = event.target;
      if (target && typeof target.closest === 'function' && target.closest('select')) {
        suppressOutsideCloseUntil = Date.now() + 1200;
      }
    }, true);

    onDOM(hostDocument, 'click', event => {
      if (!settings.panelOpen || !ui.widget) {
        return;
      }

      const path = typeof event.composedPath === 'function' ? event.composedPath() : null;
      if (Array.isArray(path) && path.includes(ui.widget)) {
        return;
      }

      const target = event.target;
      if (target && typeof target === 'object' && 'nodeType' in target && ui.widget.contains(target)) {
        return;
      }

      if (Date.now() <= suppressOutsideCloseUntil) {
        suppressOutsideCloseUntil = 0;
        return;
      }

      updateSettings({ panelOpen: false });
    }, true);

    bindSettingInput('featureAutoScroll', value => ({ featureAutoScroll: !!value }));
    bindSettingInput('featureAutoRetry', value => {
      if (!value) {
        clearRetryTimer();
      }
      return { featureAutoRetry: !!value };
    });
    bindSettingInput('featureErrorRetry', value => {
      const next = !!value;
      if (!next) {
        clearErrorRetryTimer();
        state.errorRetriesInRow = 0;
      }
      return { featureErrorRetry: next };
    });
    bindSettingInput('featureJumpBottomOnChatOpen', value => {
      const next = !!value;
      if (!next) {
        clearJumpTimer();
      } else {
        setTimeout(() => scheduleChatBottomJump(), 0);
      }
      return { featureJumpBottomOnChatOpen: next };
    });
    bindSettingInput('featureKeepScreenAwake', value => {
      const next = !!value;
      if (next === settings.featureKeepScreenAwake) {
        return null;
      }
      if (next) {
        setTimeout(async () => {
          const ok = await requestScreenWakeLock('手动开启');
          if (state.wakeLock.disposed) {
            return;
          }
          const reason = ok
            ? ''
            : (state.wakeLock.lastErrorMessage || state.wakeLock.lastErrorName || '未知错误');
          showWakeLockEnablePopup(ok, reason);
        }, 0);
      } else {
        setTimeout(() => {
          void releaseScreenWakeLock('手动关闭');
        }, 0);
      }
      return { featureKeepScreenAwake: next };
    });
    bindSettingInput('featureMobileVibration', value => {
      const next = !!value;
      if (next === settings.featureMobileVibration) {
        return null;
      }
      if (next) {
        requestVibration(settings.vibrationDurationMs, '开关预览震动');
      }
      return { featureMobileVibration: next };
    });
    bindSettingInput('featureLogInterception', value => {
      const next = !!value;
      setTimeout(() => {
        refreshLogInterceptionState('日志拦截开关切换');
      }, 0);
