  function bindSettingInput(key, transformer) {
    const input = ui.inputs[key];
    if (!input) {
      return;
    }

    const handler = () => {
      const rawValue = input.type === 'checkbox' ? input.checked : input.value;
      const patch = transformer(rawValue);
      if (patch && typeof patch === 'object') {
        updateSettings(patch);
      }
    };

    const isSelect = input.tagName === 'SELECT';
    const isNumberInput = input.tagName === 'INPUT' && input.type === 'number';
    const isCheckbox = input.tagName === 'INPUT' && input.type === 'checkbox';
    const eventName = (isSelect || isNumberInput || isCheckbox) ? 'change' : 'input';
    onDOM(input, eventName, handler);
    if (eventName !== 'change') {
      onDOM(input, 'change', handler);
    }
  }

  function syncNumericInputRanges() {
    const unlockRanges = !!settings.featureProfessionalUser;
    for (const [key, range] of Object.entries(NUMERIC_SETTING_RANGES)) {
      const input = ui.inputs[key];
      if (!input || input.type !== 'number') {
        continue;
      }
      if (unlockRanges) {
        input.removeAttribute('min');
        input.removeAttribute('max');
      } else {
        input.setAttribute('min', String(range.min));
        input.setAttribute('max', String(range.max));
      }
    }
  }

  function syncFabAppearanceInputsAvailability() {
    const mode = normalizeUiExpandMode(settings.uiExpandMode, DEFAULT_SETTINGS.uiExpandMode);
    const disableFabInputs = mode !== UI_EXPAND_MODES.FAB;
    const managedKeys = ['fabSizePx', 'fabOpacityPercent'];
    for (const key of managedKeys) {
      const input = ui.inputs[key];
      if (!input) {
        continue;
      }
      input.disabled = disableFabInputs;
      if (disableFabInputs) {
        input.title = '当前为拓展按钮模式，悬浮球参数已禁用';
      } else {
        input.removeAttribute('title');
      }
    }
  }

  function syncUIFromSettings() {
    if (!ui.widget) {
      return;
    }

    const boolKeys = [
      'featureAutoScroll',
      'featureAutoRetry',
      'featureErrorRetry',
      'featureJumpBottomOnChatOpen',
      'featureKeepScreenAwake',
      'featureMobileVibration',
      'featureLogInterception',
      'featureIframeMemoryOptimize',
      'featureProfessionalUser',
      'logInterceptSelectAll',
      'showShortRetryPopup',
      'showErrorRetryPopup',
      'debug',
    ];

    for (const key of boolKeys) {
      if (ui.inputs[key]) {
        ui.inputs[key].checked = !!settings[key];
      }
    }

    syncNumericInputRanges();

    const numericKeys = [
      'minChars',
      'maxRetriesPerMessage',
      'maxErrorRetriesPerCycle',
      'renderSettleDelayMs',
      'scrollRetryTimes',
      'scrollRetryIntervalMs',
      'retryDelayMs',
      'errorRetryDelayMs',
      'shortWaitIdleTimeoutMs',
      'shortWaitIdlePollMs',
      'errorWaitIdleTimeoutMs',
      'errorWaitIdlePollMs',
      'chatOpenJumpDelayMs',
      'chatOpenJumpRetryTimes',
      'chatOpenJumpRetryIntervalMs',
      'vibrationDurationMs',
      'iframeCullRootMarginPx',
      'iframeCullDelayMs',
      'iframeBottomWhitelistCount',
      'fabSizePx',
      'fabOpacityPercent',
    ];

    for (const key of numericKeys) {
      if (ui.inputs[key]) {
        ui.inputs[key].value = String(settings[key]);
      }
    }

    if (ui.inputs.scrollBehavior) {
      ui.inputs.scrollBehavior.value = settings.scrollBehavior;
    }
    if (ui.inputs.uiThemePreset) ui.inputs.uiThemePreset.value = settings.uiThemePreset;
    if (ui.inputs.uiExpandMode) ui.inputs.uiExpandMode.value = settings.uiExpandMode;
    if (ui.inputs.fabColorA) ui.inputs.fabColorA.value = settings.fabColorA;
    if (ui.inputs.fabColorB) ui.inputs.fabColorB.value = settings.fabColorB;
    if (ui.inputs.panelColor) ui.inputs.panelColor.value = settings.panelColor;
    syncFabAppearanceInputsAvailability();

    syncExpandModeTriggerUI();

    ui.panel.hidden = !settings.panelOpen;
    ui.pageSettings.hidden = settings.uiPage !== 'settings';
    ui.pageHelp.hidden = settings.uiPage !== 'help';
    ui.pageAbout.hidden = settings.uiPage !== 'about';
    ui.tabSettings.classList.toggle('is-active', settings.uiPage === 'settings');
    ui.tabHelp.classList.toggle('is-active', settings.uiPage === 'help');
    ui.tabAbout.classList.toggle('is-active', settings.uiPage === 'about');
    syncLogSourcePanelUI();
    scheduleLogSourcePanelRender();
    scheduleIframeLoadStatusRender(0);

    const fullyOff =
      !settings.featureAutoScroll
      && !settings.featureAutoRetry
      && !settings.featureErrorRetry
      && !settings.featureJumpBottomOnChatOpen
      && !settings.featureKeepScreenAwake
      && !settings.featureMobileVibration
      && !settings.featureLogInterception
      && !settings.featureIframeMemoryOptimize;
    ui.fab.classList.toggle('off', fullyOff);

    applyThemeVariables();
    ensureWidgetInViewport();
  }

  // Keep the floating widget visible while supporting custom sizes.
  function getDefaultPosition() {
    const fabSize = normalizeSettingInt(
      settings.fabSizePx,
      32,
      96,
      DEFAULT_SETTINGS.fabSizePx,
      settings.featureProfessionalUser
    );
    const margin = 16;
    const left = root.innerWidth - fabSize - margin;
    const top = Math.max(margin, Math.min(root.innerHeight - fabSize - margin, 120));
    return { left, top };
  }

  function setWidgetPosition(left, top, persist) {
    if (!ui.widget) {
      return;
    }

    const closedSize = normalizeSettingInt(
      settings.fabSizePx,
      32,
      96,
      DEFAULT_SETTINGS.fabSizePx,
      settings.featureProfessionalUser
    );
    const width = settings.panelOpen ? (ui.widget.offsetWidth || 360) : closedSize;
    const height = settings.panelOpen ? (ui.widget.offsetHeight || 520) : closedSize;
    const maxLeft = Math.max(8, root.innerWidth - width - 8);
    const maxTop = Math.max(8, root.innerHeight - height - 8);

    const clampedLeft = clampFloat(left, 8, maxLeft, 8);
    const clampedTop = clampFloat(top, 8, maxTop, 8);

    ui.widget.style.left = `${clampedLeft}px`;
    ui.widget.style.top = `${clampedTop}px`;

    if (persist) {
      settings.uiLeft = clampedLeft;
      settings.uiTop = clampedTop;
      saveSettings();
    }
  }

  function ensureWidgetPosition() {
    const useDefault = settings.uiLeft === null || settings.uiTop === null;
    if (useDefault) {
      const pos = getDefaultPosition();
      setWidgetPosition(pos.left, pos.top, true);
    } else {
      setWidgetPosition(settings.uiLeft, settings.uiTop, true);
    }
  }

  function ensureWidgetInViewport() {
    if (!ui.widget) {
      return;
    }
    const rect = ui.widget.getBoundingClientRect();
    setWidgetPosition(rect.left, rect.top, false);
  }

  function persistWidgetPosition() {
    if (!ui.widget) {
      return;
    }
    const rect = ui.widget.getBoundingClientRect();
    settings.uiLeft = rect.left;
    settings.uiTop = rect.top;
    saveSettings();
  }

  function makeWidgetDraggable() {
    if (!ui.widget || !ui.fab || !ui.headerDrag) {
      return;
    }

    const dragState = {
      active: false,
      pointerId: null,
      startX: 0,
      startY: 0,
      originLeft: 0,
      originTop: 0,
      moved: false,
    };

    function isInteractiveHeaderTarget(target) {
      if (!target || typeof target.closest !== 'function') {
        return false;
      }
      return !!target.closest('button, input, select, textarea, label, a');
    }

    function startDrag(event) {
      if (event.pointerType === 'mouse' && event.button !== 0) {
        return;
      }
      if (event.currentTarget === ui.headerDrag && isInteractiveHeaderTarget(event.target)) {
        return;
      }

      const rect = ui.widget.getBoundingClientRect();
      dragState.active = true;
      dragState.pointerId = Number.isFinite(event.pointerId) ? event.pointerId : null;
      dragState.startX = event.clientX;
      dragState.startY = event.clientY;
      dragState.originLeft = rect.left;
      dragState.originTop = rect.top;
      dragState.moved = false;
      ui.widget.dataset.dragging = '0';

      if (typeof event.currentTarget?.setPointerCapture === 'function' && dragState.pointerId !== null) {
        try {
          event.currentTarget.setPointerCapture(dragState.pointerId);
        } catch (_error) {
          // Ignore capture errors and continue dragging with document-level listeners.
        }
      }
      event.preventDefault();
    }

    function onMove(event) {
      if (!dragState.active) {
        return;
      }
      if (dragState.pointerId !== null && event.pointerId !== dragState.pointerId) {
        return;
      }

      const dx = event.clientX - dragState.startX;
      const dy = event.clientY - dragState.startY;

      if (Math.abs(dx) + Math.abs(dy) > 4) {
        dragState.moved = true;
        ui.widget.dataset.dragging = '1';
      }

      setWidgetPosition(dragState.originLeft + dx, dragState.originTop + dy, false);
    }

    function endDrag(event) {
      if (!dragState.active) {
        return;
      }
      if (
        dragState.pointerId !== null
        && event
        && Number.isFinite(event.pointerId)
        && event.pointerId !== dragState.pointerId
      ) {
        return;
      }

      dragState.active = false;
      dragState.pointerId = null;
      persistWidgetPosition();

      setTimeout(() => {
        if (ui.widget) {
          ui.widget.dataset.dragging = '0';
        }
      }, 0);
    }

    onDOM(ui.fab, 'pointerdown', startDrag);
    onDOM(ui.headerDrag, 'pointerdown', startDrag);
    onDOM(hostDocument, 'pointermove', onMove);
    onDOM(hostDocument, 'pointerup', endDrag);
    onDOM(hostDocument, 'pointercancel', endDrag);
  }

  function registerRuntimeEvents() {
    const eventOnFn = getRuntimeFunction('eventOn');
    const eventMakeLastFn = getRuntimeFunction('eventMakeLast');
    const events = getRuntimeObject('tavern_events');

    if (!eventOnFn || !events) {
      logError('未找到 Tavern 事件 API，核心自动功能不可用');
      return false;
    }

    const registerMessageEvent = eventMakeLastFn || eventOnFn;
    registerEventStop(registerMessageEvent(events.CHARACTER_MESSAGE_RENDERED, handleCharacterMessageRendered));
    registerEventStop(eventOnFn(events.GENERATION_STARTED, handleGenerationStarted));
    registerEventStop(eventOnFn(events.GENERATION_STOPPED, handleGenerationStopped));
    registerEventStop(eventOnFn(events.GENERATION_ENDED, handleGenerationEnded));
    registerEventStop(eventOnFn(events.CHAT_CHANGED, handleChatChanged));
    return true;
  }

  function initializePlugin() {
    ensureStyles();
    if (!buildWidget()) {
      return;
    }

    registerRuntimeEvents();

    if (settings.featureJumpBottomOnChatOpen) {
      scheduleChatBottomJump();
    }
    if (settings.featureKeepScreenAwake) {
      void requestScreenWakeLock('初始化');
    }
    refreshIframeMemoryOptimizationState('初始化');

    consoleRef.info(LOG_PREFIX, '脚本已加载');
    log('初始化完成');
  }

  // Cleanup for hot-reload and manual stop.
  function stopAll() {
    clearRetryTimer();
    clearErrorRetryTimer();
    clearJumpTimer();
    clearUiExpandModeRetryTimer();
    teardownLogInterception();
    teardownIframeMemoryOptimization();
    state.wakeLock.disposed = true;
    void releaseScreenWakeLock('脚本停止');

    for (const stop of eventStops.splice(0)) {
      try {
        stop();
      } catch (error) {
        logWarn('停止事件监听失败', error);
      }
    }

    while (domCleanup.length) {
      const fn = domCleanup.pop();
      try {
        fn();
      } catch (error) {
        logWarn('清理资源失败', error);
      }
    }

    const widget = hostDocument.getElementById(WIDGET_ID);
    if (widget) {
      widget.remove();
    }

    removeExtensionsMenuEntry();

    const styleEl = hostDocument.getElementById(STYLE_ID);
    if (styleEl) {
      styleEl.remove();
    }

    const toastRoot = hostDocument.getElementById(TOAST_ID);
    if (toastRoot) {
      toastRoot.remove();
    }

    delete root[SCRIPT_KEY];
  }

  root[SCRIPT_KEY] = {
    stop: stopAll,
  };

  if (hostDocument.readyState === 'loading') {
    onDOM(hostDocument, 'DOMContentLoaded', initializePlugin, { once: true });
  } else {
    initializePlugin();
  }
})());

