        display: flex;
        flex-direction: column;
        padding: 20px;
        gap: 15px;
        position: relative;
        flex-grow: 1;
    }

    /* Section Styling */
    .setup-section {
        border: 1px solid var(--border-color);
        background: var(--bg-secondary);
        background-color: #efe8d9;
        border-radius: var(--card-border-radius);
        padding: 18px;
        position: relative;
        box-shadow: 0 2px 6px rgba(150, 120, 80, 0.1), inset 0 1px 1px rgba(255, 255, 255, 0.7);
        overflow: hidden;
        margin-bottom: 15px;
        background-image: var(--parchment-texture);
        background-blend-mode: multiply;
    }

    .section-title {
        font-size: 20px;
        font-weight: 500;
        color: var(--text-primary);
        margin-bottom: 15px;
        padding-bottom: 8px;
        border-bottom: 1px solid var(--border-color);
        display: flex;
        align-items: center;
        gap: 8px;
    }

    /* 段落和描述文本 */
    .section-description {
        font-size: 16px;
        line-height: 1.6;
        color: var(--text-secondary);
        margin-bottom: 15px;
    }

    /* 文本强调 */
    .highlight {
        color: var(--accent-primary);
        font-weight: 500;
    }

    /* 选项容器 */
    .options-container {
        display: flex;
        flex-direction: column;
        gap: 12px;
        margin-bottom: 15px;
    }

    /* 两列布局的选项容器 */
    .options-container.two-columns {
        display: flex;
        flex-direction: row;
        flex-wrap: wrap;
        gap: 12px;
    }

    .options-container.two-columns .option-card,
    .options-container.two-columns .checkbox-option {
        width: calc(50% - 6px);
    }

    /* 选项卡片 */
    .option-card {
        border: 1px solid var(--border-color);
        border-radius: var(--card-border-radius);
        padding: 14px;
        background: var(--bg-tertiary);
        background-color: #f0e9d6; /* 更新为不透明的底色 */
        cursor: pointer;
        transition: all 0.3s ease;
        display: flex;
        align-items: flex-start;
        gap: 10px;
        box-shadow: 0 1px 3px rgba(150, 120, 80, 0.1), inset 0 1px 0 rgba(255, 255, 255, 0.5);
        background-image: var(--parchment-texture);
        background-blend-mode: multiply; /* 添加混合模式使纹理与底色融合 */
    }

    .option-card:hover {
        border-color: var(--accent-subtle);
        transform: translateY(-2px);
        background-color: #f5f0e0; /* 悬停时使用更亮的底色 */
        box-shadow: 0 4px 8px rgba(150, 120, 80, 0.15), inset 0 1px 0 rgba(255, 255, 255, 0.5);
    }

    .option-card.selected {
        border-color: var(--accent-primary);
        background-color: #e8dfc5; /* 选中时使用更深的底色 */
        box-shadow: 0 2px 6px rgba(150, 120, 80, 0.2), inset 0 1px 0 rgba(255, 255, 255, 0.5);
    }

    .option-radio {
        min-width: 20px;
        height: 20px;
        margin-top: 2px;
    }

    .option-content {
        flex: 1;
    }

    .option-title {
        font-weight: 600;
        margin-bottom: 5px;
        color: var(--text-primary);
        font-size: 17px;
    }

    .option-desc {
        font-size: 15px;
        color: var(--text-secondary);
        line-height: 1.5;
    }

    /* 表单输入样式 */
    .input-group {
        margin-bottom: 15px;
    }

    .input-label {
        display: block;
        font-weight: 500;
        margin-bottom: 8px;
        color: var(--text-primary);
    }

    .text-input {
        width: 100%;
        padding: 12px 14px;
        border: 1px solid var(--border-color);
        border-radius: 8px;
        background-color: #f0e9d6; /* 更新为不透明的底色 */
        color: var(--input-text);
        font-size: 15px;
        transition: all 0.3s ease;
        font-family: 'EB Garamond', 'Noto Serif SC', serif;
        box-shadow: inset 0 1px 3px rgba(0, 0, 0, 0.05);
        background-image: var(--parchment-texture);
        background-blend-mode: multiply; /* 添加混合模式使纹理与底色融合 */
    }

    .text-input:focus {
        border-color: var(--accent-primary);
        box-shadow: 0 0 0 3px rgba(181, 136, 99, 0.2), inset 0 1px 3px rgba(0, 0, 0, 0.05);
        outline: none;
        background-color: #f5f0e0; /* 聚焦时使用更亮的底色 */
    }

    textarea.text-input {
        min-height: 80px;
        resize: vertical;
    }

    /* 多选项样式 */
    .checkbox-option {
        display: flex;
        align-items: flex-start;
        gap: 10px;
        margin-bottom: 10px;
        padding: 12px;
        border: 1px solid var(--border-color);
        border-radius: 8px;
        transition: all 0.2s ease;
        background-color: #f0e9d6; /* 更新为不透明的底色 */
        box-shadow: 0 1px 2px rgba(150, 120, 80, 0.1), inset 0 1px 0 rgba(255, 255, 255, 0.5);
        background-image: var(--parchment-texture);
        background-blend-mode: multiply;
    }

    .checkbox-option:hover {
        background-color: rgba(233, 225, 204, 0.8);
        background-color: #f5f0e0;
        border-color: var(--accent-subtle);
        box-shadow: 0 2px 4px rgba(150, 120, 80, 0.15), inset 0 1px 0 rgba(255, 255, 255, 0.5);
    }

    .checkbox-option.selected {
        background-color: rgba(210, 180, 140, 0.2);
        background-color: #e8dfc5;
        border-color: var(--accent-primary);
        box-shadow: 0 1px 3px rgba(150, 120, 80, 0.15), inset 0 1px 0 rgba(255, 255, 255, 0.5);
    }

    .checkbox-input {
        min-width: 18px;
        height: 18px;
        margin-top: 3px;
    }

    /* 导航按钮 */
    .step-navigation {
        display: flex;
        justify-content: space-between;
        margin-top: 20px;
        padding-top: 20px;
        border-top: 1px solid var(--border-color);
        position: relative;
    }

    /* 按钮基础样式 */
    button, .step-navigation button {
        padding: 10px 20px;
        border: 1px solid var(--border-color);
        border-radius: var(--button-border-radius);
        cursor: pointer;
        font-size: 15px;
        font-weight: 500;
        display: inline-flex;
        align-items: center;
        gap: 8px;
        transition: all 0.3s ease;
        box-shadow: 0 1px 3px rgba(150, 120, 80, 0.1), inset 0 1px 0 rgba(255, 255, 255, 0.5);
        letter-spacing: 0.5px;
        font-family: 'EB Garamond', 'Noto Serif SC', serif;
    }

    button:hover:not(:disabled), .step-navigation button:hover:not(:disabled) {
        box-shadow: 0 3px 6px rgba(150, 120, 80, 0.2), inset 0 1px 0 rgba(255, 255, 255, 0.5);
        transform: translateY(-1px);
    }

    button:active:not(:disabled), .step-navigation button:active:not(:disabled) {
        box-shadow: 0 1px 2px rgba(150, 120, 80, 0.2), inset 0 1px 0 rgba(255, 255, 255, 0.5);
        transform: translateY(0);
    }

    button:disabled, .step-navigation button:disabled {
        background: var(--disabled-color);
        color: #f8f9fa;
        cursor: not-allowed;
        box-shadow: none;
        transform: none;
        opacity: 0.7;
    }

    /* 下一步和完成按钮 */
    .next-step, #generate-world-btn {
        background: var(--accent-primary);
        color: var(--text-light);
        border-color: var(--accent-primary);
        background-image: linear-gradient(to bottom, var(--accent-primary), #7b4d23);
    }

    .next-step:hover:not(:disabled), #generate-world-btn:hover:not(:disabled) {
        background: #7b4d23;
        border-color: #7b4d23;
        background-image: linear-gradient(to bottom, #7b4d23, #6b3d13);
    }

    .next-step:active:not(:disabled), #generate-world-btn:active:not(:disabled) {
        background: #6b3d13;
        border-color: #6b3d13;
        background-image: linear-gradient(to bottom, #6b3d13, #5b3d03);
    }

    /* 上一步按钮 */
    .prev-step {
        background: var(--bg-tertiary);
        color: var(--text-primary);
        background-image: linear-gradient(to bottom, var(--bg-tertiary), #dfd7c3);
    }

    .prev-step:hover:not(:disabled) {
        background: #dfd7c3;
        background-image: linear-gradient(to bottom, #dfd7c3, #d5cdb9);
    }

    .prev-step:active:not(:disabled) {
        background: #d5cdb9;
        background-image: linear-gradient(to bottom, #d5cdb9, #cbc3af);
    }

    /* 状态消息 */
    #status-message {
        text-align: center;
        margin-top: 15px;
        padding: 10px 20px;
        border-radius: var(--button-border-radius);
        background-color: #f7f3e9;
        border: 1px solid var(--border-color);
        color: var(--text-primary);
        font-weight: normal;
        position: fixed;
        bottom: 20px;
        left: 50%;
        transform: translateX(-50%);
        z-index: 1000;
        max-width: 80%;
        box-shadow: 0 3px 8px rgba(150, 120, 80, 0.15), inset 0 1px 0 rgba(255, 255, 255, 0.5);
        animation: fadeInUp 0.5s ease-out forwards;
        display: flex;
        align-items: center;
        gap: 8px;
        font-size: 15px;
        background-image: var(--parchment-texture);
        background-blend-mode: multiply;
    }

    @keyframes fadeInUp {
        from { opacity: 0; transform: translate(-50%, 20px); }
        to { opacity: 1; transform: translate(-50%, 0); }
    }

    .hidden {
        display: none !important;
    }

    .setup-step {
        transition: opacity 0.3s ease-in-out, transform 0.3s ease-in-out;
        position: relative;
        opacity: 1;
        transform: translateY(0);
    }

    .setup-step.hidden {
        opacity: 0;
        transform: translateY(10px);
        position: absolute;
        width: calc(100% - 50px);
        pointer-events: none;
        left: 25px;
        top: 0;
    }

    @keyframes fadeIn {
        from { opacity: 0; transform: translateY(10px); }
        to { opacity: 1; transform: translateY(0); }
    }

    /* 完成界面 */
    .setup-complete {
        text-align: center;
        padding: 40px 20px;
        animation: fadeIn 0.8s ease-out forwards;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        min-height: 300px;
    }

    .setup-complete h3 {
        color: var(--text-primary);
        font-size: 26px;
        margin-bottom: 15px;
        font-weight: 600;
        text-shadow: 1px 1px 1px rgba(255, 255, 255, 0.5);
        border-bottom: none;
    }

    .setup-complete p {
        color: var(--text-secondary);
        font-size: 17px;
        line-height: 1.6;
        max-width: 450px;
        margin: 0 auto;
        margin-bottom: 20px;
        text-shadow: 1px 1px 1px rgba(255, 255, 255, 0.5);
    }

    /* 结果框 */
    .result-box {
        background-color: #f0e9d6; /* 不透明的底色 */
        border: 1px solid var(--border-color);
        border-radius: 8px;
        padding: 15px;
        max-height: 250px;
        overflow-y: auto;
        text-align: left;
        margin-bottom: 20px;
        width: 100%;
        font-family: 'EB Garamond', 'Noto Serif SC', serif;
        white-space: pre-wrap;
        font-size: 15px;
        color: var(--text-primary);
        box-shadow: inset 0 1px 3px rgba(0, 0, 0, 0.05);
        background-image: var(--parchment-texture);
        background-blend-mode: multiply; /* 添加混合模式使纹理与底色融合 */
    }

    /* 复制按钮 */
    .copy-btn {
        background: var(--bg-tertiary);
        color: var(--text-primary);
        border: 1px solid var(--border-color);
        border-radius: var(--button-border-radius);
        padding: 8px 20px;
        display: inline-flex;
        align-items: center;
        gap: 8px;
        font-size: 15px;
        cursor: pointer;
        transition: all 0.3s ease;
        box-shadow: 0 1px 3px rgba(150, 120, 80, 0.1), inset 0 1px 0 rgba(255, 255, 255, 0.5);
        background-image: linear-gradient(to bottom, var(--bg-tertiary), #dfd7c3);
    }

    .copy-btn:hover {
        background: #dfd7c3;
        border-color: var(--accent-subtle);
        background-image: linear-gradient(to bottom, #dfd7c3, #d5cdb9);
    }

    .copy-btn:active {
        background: #d5cdb9;
        transform: translateY(1px);
        background-image: linear-gradient(to bottom, #d5cdb9, #cbc3af);
    }

    /* 滚动条样式 */
    ::-webkit-scrollbar {
        width: 8px;
        height: 8px;
    }

    ::-webkit-scrollbar-track {
        background: var(--scrollbar-track-color);
        border-radius: 4px;
    }

    ::-webkit-scrollbar-thumb {
        background: var(--scrollbar-thumb-color);
        border-radius: 4px;
    }

    ::-webkit-scrollbar-thumb:hover {
        background: var(--accent-primary);
    }

    /* 移动端适配 */
    @media (max-width: 768px) {
        .world-builder-container {
            margin: 10px;
            max-width: calc(100% - 20px);
        }
        .controls {
            padding: 20px;
            gap: 20px;
        }
        .wb-header {
            padding: 12px 20px;
        }
        h1 { font-size: 20px; }
        h2 { font-size: 13px; }
        .step-navigation button {
            padding: 7px 15px;
            font-size: 13px;
        }
        .setup-section, fieldset { padding: 15px; }
        .section-title, legend { font-size: 15px; margin-bottom: 15px; }
        .setup-step.hidden {
           width: calc(100% - 30px);
           left: 15px;
        }
        .text-input { font-size: 13px; }
        .option-title { font-size: 14px; }
        .option-desc { font-size: 12px; }
    }

    @media (max-width: 480px) {
        .controls { padding: 15px; }
        .step-navigation {
            flex-direction: column;
            gap: 10px;
            align-items: stretch;
        }
        .setup-complete h3 { font-size: 20px; }
        .setup-complete p { font-size: 14px; }
    }

    .text-input::placeholder {
        color: var(--placeholder-color, #422d10) !important; /* 使用CSS变量，默认为深棕色 */
        opacity: 1 !important; /* 确保完全不透明 */
        font-weight: 500 !important; /* 加粗一点 */
