    function createWorldScaleOptionsHTML() {
        let html = '';

        worldScales.forEach(scale => {
            html += `
                <div class="option-card world-scale-option" data-scale="${scale.id}">
                    <input type="radio" name="world-scale" class="option-radio" id="scale-${scale.id}" value="${scale.id}">
                    <div class="option-content">
                        <div class="option-title">${scale.name}</div>
                        <div class="option-desc">
                            ${scale.description}<br>
                            <strong>特点：</strong> ${scale.features}<br>
                            <strong>适合：</strong> ${scale.suitable}
                        </div>
                    </div>
                </div>
            `;
        });

        return html;
    }

