                        <div id="characters-options" style="margin-top: 10px; display: none;">
                            <div>选择角色数量：</div>
                            <div style="display: flex; gap: 15px; margin: 5px 0 10px;">
                                <label style="display: flex; align-items: center; gap: 5px;">
                                    <input type="radio" name="character-count" value="few" checked> 少量(1-3)
                                </label>
                                <label style="display: flex; align-items: center; gap: 5px;">
                                    <input type="radio" name="character-count" value="many"> 多个(4-8)
                                </label>
                            </div>
                            <div>角色详细程度：</div>
                            <div style="display: flex; gap: 15px; margin: 5px 0;">
                                <label style="display: flex; align-items: center; gap: 5px;">
                                    <input type="radio" name="character-detail" value="simple" checked> 简略列表
