    // 生成最终需求清单
    function generateRequirementsList() {
        // 获取世界规模名称
        const scaleInfo = worldScales.find(s => s.id === userData.worldScale);
        const scaleName = scaleInfo ? scaleInfo.name : "未选择";

        // 获取时代名称
        const eraInfo = eraOptions.find(e => e.id === userData.era);
        const eraName = eraInfo ? eraInfo.name : "未选择";
        const eraDescription = eraInfo ? eraInfo.description : "";

        // 获取主题名称
        const themeNames = userData.themes.map(themeId => {
            const themeInfo = themeOptions.find(t => t.id === themeId);
            return themeInfo ? themeInfo.name : "";
        }).filter(name => name !== "");

        // 获取模块信息
        const moduleDetails = userData.modules.map(moduleId => {
            const moduleInfo = worldModules.find(m => m.id === moduleId);
            if (!moduleInfo) return null;

            // 获取与当前世界规模相关的考虑因素
            const considerations = moduleInfo.considerations ? 
                ` - ${moduleInfo.considerations[userData.worldScale]}` : "";

            return `${moduleInfo.name}${considerations}`;
        }).filter(item => item !== null);

        // 获取输出选项
        const outputDetails = userData.outputOptions.map(outputId => {
            const outputInfo = outputOptions.find(o => o.id === outputId);
            return outputInfo ? `- ${outputInfo.name}` : "";
        }).filter(item => item !== "");

        // 构建需求清单
        let requirements = `
========================================
您的世界书需求清单
========================================

世界规模：${scaleName}
`;

        // 添加时代信息
        if (userData.era) {
            requirements += `时代/科技水平：${eraName} (${eraDescription})\n`;
        }

        // 添加自定义背景（如果有）
        if (userData.customEra && userData.customEra.trim() !== "") {
            requirements += `自定义背景：${userData.customEra.trim()}\n`;
        }

        // 添加补充说明（如果有）
        if (userData.eraNotes && userData.eraNotes.trim() !== "") {
            requirements += `时代补充说明：${userData.eraNotes.trim()}\n`;
        }

        // 添加主题
        if (themeNames.length > 0) {
            requirements += `\n核心主题/风格：${themeNames.join("、")}\n`;
        }

        // 添加自定义主题（如果有）
        if (userData.customTheme && userData.customTheme.trim() !== "") {
            requirements += `自定义主题与风格：${userData.customTheme.trim()}\n`;
        }

        // 添加主题补充说明（如果有）
        if (userData.themeNotes && userData.themeNotes.trim() !== "") {
            requirements += `主题补充说明：${userData.themeNotes.trim()}\n`;
        }

        // 添加模块
        requirements += `\n已选模块：`;
        if (moduleDetails.length > 0) {
            moduleDetails.forEach((module, index) => {
                requirements += `\n${index + 1}. ${module}`;
            });
        } else {
            requirements += "\n无";
        }

        // 添加角色信息
        if (userData.characters.enabled) {
            requirements += `\n\n主要角色设置：`;
            requirements += `\n- 角色数量：${userData.characters.count === 'few' ? '少量(1-3)' : '多个(4-8)'}`;
            requirements += `\n- 详细程度：${userData.characters.detail === 'simple' ? '简略列表' : '详细档案'}`;
        }

        // 添加补充说明
        if (userData.additionalNotes && userData.additionalNotes.trim() !== "") {
            requirements += `\n\n补充说明与杂项：${userData.additionalNotes.trim()}`;
        }

        // 添加输出选项
        requirements += `\n\n输出选项：`;
        if (outputDetails.length > 0) {
            outputDetails.forEach(output => {
                requirements += `\n${output}`;
            });
        } else {
            requirements += "\n无";
        }

        // 添加未选模块说明 - 明确指出不应包含哪些内容
        requirements += `\n\n特别说明 - 不包含的内容：`;

        // 筛选当前世界规模适用但未被选中的模块
        const applicableModules = worldModules.filter(module => 
            module.scales && module.scales.includes(userData.worldScale)
        );

        const unselectedModules = applicableModules.filter(module => 
            !userData.modules.includes(module.id)
        );

        if (unselectedModules.length > 0) {
            unselectedModules.forEach((module, index) => {
                requirements += `\n${index + 1}. 请不要输出"${module.name}"相关内容`;
            });
        } else {
            requirements += "\n所有适用模块均已选择";
        }

        // 添加角色特别说明
        if (!userData.characters.enabled) {
            requirements += `\n${unselectedModules.length + 1}. 请不要输出"主要角色"相关内容`;
        }

        requirements += "\n========================================";

        return requirements;
    }

    // 直接生成世界书需求并发送
    async function generateWorldBook($container) {
        const $statusMessage = $container.find('#status-message');
        $statusMessage.removeClass('hidden').html('<i class="fas fa-spinner fa-spin"></i> 正在生成世界书需求...');

        // 禁用所有按钮
        $container.find('button').prop('disabled', true);

        try {
            // 格式化需求清单
            const requirements = generateRequirementsList();

            // 显示完成信息并隐藏设置界面
            $container.find('.setup-step').addClass('hidden');
            $container.find('#setup-complete').removeClass('hidden');
            $statusMessage.addClass('hidden');

            // 生成回复 - 仿照问答游戏设置界面方式
            const systemInstruction = `# 世界观构建任务
请根据以下需求创建一个详尽而富有想象力的世界观设定。

# 需求清单
${requirements}

# 输出指南
1. 使用富有创意和生动形象的语言描述这个世界
2. 根据用户选择的世界规模调整细节深度:
   - 微型场景：聚焦于特定环境的氛围、规则和限制
   - 中型区域：描述多个相互关联的地点及其社会结构
   - 宏大世界：构建完整的地理、历史、文化和势力体系

3. 为每个选定的模块创建专属章节:
   - 核心规则：描述世界的基本运作法则
   - 环境设定：塑造世界的物理环境和氛围
   - 重要地点：描述关键场所及其特点
   - 势力组织：详述各势力的目标、结构和冲突
   - 关键物品/技术：介绍独特的物品或技术及其影响
   - 历史年表/关键事件：勾勒重要的历史事件和发展脉络
   - 特殊机制/系统：解释特殊的魔法、科技或社会系统

4. 确保世界观的各元素相互连贯，形成一个统一且合理的整体
5. 根据选定的时代风貌和核心主题调整整体风格和重点

请开始创建这个独特的世界，发挥你的创意，使其成为一个具有深度和真实感的设定，能够支撑各种引人入胜的故事。`;

            // 生成回复
            const result = await generate({
                user_input: "请为我打造这个世界观",
                should_stream: generationOptions.should_stream,
                injects: [
                    {
                        role: 'system',
                        content: systemInstruction,
                        position: 'before_prompt',
                        depth: 0,
                        should_scan: false
                    }
                ]
            });

            // 更新当前消息层的内容
            const lastMessageId = await triggerSlashWithResult('/pass {{lastMessageId}}');
            if (lastMessageId) {
                await setChatMessage({message: result}, parseInt(lastMessageId), {refresh: 'display_and_render_current'});
            }

        } catch (error) {
            $statusMessage.html(`<i class="fas fa-exclamation-triangle"></i> 错误：${error.message}`);
            triggerSlash(`/echo severity=error 世界构建向导: ${error.message}`);
        } finally {
            $container.find('button').prop('disabled', false);
        }
    }

    // 设置事件处理器
    function setupEventHandlers($container) {
        // 设置所有placeholder的样式
        setTimeout(() => {
            const textareas = $container.find('textarea.text-input');
            textareas.each(function() {
                // 使用jQuery的css方法直接设置样式，更浅的颜色
                $(this).css('color', '#422d10');
                $(this).css('--placeholder-color', '#b09471');

                // 为了确保样式被应用，我们也可以尝试使用内联样式
                this.style.setProperty('color', '#422d10', 'important');
                this.style.setProperty('--placeholder-color', '#b09471', 'important');

                // 使用原生DOM API设置属性
                this.setAttribute('style', this.getAttribute('style') + '; color: #422d10 !important; --placeholder-color: #b09471 !important;');
            });
        }, 100);

        // 步骤1：欢迎页面
        $container.find('#to-scale-btn').on('click', function() {
            $container.find('#step-welcome').addClass('hidden');
            $container.find('#step-scale').removeClass('hidden');
        });

        // 步骤2：世界规模选择
        $container.find('#back-to-welcome-btn').on('click', function() {
            $container.find('#step-scale').addClass('hidden');
            $container.find('#step-welcome').removeClass('hidden');
        });

        $container.find('#to-era-btn').on('click', function() {
            // 检查是否已选择世界规模
            const selectedScale = $container.find('input[name="world-scale"]:checked').val();
            if (!selectedScale) {
                showStatusMessage("请选择一个世界规模", true);
                return;
            }

            // 保存世界规模
            userData.worldScale = selectedScale;

            // 根据选择的世界规模更新时代和主题选项
            const $eraOptions = $container.find('#era-options');
            $eraOptions.html(createEraOptionsHTML());

            const $themeOptions = $container.find('#theme-options');
            $themeOptions.html(createThemeOptionsHTML());

            // 添加规模特定的标题
            let scaleSpecificTitle = "";
            if (selectedScale === "micro") {
                scaleSpecificTitle = "为您的微型场景设定气氛";
            } else if (selectedScale === "mid") {
                scaleSpecificTitle = "为您的中型区域设定特色";
            } else if (selectedScale === "macro") {
                scaleSpecificTitle = "为您的宏大世界设定背景";
            }

            if (scaleSpecificTitle) {
                $container.find('#step-era-theme .section-title').text(scaleSpecificTitle);
            }

            // 跳转到下一步
            $container.find('#step-scale').addClass('hidden');
            $container.find('#step-era-theme').removeClass('hidden');
        });

        // 步骤3：时代和主题选择
        $container.find('#back-to-scale-btn').on('click', function() {
            $container.find('#step-era-theme').addClass('hidden');
            $container.find('#step-scale').removeClass('hidden');
        });

        $container.find('#to-modules-btn').on('click', function() {
            // 检查是否已选择时代
            const selectedEra = $container.find('input[name="era"]:checked').val();
            if (!selectedEra && !$container.find('#custom-era').val().trim()) {
                showStatusMessage("请选择一个时代风貌或填写自定义背景", true);
                return;
            }

            // 保存时代和主题相关数据
            userData.era = selectedEra || "";
            userData.eraNotes = $container.find('#era-notes').val();
            userData.customEra = $container.find('#custom-era').val();

            // 收集选中的主题
            userData.themes = [];
            $container.find('.theme-option input:checked').each(function() {
                userData.themes.push($(this).val());
            });

            userData.themeNotes = $container.find('#theme-notes').val();
            userData.customTheme = $container.find('#custom-theme').val();

            // 根据选择的世界规模更新模块选项
            const $moduleOptions = $container.find('#module-options');
            $moduleOptions.html(createModulesOptionsHTML(userData.worldScale));

            // 添加规模特定的标题
            let scaleSpecificTitle = "";
            if (userData.worldScale === "micro") {
                scaleSpecificTitle = "选择微型场景的核心元素";
            } else if (userData.worldScale === "mid") {
                scaleSpecificTitle = "选择中型区域的构成要素";
            } else if (userData.worldScale === "macro") {
                scaleSpecificTitle = "选择宏大世界的框架结构";
            }

            if (scaleSpecificTitle) {
                $container.find('#step-modules .section-title').text(scaleSpecificTitle);
            }

            // 跳转到下一步
            $container.find('#step-era-theme').addClass('hidden');
            $container.find('#step-modules').removeClass('hidden');
        });

        // 步骤4：模块选择
        $container.find('#back-to-era-btn').on('click', function() {
            $container.find('#step-modules').addClass('hidden');
            $container.find('#step-era-theme').removeClass('hidden');
        });

        $container.find('#generate-world-btn').on('click', function() {
            // 收集选中的模块
            userData.modules = [];
            $container.find('.module-option input:checked').each(function() {
                const moduleId = $(this).val();
                if (moduleId !== 'characters') { // 角色单独处理
                    userData.modules.push(moduleId);
                }
            });

            // 收集选中的输出选项
            userData.outputOptions = [];
            const selectedOutput = $container.find('input[name="output-type"]:checked').val();
            if (selectedOutput) {
                userData.outputOptions.push(selectedOutput);
            }

            // 收集补充说明
            userData.additionalNotes = $('#additional-notes').val() || '';

            // 检查角色选项
            userData.characters.enabled = $('#module-characters').is(':checked');
            if (userData.characters.enabled) {
                userData.characters.count = $('input[name="character-count"]:checked').val() || 'few';
                userData.characters.detail = $('input[name="character-detail"]:checked').val() || 'simple';
            }

            // 直接生成世界书需求并发送给AI
            generateWorldBook($container);
        });

        // 重置按钮
        $container.find('#restart-btn').on('click', function() {
            // 重置所有选择
            resetUserData();

            // 重置表单状态
            $container.find('input[type="radio"]').prop('checked', false);
            $container.find('input[type="checkbox"]').prop('checked', false);
            $container.find('textarea').val('');

            // 返回第一步
            $container.find('#setup-complete').addClass('hidden');
            $container.find('#step-welcome').removeClass('hidden');
        });

        // 选项卡交互
        $container.on('click', '.option-card', function() {
            const radioBtn = $(this).find('input[type="radio"]');
            radioBtn.prop('checked', true);

            // 移除其他卡片的选中状态
            $(this).parent().find('.option-card').removeClass('selected');
            // 添加当前卡片的选中状态
            $(this).addClass('selected');
        });

        // 复选框选项交互
        $container.on('click', '.checkbox-option', function(e) {
            // 防止点击复选框本身时触发两次
            if (!$(e.target).is('input')) {
                const checkbox = $(this).find('input[type="checkbox"]');
                checkbox.prop('checked', !checkbox.prop('checked'));
            }

            // 更新样式
            if ($(this).find('input[type="checkbox"]').prop('checked')) {
                $(this).addClass('selected');
            } else {
                $(this).removeClass('selected');
            }
        });

        // 手动点击复选框时也更新样式
        $container.on('change', '.checkbox-input', function() {
            if ($(this).prop('checked')) {
                $(this).closest('.checkbox-option').addClass('selected');
            } else {
                $(this).closest('.checkbox-option').removeClass('selected');
            }
        });

        // 手动点击单选按钮时也更新样式
        $container.on('change', '.option-radio', function() {
            const optionCards = $(this).closest('.options-container').find('.option-card');
            optionCards.removeClass('selected');
            $(this).closest('.option-card').addClass('selected');
        });

        // 角色选项事件处理
        $container.on('change', 'input[name="characters"]', function() {
            const selectedCharacters = $(this).val();
            if (selectedCharacters === 'none') {
                $container.find('#character-detail-options').addClass('hidden');
            } else {
                $container.find('#character-detail-options').removeClass('hidden');
            }

            // 更新用户数据
            userData.characters = selectedCharacters;
        });

        // 角色详细程度选项事件处理
        $container.on('change', 'input[name="character-detail"]', function() {
            userData.characterDetail = $(this).val();
        });

        // 主要角色复选框点击事件
        $container.on('change', '#module-characters', function() {
            const isChecked = $(this).is(':checked');
            if (isChecked) {
                $('#characters-options').show();
                userData.characters.enabled = true;
            } else {
                $('#characters-options').hide();
                userData.characters.enabled = false;
            }
        });

        // 角色数量单选按钮点击事件
        $container.on('change', 'input[name="character-count"]', function() {
            userData.characters.count = $(this).val();
        });

        // 角色详细程度单选按钮点击事件
