        setTimeout(() => {
            if ($mes.length) {
                // 还原class
                $mes.attr('class', originalClasses);

                // 还原其他可能被修改的属性
                for (const [name, value] of Object.entries(originalAttributes)) {
                    $mes.attr(name, value);
