  `;

  // 挂到 <html> 根节点而非 body，避免 body 上的 transform 导致 fixed 定位参照系错误
  (pdoc.documentElement || pdoc.body).appendChild(root);

  // 移动端 100vh 不准确，用 JS 设置真实视口高度变量
  function setVH() {
    const vh = pwin.innerHeight * 0.01;
    pdoc.documentElement.style.setProperty('--vh', `${vh}px`);
    // 移动端：给 menu-list 加 scrollable class + 限制 max-height
    // PC端：完全不动 menu-list，保持原始状态
