  setVH();
  pwin.addEventListener('resize', setVH);

  // ── 元素引用 ──────────────────────────────────────────────
  const orb      = pdoc.getElementById(`${ID}-orb`);
  const head     = pdoc.getElementById(`${ID}-head`);
  const btnClose = pdoc.getElementById(`${ID}-close`);
  const menu     = pdoc.getElementById(`${ID}-menu`);
  let isOpen = false;

  function isPromptEnabled(li) {
    return !li.classList.contains('completion_prompt_manager_prompt_disabled');
  }

  function clickToggle(li) {
    const btn = li.querySelector('.prompt-manager-toggle-action');
    if (btn) btn.click();
  }

  // ── 色色单选档位配置 ─────────────────────────────────────
  const sexyLevels = [
    {
      el:      pdoc.getElementById(`${ID}-item-sexy-l`),
      label:   '色色(轻度)',
      turnOn:  ['瑟瑟描述'],
      turnOff: ['深度瑟瑟', '超级瑟瑟视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-sexy-m`),
      label:   '色色(中度)',
      turnOn:  ['瑟瑟描述', '深度瑟瑟'],
      turnOff: ['超级瑟瑟视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-sexy-h`),
      label:   '色色(重度)',
      turnOn:  ['瑟瑟描述', '深度瑟瑟', '超级瑟瑟视角'],
      turnOff: [],
    },
  ];

  function findByKeyword(keyword) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return [];
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).filter(li => {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      const idx = name.indexOf(keyword);
      if (idx === -1) return false;
      const before = idx > 0 ? name[idx - 1] : null;
      const after  = idx + keyword.length < name.length ? name[idx + keyword.length] : null;
      const isCJKorAlnum = c => c && /[\u4e00-\u9fff\w]/.test(c);
      return !isCJKorAlnum(before) && !isCJKorAlnum(after);
    });
  }

  function ensureOn(keyword) {
    findByKeyword(keyword).forEach(li => {
      if (!isPromptEnabled(li)) clickToggle(li);
    });
  }

  function ensureOff(keyword) {
    findByKeyword(keyword).forEach(li => {
      if (isPromptEnabled(li)) clickToggle(li);
    });
  }

  let sexyActive = -1;
  let talkActive = -1;

  function applyLevels(levels, activeIdx, setActive) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) { toastr.warning('请先打开预设管理面板'); return; }

    if (activeIdx === -1) {
      const allKw = new Set(levels.flatMap(l => [...l.turnOn, ...l.turnOff]));
      allKw.forEach(kw => ensureOff(kw));
      levels.forEach(({ el }) => el.classList.remove('is-on'));
      setActive(-1);
    } else {
      const { turnOn, turnOff, label } = levels[activeIdx];
      turnOn.forEach(kw => ensureOn(kw));
      turnOff.forEach(kw => ensureOff(kw));
      levels.forEach(({ el }, i) => el.classList.toggle('is-on', i === activeIdx));
      setActive(activeIdx);
      toastr.success(`已切换到 ${label}`);
    }
  }

  sexyLevels.forEach(({ el }, idx) => {
    el.addEventListener('click', () => {
      const next = sexyActive === idx ? -1 : idx;
      if (next === -1) toastr.info('色色已全部关闭');
      applyLevels(sexyLevels, next, v => sexyActive = v);
    });
  });

  const talkLevels = [
    {
      el:      pdoc.getElementById(`${ID}-item-talk-l`),
      label:   '不抢话(轻度)',
      turnOn:  ['防抢话', '多字数设定'],
      turnOff: ['超级防抢话', '少字数设定'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-talk-m`),
      label:   '不抢话(中度)',
      turnOn:  ['防抢话', '少字数设定'],
      turnOff: ['超级防抢话', '多字数设定'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-talk-h`),
      label:   '不抢话(重度)',
      turnOn:  ['防抢话', '超级防抢话', '少字数设定'],
      turnOff: ['多字数设定'],
    },
  ];

  talkLevels.forEach(({ el }, idx) => {
    el.addEventListener('click', () => {
      const next = talkActive === idx ? -1 : idx;
      if (next === -1) {
        const list = pdoc.querySelector('#completion_prompt_manager_list');
        if (!list) { toastr.warning('请先打开预设管理面板'); return; }
        ensureOn('多字数设定');
        ensureOff('防抢话');
        ensureOff('超级防抢话');
        ensureOff('少字数设定');
        talkLevels.forEach(({ el }) => el.classList.remove('is-on'));
        talkActive = -1;
        toastr.info('不抢话已关闭，多字数设定已开启');
        return;
      }
      applyLevels(talkLevels, next, v => talkActive = v);
    });
  });


  // ── 人称设置档位 ─────────────────────────────────────────
  const povLevels = [
    {
      el:      pdoc.getElementById(`${ID}-item-pov-1`),
      label:   '第一人称',
      turnOn:  ['第一人称视角'],
      turnOff: ['第二人称视角', '第三人称视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-pov-2`),
      label:   '第二人称',
      turnOn:  ['第二人称视角'],
      turnOff: ['第一人称视角', '第三人称视角'],
    },
    {
      el:      pdoc.getElementById(`${ID}-item-pov-3`),
      label:   '第三人称',
      turnOn:  ['第三人称视角'],
      turnOff: ['第一人称视角', '第二人称视角'],
    },
  ];

  let povActive = -1;

  povLevels.forEach(({ el }, idx) => {
    el.addEventListener('click', () => {
      const next = povActive === idx ? -1 : idx;
      if (next === -1) toastr.info('人称设置已关闭');
      applyLevels(povLevels, next, v => povActive = v);
    });
  });

  // ── 大总结按钮 ───────────────────────────────────────────
  let summaryActive = false;
  let summaryBottomItemName = null;

  const itemSummary = pdoc.getElementById(`${ID}-item-summary`);

  function getSummaryBottomItem() {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return null;
    const items = Array.from(list.querySelectorAll('li[data-pm-identifier]'));
    for (const li of items) {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      if (name.includes('模型--底部') && isPromptEnabled(li)) {
        return name;
      }
    }
    return null;
  }

  function findByExactName(fullName) {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return null;
    return Array.from(list.querySelectorAll('li[data-pm-identifier]')).find(li => {
      const name = (li.querySelector('[data-pm-name]') || {}).getAttribute?.('data-pm-name') ?? '';
      return name === fullName;
    }) ?? null;
  }

  itemSummary.addEventListener('click', () => {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) { toastr.warning('请先打开预设管理面板'); return; }

    if (!summaryActive) {
      summaryBottomItemName = getSummaryBottomItem();
      if (summaryBottomItemName) {
        console.log(`[大总结] 记录底部项目: "${summaryBottomItemName}"`);
        const liBottom = findByExactName(summaryBottomItemName);
        if (liBottom && isPromptEnabled(liBottom)) clickToggle(liBottom);
      } else {
        console.warn('[大总结] 未找到已开启的"模型--底部"项目');
      }
      ensureOn('大总结之术');
      summaryActive = true;
      itemSummary.classList.add('is-on');
      toastr.success('大总结已开启');

    } else {
      ensureOff('大总结之术');
      if (summaryBottomItemName) {
        const li = findByExactName(summaryBottomItemName);
        if (li && !isPromptEnabled(li)) {
          clickToggle(li);
          console.log(`[大总结] 已恢复: "${summaryBottomItemName}"`);
        }
      } else {
        console.warn('[大总结] 无记录，无法恢复底部项目');
        toastr.warning('无法恢复底部项目，请手动开启');
      }
      summaryActive = false;
      summaryBottomItemName = null;
      itemSummary.classList.remove('is-on');
      toastr.info('大总结已关闭');
    }
  });

  // ── 检查更新按钮 ──────────────────────────────────────────
  pdoc.getElementById(`${ID}-item-update`).addEventListener('click', () => {
    toastr.info('尽情期待，如果喜欢我的预设\n请多来我的dc帖子聊天吹水。', '', { timeOut: 8000 });
  });

  // ── 检查某关键字对应的预设项是否全部开启 ──────────────────
  function isKeywordOn(keyword) {
    const items = findByKeyword(keyword);
    // 找不到该关键字对应的项，视为关闭
    if (items.length === 0) return false;
    return items.every(li => isPromptEnabled(li));
  }

