  // turnOn 里的关键字全部开启 && turnOff 里的关键字全部关闭 → 匹配
  function detectLevel(levels) {
    for (let i = 0; i < levels.length; i++) {
      const { turnOn, turnOff } = levels[i];
      const onMatch  = turnOn.every(kw => isKeywordOn(kw));
      const offMatch = turnOff.every(kw => !isKeywordOn(kw));
      if (onMatch && offMatch) return i;
    }
    return -1;
  }

  // ── 初始化时读取预设状态，自动高亮对应档位 ──────────────────
  function initDetectState() {
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (!list) return; // 预设面板未打开，无法检测，跳过
    sexyActive = detectLevel(sexyLevels);
    talkActive = detectLevel(talkLevels);
    povActive  = detectLevel(povLevels);
    // 大总结：检测"大总结之术"是否开启
    const summaryOn = isKeywordOn('大总结之术');
    if (summaryOn) {
      summaryActive = true;
      itemSummary.classList.add('is-on');
    }
    syncAllToggleBtns();
  }

  // ── 同步所有开关按钮状态 ─────────────────────────────────
  function syncAllToggleBtns() {
    sexyLevels.forEach(({ el }, i) => el.classList.toggle('is-on', i === sexyActive));
    talkLevels.forEach(({ el }, i) => el.classList.toggle('is-on', i === talkActive));
    povLevels.forEach(({ el }, i) => el.classList.toggle('is-on', i === povActive));
  }

  // 1200ms 首次检测，2000ms 兜底再试一次
  let initDone = false;
  function tryInitDetect() {
    if (initDone) return;
    const list = pdoc.querySelector('#completion_prompt_manager_list');
    if (list) {
      initDone = true;
      initDetectState();
    }
  }
  setTimeout(tryInitDetect, 1200);
  setTimeout(tryInitDetect, 2000);

  // ── 展开/收起 ────────────────────────────────────────────
  function updateMenuDirection() {
    const orbX = parseInt(root.style.left) || 0;
    const orbY = parseInt(root.style.top)  || 0;
    const menuH = 420; // 菜单估算最大高度

    // 左右方向
    if (orbX < pwin.innerWidth / 2) {
      menu.style.left  = '0';
      menu.style.right = 'auto';
    } else {
      menu.style.left  = 'auto';
      menu.style.right = '0';
    }

    // 上下方向：下方空间不够就往上弹
    const spaceBelow = pwin.innerHeight - orbY - 60;
    if (spaceBelow < menuH && orbY > menuH / 2) {
      // 往上弹
      menu.style.top    = 'auto';
      menu.style.bottom = '58px';
      root.classList.add('open-up');
      if (orbX < pwin.innerWidth / 2) {
        menu.style.transformOrigin = 'bottom left';
      } else {
        menu.style.transformOrigin = 'bottom right';
      }
    } else {
      // 往下弹（默认）
      menu.style.top    = '58px';
      menu.style.bottom = 'auto';
      root.classList.remove('open-up');
      if (orbX < pwin.innerWidth / 2) {
        menu.style.transformOrigin = 'top left';
      } else {
        menu.style.transformOrigin = 'top right';
      }
    }
  }

  function toggle() {
    isOpen = !isOpen;
    if (isOpen) {
      updateMenuDirection();
      syncAllToggleBtns();
    } else {
      root.classList.remove('open-up');
    }
    root.classList.toggle('open', isOpen);
  }
  function close() { isOpen = true; toggle(); }

  btnClose.addEventListener('click', e => { e.stopPropagation(); close(); });

  // ── 保存位置 ──────────────────────────────────────────────
  function savePos() {
    try {
      insertOrAssignVariables({
        orbV2_pos: JSON.stringify({ x: parseInt(root.style.left), y: parseInt(root.style.top) })
      }, { type: 'global' });
    } catch (_) {}
  }

  // ── 拖拽（鼠标）──────────────────────────────────────────
  let drag = false, ox = 0, oy = 0, moved = false;

  let dragMask = null;
  function createMask() {
    dragMask = parent.document.createElement('div');
    dragMask.style.cssText = [
      'position:fixed', 'inset:0', 'z-index:2147483646',
      'cursor:grabbing', 'background:transparent',
    ].join(';');
    parent.document.body.appendChild(dragMask);
  }
  function removeMask() {
    dragMask?.remove();
    dragMask = null;
  }

  function startDrag(cx, cy) {
    drag = true; moved = false;
    const rect = root.getBoundingClientRect();
    ox = cx - rect.left;
    oy = cy - rect.top;
    root.style.transition = 'none';
    createMask();
  }
  function moveDrag(cx, cy) {
    if (!drag) return;
    moved = true;
    root.style.left = Math.max(4, Math.min(cx - ox, pwin.innerWidth  - 56)) + 'px';
    root.style.top  = Math.max(4, Math.min(cy - oy, pwin.innerHeight - 56)) + 'px';
  }
  function endDrag() {
    if (!drag) return;
    drag = false;
    root.style.transition = '';
    removeMask();
    if (moved) savePos();
  }

  orb.addEventListener('mousedown', e => { startDrag(e.clientX, e.clientY); e.preventDefault(); });
  head.addEventListener('mousedown', e => {
    if (e.target.id === `${ID}-close`) return;
    startDrag(e.clientX, e.clientY); e.preventDefault();
  });
  parent.document.addEventListener('mousemove', e => moveDrag(e.clientX, e.clientY));
  parent.document.addEventListener('mouseup', () => endDrag());

  orb.addEventListener('click', e => {
    if (moved) { moved = false; return; }
    toggle();
  });

  // ── 拖拽（触摸）──────────────────────────────────────────
  // 只在 orb 本身监听 touch，不挂全局 pdoc，避免菜单内触摸被误拦截

  orb.addEventListener('touchstart', e => {
    const t = e.touches[0];
    startDrag(t.clientX, t.clientY);
    e.stopPropagation();
  }, { passive: true });

  orb.addEventListener('touchmove', e => {
    if (!drag) return;
    const t = e.touches[0];
    moveDrag(t.clientX, t.clientY);
  }, { passive: true });

  orb.addEventListener('touchend', e => {
    const wasMoved = moved;
    endDrag();
    if (!wasMoved) toggle();
    e.stopPropagation();
    e.preventDefault(); // 阻止后续 click 事件触发
  }, { passive: false });

  // head 拖拽触摸
  head.addEventListener('touchstart', e => {
    if (e.target.id === `${ID}-close`) return;
    const t = e.touches[0];
    startDrag(t.clientX, t.clientY);
    e.stopPropagation();
  }, { passive: true });

  head.addEventListener('touchmove', e => {
    if (!drag) return;
    const t = e.touches[0];
    moveDrag(t.clientX, t.clientY);
  }, { passive: true });

  head.addEventListener('touchend', e => {
    endDrag();
    e.stopPropagation();
  }, { passive: true });

  // 全局 touchmove 只用于拖拽中跟踪位置（鼠标拖拽用）
  // 触摸拖拽已在 orb/head 上处理，这里不重复注册

  // ── 预设切换自动销毁 ─────────────────────────────────────
  // ST 的 completion preset 下拉框 id 固定为 settings_preset_openai
  // 直接监听它的 change 事件，触发即销毁悬浮窗，简单可靠。

  // 脚本失效（预设切换）时，window 会被销毁，触发 pagehide/unload。
  // 在此时删除挂在 pdoc 上的悬浮窗，实现自动清理。
  window.addEventListener('pagehide', () => {
    pdoc.getElementById(ID)?.remove();
    pdoc.getElementById(`${ID}-style`)?.remove();
  });
  window.addEventListener('unload', () => {
    pdoc.getElementById(ID)?.remove();
    pdoc.getElementById(`${ID}-style`)?.remove();
  });

}));

